import { create } from "zustand";
import {
  cloneMockAgentTasks,
  isMockSeedTaskId,
  linkMockAgentTasksToBucketIds,
} from "../../offline/mock_data";
import { useTradingAgentStore } from "./tradingAgentStore";
import {
  getTaskReportingMeta,
  isGatedTier,
} from "../components/tradeagent/reportTier";
import { createTaskPolicyResolver } from "./bucketPolicyStore";
import type { TradingMode } from "../configs/tradeLayoutMode";
import type {
  AgentTask,
  AgentTaskPendingEdit,
  AgentTaskStatus,
  AgentTaskStatusEvent,
  AgentTaskStoreState,
  ForceExecuteOptions,
} from "./types";

function generateHashId(): string {
  if (typeof crypto !== "undefined" && crypto.randomUUID) {
    return crypto.randomUUID().replace(/-/g, "").slice(0, 16);
  }
  return `${Date.now().toString(16)}${Math.random().toString(16).slice(2, 10)}`.slice(
    0,
    16,
  );
}

function nowIso(): string {
  return new Date().toISOString();
}

function appendStatusEvent(
  history: AgentTaskStatusEvent[],
  status: AgentTaskStatus,
  note?: string,
): AgentTaskStatusEvent[] {
  const at = nowIso();
  const last = history[history.length - 1];
  if (last?.status === status) return history;
  return [...history, { status, at, ...(note ? { note } : {}) }];
}

function patchTask(
  tasks: AgentTask[],
  id: string,
  patch: Partial<Omit<AgentTask, "id">>,
): AgentTask[] {
  return tasks.map((task) =>
    task.id === id
      ? { ...task, ...patch, updatedAt: nowIso() }
      : task,
  );
}

export const useAgentTaskStore = create<AgentTaskStoreState>((set, get) => ({
  tasks: cloneMockAgentTasks() as AgentTask[],
  pendingEdit: null,
  navigateToAgentTasks: false,
  seedBucketsLinked: false,
  linkedBucketKey: null,

  addTask: (input, options) => {
    const navigate = options?.navigate ?? true;
    const appendMemory = options?.appendMemory ?? true;
    const timestamp = nowIso();
    const status = input.status;
    const agentId =
      input.agentId ?? useTradingAgentStore.getState().resolveDefaultAgentId();
    const task: AgentTask = {
      id: input.id ?? generateHashId(),
      agentId,
      description: input.description,
      status,
      marketId: input.marketId ?? null,
      bucketId: input.bucketId ?? null,
      trigger: input.trigger ?? "",
      eta: input.eta ?? null,
      createdAt: input.createdAt ?? timestamp,
      updatedAt: input.updatedAt ?? timestamp,
      isNew: input.isNew ?? true,
      statusBeforePause: input.statusBeforePause,
      statusHistory: input.statusHistory ?? [
        {
          status,
          at: input.createdAt ?? timestamp,
          note: "Task created.",
        },
      ],
      guardrail: input.guardrail,
      leaderTradeId: input.leaderTradeId,
      copyRelationId: input.copyRelationId,
    };
    if (appendMemory) {
      useTradingAgentStore
        .getState()
        .appendMemoryNote(
          agentId,
          `Task created: ${input.description.slice(0, 120)}${input.description.length > 120 ? "…" : ""}`,
        );
    }
    set((state) => ({
      tasks: [task, ...state.tasks],
      ...(navigate ? { navigateToAgentTasks: true } : {}),
    }));
    return task;
  },

  updateTask: (id, patch) => {
    set((state) => ({
      tasks: patchTask(state.tasks, id, { ...patch, isNew: patch.isNew ?? true }),
    }));
  },

  pauseTask: (id) => {
    const task = get().tasks.find((t) => t.id === id);
    if (
      !task ||
      task.status === "paused" ||
      task.status === "completed" ||
      task.status === "rejected"
    ) {
      return;
    }
    set((state) => ({
      tasks: patchTask(state.tasks, id, {
        statusBeforePause: task.status as AgentTaskStatus,
        status: "paused",
        statusHistory: appendStatusEvent(
          task.statusHistory,
          "paused",
          "Paused by user.",
        ),
        isNew: true,
      }),
    }));
  },

  resumeTask: (id) => {
    const task = get().tasks.find((t) => t.id === id);
    if (!task || task.status !== "paused") return;
    const resumeStatus: AgentTaskStatus =
      task.statusBeforePause &&
      task.statusBeforePause !== "paused" &&
      task.statusBeforePause !== "completed" &&
      task.statusBeforePause !== "rejected"
        ? task.statusBeforePause
        : "pending";
    set((state) => ({
      tasks: patchTask(state.tasks, id, {
        status: resumeStatus,
        statusBeforePause: undefined,
        statusHistory: appendStatusEvent(
          task.statusHistory,
          resumeStatus,
          "Task resumed.",
        ),
        isNew: true,
      }),
    }));
  },

  forceExecute: (id, options?: ForceExecuteOptions) => {
    const task = get().tasks.find((t) => t.id === id);
    if (
      !task ||
      task.status === "completed" ||
      task.status === "rejected" ||
      task.status === "executing"
    ) {
      return;
    }
    const sizePct = options?.sizePct;
    const executeNote =
      sizePct != null && sizePct !== 100
        ? `Approved with ${sizePct}% size tweak.`
        : "Force execute requested.";
    useTradingAgentStore
      .getState()
      .appendMemoryNote(task.agentId, executeNote);
    set((state) => ({
      tasks: patchTask(state.tasks, id, {
        status: "executing",
        statusBeforePause: undefined,
        statusHistory: appendStatusEvent(
          task.statusHistory,
          "executing",
          executeNote,
        ),
        isNew: true,
      }),
    }));
  },

  forceExecuteAllPending: (tradingMode: TradingMode = "highAgency") => {
    const resolvePolicy = createTaskPolicyResolver(tradingMode);
    const targets = get().tasks.filter((t) => {
      if (t.status !== "pending" && t.status !== "watching") return false;
      const tier = getTaskReportingMeta(t, resolvePolicy(t)).reportTier;
      return !isGatedTier(tier);
    });
    if (targets.length === 0) return;
    for (const task of targets) {
      useTradingAgentStore
        .getState()
        .appendMemoryNote(task.agentId, "Force execute requested for task.");
    }
    set((state) => ({
      tasks: state.tasks.map((task) => {
        if (task.status !== "pending" && task.status !== "watching") {
          return task;
        }
        return {
          ...task,
          status: "executing" as const,
          updatedAt: nowIso(),
          statusHistory: appendStatusEvent(
            task.statusHistory,
            "executing",
            "Force execute requested.",
          ),
          isNew: true,
        };
      }),
    }));
  },

  pauseActiveTasks: () => {
    set((state) => ({
      tasks: state.tasks.map((task) => {
        if (task.status !== "executing" && task.status !== "watching") {
          return task;
        }
        return {
          ...task,
          statusBeforePause: task.status as AgentTaskStatus,
          status: "paused" as const,
          updatedAt: nowIso(),
          statusHistory: appendStatusEvent(
            task.statusHistory,
            "paused",
            "Paused by user.",
          ),
          isNew: true,
        };
      }),
    }));
  },

  pauseTasksForAgent: (agentId) => {
    set((state) => ({
      tasks: state.tasks.map((task) => {
        if (
          task.agentId !== agentId ||
          (task.status !== "executing" && task.status !== "watching")
        ) {
          return task;
        }
        return {
          ...task,
          statusBeforePause: task.status as AgentTaskStatus,
          status: "paused" as const,
          updatedAt: nowIso(),
          statusHistory: appendStatusEvent(
            task.statusHistory,
            "paused",
            "Paused by user (riskiest agent).",
          ),
          isNew: true,
        };
      }),
    }));
  },

  rejectTask: (id) => {
    const task = get().tasks.find((t) => t.id === id);
    if (!task || (task.status !== "pending" && task.status !== "watching")) {
      return;
    }
    useTradingAgentStore
      .getState()
      .appendMemoryNote(task.agentId, "Intent rejected by user.");
    set((state) => ({
      tasks: patchTask(state.tasks, id, {
        status: "rejected",
        statusHistory: appendStatusEvent(
          task.statusHistory,
          "rejected",
          "Rejected by user.",
        ),
        isNew: true,
      }),
    }));
  },

  rejectAllPending: () => {
    const targets = get().tasks.filter(
      (t) => t.status === "pending" || t.status === "watching",
    );
    if (targets.length === 0) return;
    for (const task of targets) {
      useTradingAgentStore
        .getState()
        .appendMemoryNote(task.agentId, "Intent rejected by user.");
    }
    set((state) => ({
      tasks: state.tasks.map((task) => {
        if (task.status !== "pending" && task.status !== "watching") {
          return task;
        }
        return {
          ...task,
          status: "rejected" as const,
          updatedAt: nowIso(),
          statusHistory: appendStatusEvent(
            task.statusHistory,
            "rejected",
            "Rejected by user.",
          ),
          isNew: true,
        };
      }),
    }));
  },

  pauseActiveTasksForBucket: (bucketId) => {
    set((state) => ({
      tasks: state.tasks.map((task) => {
        if (
          task.bucketId?.toString() !== bucketId.toString() ||
          (task.status !== "executing" && task.status !== "watching")
        ) {
          return task;
        }
        return {
          ...task,
          statusBeforePause: task.status as AgentTaskStatus,
          status: "paused" as const,
          updatedAt: nowIso(),
          statusHistory: appendStatusEvent(
            task.statusHistory,
            "paused",
            "Paused by user (this bucket).",
          ),
          isNew: true,
        };
      }),
    }));
  },

  rejectAllPendingForBucket: (bucketId) => {
    const targets = get().tasks.filter(
      (t) =>
        t.bucketId?.toString() === bucketId.toString() &&
        (t.status === "pending" || t.status === "watching"),
    );
    if (targets.length === 0) return;
    for (const task of targets) {
      useTradingAgentStore
        .getState()
        .appendMemoryNote(task.agentId, "Intent rejected by user (this bucket).");
    }
    set((state) => ({
      tasks: state.tasks.map((task) => {
        if (
          task.bucketId?.toString() !== bucketId.toString() ||
          (task.status !== "pending" && task.status !== "watching")
        ) {
          return task;
        }
        return {
          ...task,
          status: "rejected" as const,
          updatedAt: nowIso(),
          statusHistory: appendStatusEvent(
            task.statusHistory,
            "rejected",
            "Rejected by user (this bucket).",
          ),
          isNew: true,
        };
      }),
    }));
  },

  markAllSeen: () => {
    set((state) => ({
      tasks: state.tasks.map((t) => (t.isNew ? { ...t, isNew: false } : t)),
    }));
  },

  setPendingEdit: (edit: AgentTaskPendingEdit | null) => {
    set({ pendingEdit: edit });
  },

  setNavigateToAgentTasks: (value: boolean) => {
    set({ navigateToAgentTasks: value });
  },

  linkSeedTasksToBuckets: (bucketIds: string[]) => {
    if (bucketIds.length === 0) return;
    const key = bucketIds.join("|");
    if (get().linkedBucketKey === key) return;
    const dynamicTasks = get().tasks.filter((task) => !isMockSeedTaskId(task.id));
    const linkedSeeds = linkMockAgentTasksToBucketIds(
      cloneMockAgentTasks(),
      bucketIds,
    ) as AgentTask[];
    set({
      tasks: [...linkedSeeds, ...dynamicTasks],
      seedBucketsLinked: true,
      linkedBucketKey: key,
    });
  },
}));

export function selectActiveAgentTaskCount(tasks: AgentTask[]): number {
  return tasks.filter((t) =>
    ["pending", "watching", "executing"].includes(t.status),
  ).length;
}

export function selectHasUnreadAgentTasks(tasks: AgentTask[]): boolean {
  return tasks.some((t) => t.isNew);
}
