import React from "react";

import type {
  FleetActivityLogEntry,
  FleetActivityLogNarrativeSegment,
} from "../../utils/fleetActivityLog";
import { formatFleetActivityLogTimestamp } from "../../utils/fleetActivityLog";
import "./agent.css";

export interface AgentActivityLogTimelineProps {
  entries: FleetActivityLogEntry[];
  onSymbolClick?: (marketId: string) => void;
  isSymbolNavigable?: (marketId: string) => boolean;
}

function canNavigateToSymbol(
  entry: FleetActivityLogEntry,
  onSymbolClick: AgentActivityLogTimelineProps["onSymbolClick"],
  isSymbolNavigable: AgentActivityLogTimelineProps["isSymbolNavigable"],
): boolean {
  if (!onSymbolClick || !entry.marketId.trim()) return false;
  if (isSymbolNavigable) return isSymbolNavigable(entry.marketId);
  return true;
}

function renderNarrativeSegment(
  segment: FleetActivityLogNarrativeSegment,
  index: number,
  options: {
    symbolNavigable: boolean;
    symbolActionLabel: string;
    onSymbolClick?: (marketId: string) => void;
    marketId: string;
  },
): React.ReactNode {
  const key = `${segment.kind}-${index}`;

  switch (segment.kind) {
    case "text":
      return <React.Fragment key={key}>{segment.text}</React.Fragment>;
    case "value":
      return (
        <span key={key} className="agent-activity-log-narrative-value">
          {segment.text}
        </span>
      );
    case "pnlValue":
      return (
        <span
          key={key}
          className={`agent-activity-log-pnl-value agent-activity-log-pnl-value--${segment.tone}`}
        >
          {segment.text}
        </span>
      );
    case "symbol":
      if (options.symbolNavigable) {
        return (
          <button
            key={key}
            type="button"
            className="agent-activity-log-symbol-link"
            aria-label={options.symbolActionLabel}
            onClick={() => options.onSymbolClick?.(options.marketId)}
          >
            {segment.text}
          </button>
        );
      }
      return (
        <span key={key} className="agent-activity-log-symbol">
          {segment.text}
        </span>
      );
    default:
      return null;
  }
}

export default function AgentActivityLogTimeline({
  entries,
  onSymbolClick,
  isSymbolNavigable,
}: AgentActivityLogTimelineProps): JSX.Element {
  return (
    <ol className="agent-activity-log-timeline" aria-label="Fleet activity log">
      {entries.map((entry, index) => {
        const isLast = index === entries.length - 1;
        const isLatest = index === 0;
        const badgeClass =
          entry.tone === "long"
            ? "agent-activity-log-badge agent-activity-log-badge--long"
            : "agent-activity-log-badge agent-activity-log-badge--short";
        const itemClass = [
          "agent-activity-log-item",
          `agent-activity-log-item--${entry.tone}`,
        ].join(" ");
        const symbolNavigable = canNavigateToSymbol(
          entry,
          onSymbolClick,
          isSymbolNavigable,
        );
        const symbolActionLabel = `View ${entry.symbolLabel} on trade page`;

        return (
          <li key={entry.id} className={itemClass}>
            <time
              className="agent-activity-log-time"
              dateTime={entry.timestamp}
            >
              {formatFleetActivityLogTimestamp(entry.timestamp)}
            </time>
            <div className="agent-activity-log-track">
              {!isLast ? (
                <span className="agent-activity-log-track-line" aria-hidden />
              ) : null}
              <span
                className={[
                  "agent-activity-log-dot",
                  isLatest ? "agent-activity-log-dot--latest" : "",
                ]
                  .filter(Boolean)
                  .join(" ")}
                aria-hidden
              />
            </div>
            <div className="agent-activity-log-body">
              <span className={badgeClass}>{entry.badgeLabel}</span>
              <p className="agent-activity-log-narrative" aria-label={entry.narrative}>
                {entry.narrativeSegments.map((segment, index) =>
                  renderNarrativeSegment(segment, index, {
                    symbolNavigable,
                    symbolActionLabel,
                    onSymbolClick,
                    marketId: entry.marketId,
                  }),
                )}
              </p>
            </div>
          </li>
        );
      })}
    </ol>
  );
}
