import type { FleetAgentRecord, FleetBehaviorProfile } from "../../../offline/mock_data/fleetCatalog";
import type { PropertyProfile } from "../../../offline/mock_data/types";

export type AgentHeroFocus = "copy" | "trust" | "scale" | "brand" | "playbook";

export type AgentActionTabId =
  | "action"
  | "token"
  | "reputation"
  | "about";

/** Split header (lg/md/sm) vs full-width title band (xs/xxs). */
export type AgentHeroColumnLayout = "narrow" | "wide";

export const AGENT_HERO_FOCUS_OPTIONS = [
  { value: "copy", label: "Copy" },
  { value: "trust", label: "Trust" },
  { value: "scale", label: "Scale" },
  { value: "brand", label: "Brand" },
  { value: "playbook", label: "Playbook" },
] as const;

export const DEFAULT_AGENT_HERO_FOCUS: AgentHeroFocus = "copy";

export const AGENT_HERO_FOCUS_LOOP_MS = 5000;

export const VALID_AGENT_HERO_FOCUSES: readonly AgentHeroFocus[] = [
  "copy",
  "trust",
  "scale",
  "brand",
  "playbook",
];

export interface AgentHeroFocusContent {
  eyebrow: string;
  /** Full detail on hover when the eyebrow is truncated. */
  eyebrowTitle?: string;
  titleChip: { kind: "ticker" | "verified"; value: string } | null;
}

export function resolveAgentHeroColumnLayout(
  breakpoint: string,
): AgentHeroColumnLayout {
  return breakpoint === "xs" || breakpoint === "xxs" ? "wide" : "narrow";
}

export function shortWalletAddress(address: string): string {
  if (address.length <= 12) return address;
  return `${address.slice(0, 6)}…${address.slice(-4)}`;
}

export function extractRiskLabel(riskScore: string): string {
  const segment = riskScore.split("·")[0]?.trim();
  return segment || riskScore.trim();
}

export function humanizeBehaviorProfile(profile: FleetBehaviorProfile): string {
  switch (profile) {
    case "high_freq_aggressive":
      return "High freq";
    case "steady_yield":
      return "Steady yield";
    case "sniper":
      return "Sniper";
    case "grid_range":
      return "Grid range";
    case "macro_dislocation":
      return "Macro";
    default:
      return profile;
  }
}

export function formatManagedAum(
  profile: PropertyProfile,
  fleet: FleetAgentRecord,
): string {
  const aumStat = profile.stats.find((stat) => stat.label === "AUM");
  if (aumStat?.value) {
    return aumStat.value;
  }

  const millions = fleet.tvlManagedSim / 1_000_000;
  if (millions >= 1) {
    return `$${millions.toFixed(1)}M`;
  }

  return `$${(fleet.tvlManagedSim / 1_000).toFixed(0)}K`;
}

export function buildAgentHeroFocusContent(
  focus: AgentHeroFocus,
  profile: PropertyProfile,
  fleet: FleetAgentRecord,
  layout: AgentHeroColumnLayout = "narrow",
): AgentHeroFocusContent {
  const showTitleChip = layout === "wide";
  const aum = formatManagedAum(profile, fleet);
  const riskLabel = extractRiskLabel(profile.riskScore);
  const behaviorLabel = humanizeBehaviorProfile(fleet.behaviorProfile);

  switch (focus) {
    case "copy":
      return {
        eyebrow: `Copy · ${fleet.copyCount.toLocaleString()} · ${fleet.winRatePct}% win`,
        eyebrowTitle: `Copy trading · ${profile.sector}`,
        titleChip: showTitleChip
          ? { kind: "ticker", value: profile.ticker }
          : null,
      };
    case "trust": {
      const agentWallet = shortWalletAddress(fleet.agentWallet);
      const masterWallet = shortWalletAddress(fleet.masterWallet);
      return {
        eyebrow: `Agent ${agentWallet} · Master ${masterWallet}`,
        eyebrowTitle: `Agent ${fleet.agentWallet} · Master ${fleet.masterWallet}`,
        titleChip:
          showTitleChip && profile.verifiedLabel
            ? { kind: "verified", value: profile.verifiedLabel }
            : null,
      };
    }
    case "scale":
      return {
        eyebrow: `${aum} · ${profile.sector}`,
        eyebrowTitle: `${aum} managed · ${profile.strategy}`,
        titleChip: showTitleChip
          ? { kind: "ticker", value: profile.ticker }
          : null,
      };
    case "brand":
      return {
        eyebrow: `${profile.ticker} desk · ${profile.sector}`,
        eyebrowTitle: profile.strategy,
        titleChip: null,
      };
    case "playbook":
      return {
        eyebrow: `${profile.strategy} · ${riskLabel} · ${behaviorLabel}`,
        eyebrowTitle: `${profile.strategy} · ${profile.sector}`,
        titleChip: showTitleChip
          ? { kind: "ticker", value: profile.ticker }
          : null,
      };
    default:
      return buildAgentHeroFocusContent(
        DEFAULT_AGENT_HERO_FOCUS,
        profile,
        fleet,
        layout,
      );
  }
}

export function normalizeAgentHeroFocus(value: unknown): AgentHeroFocus {
  if (
    typeof value === "string" &&
    (VALID_AGENT_HERO_FOCUSES as readonly string[]).includes(value)
  ) {
    return value as AgentHeroFocus;
  }
  return DEFAULT_AGENT_HERO_FOCUS;
}

export function nextAgentHeroFocus(current: AgentHeroFocus): AgentHeroFocus {
  const index = VALID_AGENT_HERO_FOCUSES.indexOf(current);
  const nextIndex =
    index < 0 ? 0 : (index + 1) % VALID_AGENT_HERO_FOCUSES.length;
  return VALID_AGENT_HERO_FOCUSES[nextIndex] ?? DEFAULT_AGENT_HERO_FOCUS;
}

/** 1 = forward (next stack rises from below), -1 = backward (next stack drops from above). */
export function focusSlideDirection(
  from: AgentHeroFocus,
  to: AgentHeroFocus,
): 1 | -1 {
  if (from === to) return 1;

  const fromIndex = VALID_AGENT_HERO_FOCUSES.indexOf(from);
  const toIndex = VALID_AGENT_HERO_FOCUSES.indexOf(to);
  if (fromIndex < 0 || toIndex < 0) return 1;

  const count = VALID_AGENT_HERO_FOCUSES.length;
  const forward = (toIndex - fromIndex + count) % count;
  const backward = (fromIndex - toIndex + count) % count;
  return forward <= backward ? 1 : -1;
}

export function resolveAgentPrefs(
  agent: { heroFocus?: unknown; heroFocusLoop?: unknown } | undefined,
): { heroFocus: AgentHeroFocus; heroFocusLoop: boolean } {
  return {
    heroFocus: normalizeAgentHeroFocus(agent?.heroFocus),
    heroFocusLoop: agent?.heroFocusLoop === true,
  };
}

export function hasAgentToken(fleet: FleetAgentRecord): boolean {
  return Boolean(fleet.tokenAddress?.trim());
}

export function buildActionTabs(hasToken: boolean): AgentActionTabId[] {
  if (hasToken) {
    return ["action", "token", "reputation", "about"];
  }
  return ["action", "reputation", "about"];
}

/** Copy-trade agent page — performance-first, no token tab. */
export const COPY_TRADE_ACTION_TAB_IDS: AgentActionTabId[] = [
  "action",
  "reputation",
  "about",
];

export function buildCopyTradeActionTabs(): AgentActionTabId[] {
  return COPY_TRADE_ACTION_TAB_IDS;
}

export function parseAgentActionTabParam(
  value: string | null,
  hasToken: boolean,
): AgentActionTabId | undefined {
  if (!value) return undefined;
  const tabs = buildActionTabs(hasToken);
  if ((tabs as readonly string[]).includes(value)) {
    return value as AgentActionTabId;
  }
  return undefined;
}

export function parseCopyTradeActionTabParam(
  value: string | null,
): AgentActionTabId | undefined {
  if (!value) return undefined;
  if ((COPY_TRADE_ACTION_TAB_IDS as readonly string[]).includes(value)) {
    return value as AgentActionTabId;
  }
  return undefined;
}

export function defaultActionTabForFocus(
  focus: AgentHeroFocus,
  hasToken = false,
): AgentActionTabId {
  switch (focus) {
    case "playbook":
      return "action";
    case "trust":
      return "reputation";
    case "scale":
    case "brand":
      return hasToken ? "token" : "about";
    default:
      return "action";
  }
}
