function loadColorTheme(): ColorTheme {
  if (typeof window === "undefined") return DEFAULT_SETTINGS.colorTheme;
  try {
    const saved = localStorage.getItem(COLOR_THEME_KEY);
    if (saved === "theme1" || saved === "theme2" || saved === "theme3" || saved === "theme4") {
      return saved;
    }
  } catch {
    // ignore
  }
  return DEFAULT_SETTINGS.colorTheme;
}

function loadLayout(): LayoutStyle {
  if (typeof window === "undefined") return DEFAULT_SETTINGS.layout;
  try {
    const saved = localStorage.getItem(LAYOUT_KEY);
    if (saved === "layout5") {
      return "layout1";
    }
    if (saved && (VALID_LAYOUTS as readonly string[]).includes(saved)) {
      return saved as LayoutStyle;
    }
  } catch {
    // ignore
  }
  return DEFAULT_SETTINGS.layout;
}

function mergePendingOrderLineFilters(
  parsed: Partial<PendingOrderLineFilters> | undefined,
): PendingOrderLineFilters {
  const defaults = DEFAULT_PENDING_ORDER_LINE_FILTERS;
  if (!parsed) return defaults;
  return {
    agent: typeof parsed.agent === "boolean" ? parsed.agent : defaults.agent,
    manual: typeof parsed.manual === "boolean" ? parsed.manual : defaults.manual,
    scale: typeof parsed.scale === "boolean" ? parsed.scale : defaults.scale,
    limit: typeof parsed.limit === "boolean" ? parsed.limit : defaults.limit,
    stopLimit: typeof parsed.stopLimit === "boolean" ? parsed.stopLimit : defaults.stopLimit,
  };
}

function loadChartOverlays(): ChartOverlayPrefs {
  if (typeof window === "undefined") return DEFAULT_CHART_OVERLAYS;
  try {
    const saved = localStorage.getItem(CHART_OVERLAYS_KEY);
    if (!saved) return DEFAULT_CHART_OVERLAYS;
    const parsed = JSON.parse(saved) as Partial<ChartOverlayPrefs>;
    return {
      showExecutionMarkers:
        typeof parsed.showExecutionMarkers === "boolean"
          ? parsed.showExecutionMarkers
          : DEFAULT_CHART_OVERLAYS.showExecutionMarkers,
      showPendingOrderLines:
        typeof parsed.showPendingOrderLines === "boolean"
          ? parsed.showPendingOrderLines
          : DEFAULT_CHART_OVERLAYS.showPendingOrderLines,
      pendingOrderLineFilters: mergePendingOrderLineFilters(parsed.pendingOrderLineFilters),
    };
  } catch {
    return DEFAULT_CHART_OVERLAYS;
  }
}

