import { getMockMarketPrice } from "./demoData";

export type MockOrderbookSnapshot = {
  bids: Array<[number, number]>;
  asks: Array<[number, number]>;
};

export type MockOrderbookDelta = {
  bids: Array<[number, number]>;
  asks: Array<[number, number]>;
};

export type MockOrderbookTick =
  | { kind: "delta"; delta: MockOrderbookDelta }
  | { kind: "snapshot"; snapshot: MockOrderbookSnapshot };

type BookState = {
  rng: () => number;
  tick: number;
  mid: number;
  sequence: number;
  depth: number;
  bids: Array<[number, number]>;
  asks: Array<[number, number]>;
};

const bookStates = new Map<string, BookState>();

function hashSeed(value: string): number {
  let hash = 0;
  for (let i = 0; i < value.length; i += 1) {
    hash = (hash * 31 + value.charCodeAt(i)) | 0;
  }
  return Math.abs(hash) || 1;
}

function mulberry32(seed: number): () => number {
  let state = seed;
  return () => {
    state |= 0;
    state = (state + 0x6d2b79f5) | 0;
    let t = Math.imul(state ^ (state >>> 15), 1 | state);
    t = (t + Math.imul(t ^ (t >>> 7), 61 | t)) ^ t;
    return ((t ^ (t >>> 14)) >>> 0) / 4294967296;
  };
}

function mockTradePriceStep(price: number): number {
  if (price < 1) return 0.0001;
  if (price < 100) return 0.05;
  if (price < 1000) return 1;
  return 20;
}

function roundToTick(price: number, tick: number): number {
  const decimals = tick < 0.0001 ? 8 : tick < 0.01 ? 6 : tick < 1 ? 4 : 2;
  return Number((Math.round(price / tick) * tick).toFixed(decimals));
}

function roundSize(size: number): number {
  return Number(Math.max(0.0001, size).toFixed(4));
}

function baseSizeForPrice(price: number): number {
  if (price >= 10_000) return 0.15;
  if (price >= 1_000) return 0.4;
  if (price >= 100) return 1.2;
  if (price >= 1) return 8;
  return 500;
}

function buildLevels(
  mid: number,
  tick: number,
  depth: number,
  rng: () => number,
): { bids: Array<[number, number]>; asks: Array<[number, number]> } {
  const baseSize = baseSizeForPrice(mid);
  const bids: Array<[number, number]> = [];
  const asks: Array<[number, number]> = [];

  for (let i = 0; i < depth; i += 1) {
    const distance = i + 1;
    const decay = 1 / (1 + i * 0.18);
    const size = roundSize(baseSize * decay * (0.65 + rng() * 1.1));
    bids.push([
      roundToTick(Math.max(tick, mid - tick * distance), tick),
      size,
    ]);
    asks.push([
      roundToTick(Math.max(tick, mid + tick * distance), tick),
      size,
    ]);
  }

  bids.sort((a, b) => b[0] - a[0]);
  asks.sort((a, b) => b[0] - a[0]);
  return { bids, asks };
}

function ensureBookState(marketId: string, depth: number): BookState {
  const existing = bookStates.get(marketId);
  if (existing && existing.depth === depth) {
    return existing;
  }

  const mid = getMockMarketPrice(marketId);
  const tick = mockTradePriceStep(mid);
  const rng = mulberry32(hashSeed(`${marketId}:${depth}`));
  const { bids, asks } = buildLevels(mid, tick, depth, rng);

  const state: BookState = {
    rng,
    tick,
    mid,
    sequence: 1,
    depth,
    bids,
    asks,
  };
  bookStates.set(marketId, state);
  return state;
}

export function resetMockOrderbook(marketId: string): void {
  bookStates.delete(marketId);
}

export function getMockOrderbookSnapshot(
  marketId = "1",
  depth = 20,
): MockOrderbookSnapshot {
  const state = ensureBookState(marketId, depth);
  return {
    bids: state.bids.map(([price, size]) => [price, size]),
    asks: state.asks.map(([price, size]) => [price, size]),
  };
}

export function getMockOrderbookMid(marketId = "1", depth = 20): number {
  const state = ensureBookState(marketId, depth);
  return state.mid;
}

export function getMockOrderbookBestPrices(
  marketId = "1",
  depth = 20,
): { bestBid: number; bestAsk: number } | null {
  const state = ensureBookState(marketId, depth);
  if (state.bids.length === 0 || state.asks.length === 0) {
    return null;
  }
  return {
    bestBid: state.bids[0][0],
    bestAsk: state.asks[0][0],
  };
}

function pickLevelIndex(depth: number, rng: () => number): number {
  const bias = rng();
  if (bias < 0.55) return 0;
  if (bias < 0.8) return Math.min(1, depth - 1);
  return Math.min(Math.floor(rng() * depth), depth - 1);
}

function mutateLevelSize(
  levels: Array<[number, number]>,
  index: number,
  rng: () => number,
): Array<[number, number]> {
  const [price, size] = levels[index];
  const delta = 0.82 + rng() * 0.36;
  const nextSize = roundSize(size * delta);
  if (nextSize === size) {
    return [[price, roundSize(size * (delta > 1 ? 1.08 : 0.92))]];
  }
  return [[price, nextSize]];
}

function shiftMidPrice(state: BookState): MockOrderbookTick | null {
  const direction = state.rng() < 0.5 ? -1 : 1;
  const nextMid = roundToTick(state.mid + state.tick * direction, state.tick);
  if (nextMid <= state.tick) return null;

  state.mid = nextMid;
  const { bids, asks } = buildLevels(nextMid, state.tick, state.depth, state.rng);
  state.bids = bids;
  state.asks = asks;
  state.sequence += 1;

  return {
    kind: "snapshot",
    snapshot: {
      bids: bids.map(([price, size]) => [price, size]),
      asks: asks.map(([price, size]) => [price, size]),
    },
  };
}

export function tickMockOrderbook(marketId: string): MockOrderbookTick | null {
  const state = bookStates.get(marketId);
  if (!state || state.bids.length === 0 || state.asks.length === 0) {
    return null;
  }

  const roll = state.rng();
  if (roll < 0.12) {
    return shiftMidPrice(state);
  }

  const side = state.rng() < 0.5 ? "bid" : "ask";
  const levels = side === "bid" ? state.bids : state.asks;
  const index = pickLevelIndex(levels.length, state.rng);
  const updates = mutateLevelSize(levels, index, state.rng);
  const [price, size] = updates[0];

  levels[index] = [price, size];
  state.sequence += 1;

  return {
    kind: "delta",
    delta: side === "bid" ? { bids: updates, asks: [] } : { bids: [], asks: updates },
  };
}

/** @deprecated Use tickMockOrderbook instead */
export function tickMockOrderbookDelta(marketId: string): MockOrderbookDelta | null {
  const tick = tickMockOrderbook(marketId);
  return tick?.kind === "delta" ? tick.delta : null;
}

export function getMockOrderbookSequenceId(marketId: string): string {
  const state = bookStates.get(marketId);
  return state ? `mock-${state.sequence}` : "mock-1";
}
