/** Maps seed task index to agent id (1:1 with Object.values(MOCK_TASK_IDS)). */
export const SEED_TASK_AGENT_SLOTS = [
  MOCK_AGENT_IDS.alphaArb,
  MOCK_AGENT_IDS.ethScalper,
  MOCK_AGENT_IDS.solRunner,
  MOCK_AGENT_IDS.avaxGuard,
  MOCK_AGENT_IDS.takeProfitBot,
  MOCK_AGENT_IDS.btcLateTrader,
  MOCK_AGENT_IDS.ethReversal,
  MOCK_AGENT_IDS.solBreakdown,
  MOCK_AGENT_IDS.fundingRotator,
] as const;

export const mockTradingAgents: MockTradingAgent[] = SEED_AGENTS;

export function cloneMockTradingAgents(): MockTradingAgent[] {
  return mockTradingAgents.map((agent) => {
    const metrics = getFleetTradeMetrics(agent.id);
    return {
      ...agent,
      memoryCapacity: { ...agent.memoryCapacity },
      memory: agent.memory.map((item) => ({ ...item })),
      revenue30d: metrics?.revenue30dUsd ?? agent.revenue30d,
      riskScore: metrics?.reputationGrade ?? agent.riskScore,
    };
  });
}

export function linkMockTasksToAgentIds<T extends { id: string; agentId?: string }>(
  tasks: T[],
): T[] {
  const seedSlotByTaskId = new Map<string, string>();
  SEED_TASK_ID_LIST.forEach((taskId, index) => {
    seedSlotByTaskId.set(
      taskId,
      SEED_TASK_AGENT_SLOTS[index] ?? MOCK_AGENT_IDS.alphaArb,
    );
  });

  return tasks.map((task) => {
    const agentId = seedSlotByTaskId.get(task.id);
    if (!agentId) return task;
    return { ...task, agentId };
  });
}
