import { useMemo, useState } from "react";

import Orderbook002 from "@mormlayer/components/orderbook/Orderbook02";
import { SubscriptionProvider } from "@mormlayer/context/SubscriptionContext";
import {
  DEFAULT_HEIGHT_ORDERBOOK,
  DEFAULT_MAX_DEPTH,
  DEFAULT_WS_URL,
} from "@mormlayer/constants";
import { formatOrderbookPrice } from "@mormlayer/sdk/utils/display";
import {
  DEFAULT_JITTER,
  type EnhancementConfig,
} from "@mormlayer/utils/orderbookEnhancement";
import type { OrderbookDepthTooltipPlacement } from "@mormlayer/components/orderbook/orderbookDepthTooltipLayout";

import { ComponentDocPage } from "../layout/ComponentDocPage";
import { DocSection } from "../layout/DocSection";
import { PreviewCanvas } from "../layout/PreviewCanvas";
import { VariantGrid } from "../layout/VariantGrid";

const OFFLINE_BASE_URL = "offline://local";
const DEMO_MARKET_ID = "1";

const ENHANCEMENT_ON: EnhancementConfig = {
  enabled: true,
  jitter: DEFAULT_JITTER,
  fakePending: {
    maxFakeLevelsPerSide: 3,
    minLifetimeMs: 2000,
    maxLifetimeMs: 8000,
    volumeScalePct: 0.8,
    minAddDelayMs: 1500,
    maxAddDelayMs: 5000,
  },
};

function normalizeHeight(raw: string): string {
  const trimmed = raw.trim();
  if (!trimmed) return DEFAULT_HEIGHT_ORDERBOOK;
  if (/^\d+(\.\d+)?$/.test(trimmed)) return `${trimmed}px`;
  if (/^\d+(\.\d+)?(px|rem|em|%|vh)$/i.test(trimmed)) return trimmed;
  return DEFAULT_HEIGHT_ORDERBOOK;
}

function OrderbookPreview({
  maxDepth,
  height,
  animationEnabled,
  enhancementsEnabled,
  tooltipPlacement,
  onPriceClick,
}: {
  maxDepth: number;
  height: string;
  animationEnabled: boolean;
  enhancementsEnabled: boolean;
  tooltipPlacement: OrderbookDepthTooltipPlacement;
  onPriceClick?: (price: number) => void;
}): JSX.Element {
  return (
    <div className="uitest-orderbook-frame">
      <Orderbook002
        baseURL={OFFLINE_BASE_URL}
        marketId={DEMO_MARKET_ID}
        maxDepth={maxDepth}
        height={height}
        animationEnabled={animationEnabled}
        enhancementConfig={enhancementsEnabled ? ENHANCEMENT_ON : { enabled: false }}
        tooltipPlacement={tooltipPlacement}
        onPriceClick={onPriceClick}
      />
    </div>
  );
}

function VariantPreset({
  label,
  description,
  isActive,
  onApply,
}: {
  label: string;
  description: string;
  isActive: boolean;
  onApply: () => void;
}): JSX.Element {
  return (
    <button
      type="button"
      className={`uitest-variant-preset${isActive ? " is-active" : ""}`}
      onClick={onApply}
    >
      <span className="uitest-variant-preset__label">{label}</span>
      <span className="uitest-variant-preset__description">{description}</span>
    </button>
  );
}

function Orderbook02PageContent(): JSX.Element {
  const [maxDepth, setMaxDepth] = useState(DEFAULT_MAX_DEPTH);
  const [heightInput, setHeightInput] = useState(DEFAULT_HEIGHT_ORDERBOOK);
  const [animationEnabled, setAnimationEnabled] = useState(true);
  const [enhancementsEnabled, setEnhancementsEnabled] = useState(true);
  const [tooltipPlacement, setTooltipPlacement] =
    useState<OrderbookDepthTooltipPlacement>("auto");
  const [lastClickedPrice, setLastClickedPrice] = useState<number | null>(null);

  const previewHeight = useMemo(
    () => normalizeHeight(heightInput),
    [heightInput],
  );

  const handleHeightBlur = (): void => {
    const normalized = normalizeHeight(heightInput);
    if (normalized !== heightInput) {
      setHeightInput(normalized);
    }
  };

  return (
    <ComponentDocPage
      title="Orderbook02"
      description="Centered spread orderbook with canvas slots, spread drag pan, depth hover tooltip, and bid/ask footer balance."
    >
      <DocSection
        title="Live preview"
        description="Single offline mock orderbook for BTC (market 1). Adjust controls below — variant presets apply to this preview."
      >
        <div className="uitest-controls">
          <label className="uitest-field">
            <span className="uitest-field__label">Max depth ({maxDepth})</span>
            <input
              className="uitest-input"
              type="range"
              min={5}
              max={40}
              step={1}
              value={maxDepth}
              onChange={(event) => setMaxDepth(Number(event.target.value))}
            />
          </label>
          <label className="uitest-field">
            <span className="uitest-field__label">Height</span>
            <input
              className="uitest-input"
              value={heightInput}
              onChange={(event) => setHeightInput(event.target.value)}
              onBlur={handleHeightBlur}
              placeholder={DEFAULT_HEIGHT_ORDERBOOK}
            />
          </label>
          <label className="uitest-field">
            <span className="uitest-field__label">Tooltip placement</span>
            <select
              className="uitest-input"
              value={tooltipPlacement}
              onChange={(event) =>
                setTooltipPlacement(
                  event.target.value as OrderbookDepthTooltipPlacement,
                )
              }
            >
              <option value="auto">auto</option>
              <option value="left">left</option>
              <option value="right">right</option>
            </select>
          </label>
          <label className="uitest-field uitest-field--checkbox">
            <input
              type="checkbox"
              checked={animationEnabled}
              onChange={(event) => setAnimationEnabled(event.target.checked)}
            />
            <span className="uitest-field__label">Size flash animation</span>
          </label>
          <label className="uitest-field uitest-field--checkbox">
            <input
              type="checkbox"
              checked={enhancementsEnabled}
              onChange={(event) => setEnhancementsEnabled(event.target.checked)}
            />
            <span className="uitest-field__label">
              Enhancements (jitter + fake pending)
            </span>
          </label>
          {lastClickedPrice != null ? (
            <p className="uitest-field__label">
              Last price click: {formatOrderbookPrice(lastClickedPrice)}
            </p>
          ) : null}
        </div>

        <PreviewCanvas className="uitest-preview-canvas--orderbook" minHeight={680}>
          <OrderbookPreview
            maxDepth={maxDepth}
            height={previewHeight}
            animationEnabled={animationEnabled}
            enhancementsEnabled={enhancementsEnabled}
            tooltipPlacement={tooltipPlacement}
            onPriceClick={setLastClickedPrice}
          />
        </PreviewCanvas>
      </DocSection>

      <DocSection
        title="Enhancements"
        description="Apply a preset to the live preview — one mock feed avoids shared-state conflicts."
      >
        <VariantGrid columns={2}>
          <VariantPreset
            label="Enhancements on"
            description="Jitter and fake pending levels layered on the mock feed."
            isActive={enhancementsEnabled}
            onApply={() => setEnhancementsEnabled(true)}
          />
          <VariantPreset
            label="Enhancements off"
            description="Raw mock orderbook without display-only enhancements."
            isActive={!enhancementsEnabled}
            onApply={() => setEnhancementsEnabled(false)}
          />
        </VariantGrid>
      </DocSection>

      <DocSection
        title="Animation"
        description="Apply a preset to toggle size-change flash highlights on level rows."
      >
        <VariantGrid columns={2}>
          <VariantPreset
            label="Animation on"
            description="Flash bid/ask rows when size changes."
            isActive={animationEnabled}
            onApply={() => setAnimationEnabled(true)}
          />
          <VariantPreset
            label="Animation off"
            description="Suppress flash highlights on size updates."
            isActive={!animationEnabled}
            onApply={() => setAnimationEnabled(false)}
          />
        </VariantGrid>
      </DocSection>
    </ComponentDocPage>
  );
}

export function Orderbook02Page(): JSX.Element {
  return (
    <SubscriptionProvider defaultWsURL={DEFAULT_WS_URL}>
      <Orderbook02PageContent />
    </SubscriptionProvider>
  );
}
