/**
 * Cubic-bezier easing function factory
 * Creates an easing function based on cubic-bezier control points
 * https://developer.mozilla.org/en-US/blog/custom-easing-in-css-with-linear/
 *
 * @param x1 - First control point x coordinate
 * @param y1 - First control point y coordinate
 * @param x2 - Second control point x coordinate
 * @param y2 - Second control point y coordinate
 * @returns A function that takes progress (0-1, time fraction) and returns eased progress (0-1, output value)
 */
export function createCubicBezierEasing(
  x1: number,
  y1: number,
  x2: number,
  y2: number,
): (progress: number) => number {
  const getX = (t: number): number => {
    const mt = 1 - t;
    return 3 * mt * mt * t * x1 + 3 * mt * t * t * x2 + t * t * t;
  };

  const getY = (t: number): number => {
    const mt = 1 - t;
    return 3 * mt * mt * t * y1 + 3 * mt * t * t * y2 + t * t * t;
  };

  return (progress: number): number => {
    if (progress <= 0) return 0;
    if (progress >= 1) return 1;

    let t0 = 0;
    let t1 = 1;
    let t = 0.5;

    for (let i = 0; i < 12; i++) {
      const x = getX(t);
      if (Math.abs(x - progress) < 0.0001) break;
      if (x < progress) {
        t0 = t;
      } else {
        t1 = t;
      }
      t = (t0 + t1) / 2;
    }

    return getY(t);
  };
}

/** Pre-hydration fallback only — runtime layout uses measured DOM heights. */
export const ORDERBOOK_LEVEL_ROW_HEIGHT = 20.83333;

/** Pre-hydration fallback only. */
export const ORDERBOOK_SPREAD_ROW_HEIGHT = 20;

export function clampScrollTop(scrollable: HTMLElement, value: number): number {
  const max = Math.max(0, scrollable.scrollHeight - scrollable.clientHeight);
  return Math.max(0, Math.min(value, max));
}

export function sumBoundingHeights(nodes: NodeListOf<Element>): number {
  let total = 0;
  nodes.forEach((el) => {
    total += el.getBoundingClientRect().height;
  });
  return total;
}

export function measureBlockHeights(root: HTMLElement): {
  askBlockH: number;
  bidBlockH: number;
} {
  const askEls = root.querySelectorAll(".orderbook-level.ask");
  const bidEls = root.querySelectorAll(".orderbook-level.bid");
  return {
    askBlockH: sumBoundingHeights(askEls),
    bidBlockH: sumBoundingHeights(bidEls),
  };
}

/** Sum natural row heights inside a side slot (ignores slot overflow clip). */
export function measureSlotContentHeight(slot: HTMLElement): number {
  const rows = slot.querySelectorAll(".orderbook-level");
  if (rows.length > 0) {
    return sumBoundingHeights(rows);
  }
  const empty = slot.querySelector(".message.empty");
  if (empty) {
    return empty.getBoundingClientRect().height;
  }
  return 0;
}

/**
 * Fixed viewport-tall canvas height per side.
 * Rows stack from spread outward (flex-end asks, flex-start bids).
 */
export function computeSideCanvasHeight(viewportH: number): number {
  return viewportH;
}

/** Extra symmetric padding so spread pan has scroll range while rest stays centered. */
export function computePanSlack(viewportH: number): number {
  return Math.round(viewportH * 0.35);
}

export function computeScrollPadding(
  viewportH: number,
  askBlockH: number,
  bidBlockH: number,
  spreadH: number,
  panSlack = computePanSlack(viewportH),
): { paddingTop: number; paddingBottom: number; panSlack: number } {
  const centerTop = Math.max(0, viewportH / 2 - askBlockH - spreadH / 2);
  const centerBottom = Math.max(0, viewportH / 2 - bidBlockH - spreadH / 2);
  return {
    paddingTop: centerTop + panSlack,
    paddingBottom: centerBottom + panSlack,
    panSlack,
  };
}

/**
 * Vertical offset of spread center from section center (px). Zero = centered.
 */
export function measureSpreadDrift(
  section: HTMLElement,
  spreadEl: HTMLElement,
): number {
  const viewportH = section.clientHeight;
  const spreadRect = spreadEl.getBoundingClientRect();
  const sectionRect = section.getBoundingClientRect();
  return (
    spreadRect.top -
    sectionRect.top +
    spreadRect.height / 2 -
    viewportH / 2
  );
}

/**
 * Deterministic rest scroll for viewport canvas layout (before/after paint).
 */
export function computeRestScrollTopFromLayout(
  viewportH: number,
  canvasH: number,
  spreadH: number,
  panSlack: number,
): number {
  return Math.max(0, panSlack + canvasH + spreadH / 2 - viewportH / 2);
}

/**
 * Scroll offset that places the spread at the viewport vertical center.
 * Uses live layout rects so padding and variable row heights are respected.
 */
export function measureRestScrollTop(
  scrollable: HTMLElement,
  spreadEl: HTMLElement,
): number | null {
  const viewportH = scrollable.clientHeight;
  const spreadRect = spreadEl.getBoundingClientRect();
  const spreadH = spreadRect.height;
  if (viewportH === 0 || spreadH === 0) return null;

  const scrollableRect = scrollable.getBoundingClientRect();
  const spreadCenterInContent =
    scrollable.scrollTop +
    (spreadRect.top - scrollableRect.top) +
    spreadH / 2;

  return Math.max(0, spreadCenterInContent - viewportH / 2);
}

/**
 * Pre-hydration fallback scroll offset (fixed row height estimate).
 */
export function getDefaultOrderbookScrollTop(
  viewportHeight: number,
  askCount: number,
): number {
  const askBlockHeight = askCount * ORDERBOOK_LEVEL_ROW_HEIGHT;
  return Math.max(
    0,
    askBlockHeight - viewportHeight / 2 + ORDERBOOK_SPREAD_ROW_HEIGHT / 2,
  );
}
