import { resolveBinanceKlineSymbol } from "../../mormv1/components/tradingview/symbols";
import { toBinanceSymbol } from "../../mormv1/sdk/api/binance/klineUtil";
import { BINANCE_SPOT_WS_BASE } from "../../mormv1/sdk/api/binance/types";

const WS_RECONNECT_BASE_MS = 1000;
const WS_RECONNECT_MAX_MS = 30_000;
const STALE_PRICE_MS = 30_000;

type PriceEntry = {
  price: number;
  updatedAt: number;
};

type BinanceMiniTickerMessage = {
  e?: string;
  c?: string;
};

const pricesByBaseAsset = new Map<string, PriceEntry>();
const listenersByBaseAsset = new Map<string, Set<() => void>>();

let activeBaseAsset: string | null = null;
let refCount = 0;
let ws: WebSocket | null = null;
let reconnectAttempt = 0;
let reconnectTimer: ReturnType<typeof setTimeout> | null = null;

function normalizeBaseAsset(baseAsset: string): string {
  return baseAsset.trim().toUpperCase().replace(/-USDT$/, "");
}

function notifyListeners(baseAsset: string): void {
  listenersByBaseAsset.get(baseAsset)?.forEach((listener) => listener());
}

function clearReconnectTimer(): void {
  if (reconnectTimer !== null) {
    clearTimeout(reconnectTimer);
    reconnectTimer = null;
  }
}

function closeWs(): void {
  clearReconnectTimer();
  if (!ws) return;
  ws.onopen = null;
  ws.onmessage = null;
  ws.onerror = null;
  ws.onclose = null;
  if (ws.readyState === WebSocket.OPEN || ws.readyState === WebSocket.CONNECTING) {
    ws.close();
  }
  ws = null;
}

function buildWsUrl(baseAsset: string): string | null {
  const binanceSymbol = resolveBinanceKlineSymbol(baseAsset);
  if (!binanceSymbol) return null;
  const pair = toBinanceSymbol(binanceSymbol).toLowerCase();
  return `${BINANCE_SPOT_WS_BASE}/${pair}@miniTicker`;
}

function handleWsMessage(event: MessageEvent): void {
  if (!activeBaseAsset) return;
  try {
    const payload = JSON.parse(String(event.data)) as BinanceMiniTickerMessage;
    const close = payload.c;
    if (!close) return;
    const price = parseFloat(close);
    if (!Number.isFinite(price) || price <= 0) return;
    const normalized = normalizeBaseAsset(activeBaseAsset);
    pricesByBaseAsset.set(normalized, { price, updatedAt: Date.now() });
    notifyListeners(normalized);
  } catch {
    // ignore malformed frames
  }
}

function connectWs(): void {
  if (!activeBaseAsset) return;
  const wsUrl = buildWsUrl(activeBaseAsset);
  if (!wsUrl) return;

  closeWs();
  const socket = new WebSocket(wsUrl);
  ws = socket;

  socket.onopen = () => {
    reconnectAttempt = 0;
  };

  socket.onmessage = handleWsMessage;

  socket.onerror = () => {
    // reconnect handled on close
  };

  socket.onclose = () => {
    ws = null;
    if (refCount <= 0 || !activeBaseAsset) return;
    const delay = Math.min(
      WS_RECONNECT_BASE_MS * 2 ** reconnectAttempt,
      WS_RECONNECT_MAX_MS,
    );
    reconnectAttempt += 1;
    reconnectTimer = setTimeout(() => {
      if (refCount > 0 && activeBaseAsset) connectWs();
    }, delay);
  };
}

export function acquireBinanceReferencePrice(baseAsset: string): boolean {
  const normalized = normalizeBaseAsset(baseAsset);
  if (!resolveBinanceKlineSymbol(normalized)) return false;

  if (activeBaseAsset !== normalized) {
    activeBaseAsset = normalized;
    reconnectAttempt = 0;
    if (refCount > 0) connectWs();
  }

  refCount += 1;
  if (refCount === 1) connectWs();
  return true;
}

export function releaseBinanceReferencePrice(baseAsset?: string): void {
  if (baseAsset) {
    const normalized = normalizeBaseAsset(baseAsset);
    if (activeBaseAsset !== normalized) return;
  }

  refCount = Math.max(0, refCount - 1);
  if (refCount === 0) {
    activeBaseAsset = null;
    closeWs();
  }
}

export function getBinanceReferencePrice(baseAsset: string): number | null {
  const normalized = normalizeBaseAsset(baseAsset);
  const entry = pricesByBaseAsset.get(normalized);
  if (!entry) return null;
  if (Date.now() - entry.updatedAt > STALE_PRICE_MS) return null;
  return entry.price;
}

export function subscribeBinanceReferencePrice(
  baseAsset: string,
  listener: () => void,
): () => void {
  const normalized = normalizeBaseAsset(baseAsset);
  let set = listenersByBaseAsset.get(normalized);
  if (!set) {
    set = new Set();
    listenersByBaseAsset.set(normalized, set);
  }
  set.add(listener);
  return () => {
    set?.delete(listener);
    if (set && set.size === 0) listenersByBaseAsset.delete(normalized);
  };
}

/** Test-only: inject a reference price without WebSocket. */
export function setReferencePriceForTest(baseAsset: string, price: number): void {
  const normalized = normalizeBaseAsset(baseAsset);
  pricesByBaseAsset.set(normalized, { price, updatedAt: Date.now() });
  notifyListeners(normalized);
}

/** Test-only: reset hub state. */
export function resetBinanceReferencePriceForTest(): void {
  refCount = 0;
  activeBaseAsset = null;
  closeWs();
  pricesByBaseAsset.clear();
  listenersByBaseAsset.clear();
}
