import { mockWalletState, MOCK_SEED_MARKET } from "./demoData";
import { MOCK_TASK_IDS } from "./agentTasks";
import { mockHashId } from "./mockHashId";
import type { MockRawTrade } from "./demoData";

const SATOSHI = 100_000_000;
const MOCK_WALLET_ADDRESS = mockWalletState.address;
const COUNTERPARTY = "0xdeadbeef00000000000000000000000000000001";

function toSatoshiStr(value: number): string {
  return String(Math.round(value * SATOSHI));
}

/** HL-style fill row for offline Trade History tab. */
export type MockTradeFill = MockRawTrade & {
  dir: string;
  closedPnl: number;
  /** Display fee in USDC (avoids satoshi conversion in UI). */
  fee?: number;
  coin?: string;
  symbol?: string;
  orderId?: string;
  agentTaskId?: string | null;
};

function fill(
  seed: string,
  opts: {
    marketIndex: string;
    coin: string;
    timestamp: string;
    price: number;
    quantity: number;
    dir: string;
    closedPnl: number;
    fee: number;
    userIsBuyer: boolean;
    orderId?: string;
    agentTaskId?: string | null;
  },
): MockTradeFill {
  const tradeId = mockHashId(`mock:trade-history:${seed}`);
  const buyOrderId = mockHashId(`mock:trade-history:buy:${seed}`);
  const sellOrderId = mockHashId(`mock:trade-history:sell:${seed}`);
  return {
    tradeId,
    buyOrderId,
    sellOrderId,
    price: toSatoshiStr(opts.price),
    quantity: toSatoshiStr(opts.quantity),
    timestamp: opts.timestamp,
    marketIndex: opts.marketIndex,
    makerFee: toSatoshiStr(opts.fee * 0.4),
    takerFee: toSatoshiStr(opts.fee),
    dualWriteId: "",
    sequenceId: "1",
    tradeType: "INITIAL",
    buyAddress: opts.userIsBuyer ? MOCK_WALLET_ADDRESS : COUNTERPARTY,
    sellAddress: opts.userIsBuyer ? COUNTERPARTY : MOCK_WALLET_ADDRESS,
    dir: opts.dir,
    closedPnl: opts.closedPnl,
    fee: opts.fee,
    coin: opts.coin,
    symbol: opts.coin,
    orderId: opts.orderId ?? buyOrderId,
    agentTaskId: opts.agentTaskId ?? null,
  };
}

