import { useState, useEffect, useCallback, useRef, MutableRefObject } from "react";
import { InfoClient } from "../sdk";
import { MultiFeedOrderbookData } from "../sdk/types/api";
import { useSubscription } from "../context/SubscriptionContext";
import { toNumberFromSatoshi } from "../sdk/utils/math";
import { isOfflineMode } from "../sdk/utils/onboardMock";
import {
  getMockOrderbookSnapshot,
  resetMockOrderbook,
  tickMockOrderbook,
  getMockOrderbookSequenceId,
  generateMockTradeOnMidShift,
  getMockMarketBaseAsset,
  isJellyOverrideActive,
  getJellyOrderbookSnapshot,
  JELLY_MARKET_INDEX,
} from "../../offline/mock_data";
import { resolveBinanceKlineSymbol } from "../components/tradingview/symbols";
import { getJellyModeActive } from "../../offline/mock_data/jellyevent";
import { getJellyReplayFrameIndex } from "../../offline/mock_data/jellyevent/jellyReplayState";
import { getJellyRowAtFrame } from "../../offline/mock_data/jellyevent";
