import {
  useCallback,
  useLayoutEffect,
  useMemo,
  useRef,
  useState,
  type RefObject,
} from "react";
import {
  computeOrderbookDepthTooltipPosition,
  type OrderbookDepthTooltipLayoutResult,
  type OrderbookDepthTooltipPlacement,
} from "./orderbookDepthTooltipLayout";

const FALLBACK_TOOLTIP_WIDTH = 220;
const FALLBACK_TOOLTIP_HEIGHT = 120;

export interface UseOrderbookDepthTooltipLayoutOptions {
  anchorEl: HTMLElement | null;
  panelEl: HTMLElement | null;
  isActive: boolean;
  placement?: OrderbookDepthTooltipPlacement;
  scrollContainerEl?: HTMLElement | null;
  measureDeps?: readonly unknown[];
}

export interface UseOrderbookDepthTooltipLayoutResult {
  tooltipRef: RefObject<HTMLDivElement>;
  layout: OrderbookDepthTooltipLayoutResult;
}

export function useOrderbookDepthTooltipLayout({
  anchorEl,
  panelEl,
  isActive,
  placement = "auto",
  scrollContainerEl = null,
  measureDeps = [],
}: UseOrderbookDepthTooltipLayoutOptions): UseOrderbookDepthTooltipLayoutResult {
  const tooltipRef = useRef<HTMLDivElement>(null);
  const [size, setSize] = useState({ width: 0, height: 0 });
  const [anchorRect, setAnchorRect] = useState<DOMRectReadOnly | null>(null);
  const [panelRect, setPanelRect] = useState<DOMRectReadOnly | null>(null);

  const updateRects = useCallback(() => {
    if (!anchorEl || !panelEl) {
      setAnchorRect(null);
      setPanelRect(null);
      return;
    }
    setAnchorRect(anchorEl.getBoundingClientRect());
    setPanelRect(panelEl.getBoundingClientRect());
  }, [anchorEl, panelEl]);

  useLayoutEffect(() => {
    if (!isActive || !anchorEl || !panelEl) {
      setAnchorRect(null);
      setPanelRect(null);
      return;
    }

    updateRects();

    const tooltip = tooltipRef.current;
    if (tooltip) {
      const width = tooltip.offsetWidth;
      const height = tooltip.offsetHeight;
      setSize((current) =>
        current.width === width && current.height === height
          ? current
          : { width, height },
      );
    }

    const onReposition = () => updateRects();
    window.addEventListener("resize", onReposition);
    window.addEventListener("scroll", onReposition, true);
    scrollContainerEl?.addEventListener("scroll", onReposition, { passive: true });

    return () => {
      window.removeEventListener("resize", onReposition);
      window.removeEventListener("scroll", onReposition, true);
      scrollContainerEl?.removeEventListener("scroll", onReposition);
    };
  }, [isActive, anchorEl, panelEl, scrollContainerEl, updateRects, ...measureDeps]);

  const layout = useMemo(() => {
    if (!anchorRect || !panelRect) {
      return {
        left: 0,
        top: 0,
        side: "left" as const,
      };
    }

    return computeOrderbookDepthTooltipPosition({
      rowRect: anchorRect,
      panelRect,
      tooltipWidth: size.width > 0 ? size.width : FALLBACK_TOOLTIP_WIDTH,
      tooltipHeight: size.height > 0 ? size.height : FALLBACK_TOOLTIP_HEIGHT,
      placement,
    });
  }, [anchorRect, panelRect, size.width, size.height, placement]);

  return { tooltipRef, layout };
}
