import { useState } from "react";

import { SliderConfirmBar } from "@mormlayer/components/smartlayout/slider-confirm-bar";
import "@mormlayer/components/smartlayout/layout.css";
import { MorpheumLogo } from "@mormlayer/components/ui/MorpheumLogo";

import { ComponentDocPage } from "../layout/ComponentDocPage";
import { DocSection } from "../layout/DocSection";
import { PreviewCanvas } from "../layout/PreviewCanvas";
import { VariantGrid, VariantTile } from "../layout/VariantGrid";

export function SliderConfirmBarPage(): JSX.Element {
  const [label, setLabel] = useState("Slide to confirm");
  const [disabled, setDisabled] = useState(false);
  const [confirmThreshold, setConfirmThreshold] = useState(90);
  const [showIcon, setShowIcon] = useState(false);
  const [confirmCount, setConfirmCount] = useState(0);

  const handleConfirm = () => {
    setConfirmCount((count) => count + 1);
  };

  return (
    <ComponentDocPage
      title="Slider confirm bar"
      description="Drag-to-confirm control used in transfer modal footers. Pointer events support mouse, touch, and pen — slide past the threshold and release to confirm."
    >
      <DocSection
        title="Default preview"
        description="Default arrow thumb on a terminal canvas."
      >
        <PreviewCanvas minHeight={120}>
          <div style={{ width: "100%", maxWidth: 360 }}>
            <SliderConfirmBar onConfirm={() => {}} />
          </div>
        </PreviewCanvas>
      </DocSection>

      <DocSection
        title="Customization"
        description="Edit label, disabled state, confirm threshold, and thumb icon live."
      >
        <div className="uitest-controls">
          <label className="uitest-field">
            <span className="uitest-field__label">Label</span>
            <input
              className="uitest-input"
              value={label}
              onChange={(e) => setLabel(e.target.value)}
            />
          </label>
          <label className="uitest-field">
            <span className="uitest-field__label">
              Confirm threshold ({confirmThreshold}%)
            </span>
            <input
              className="uitest-input"
              type="range"
              min={50}
              max={100}
              step={5}
              value={confirmThreshold}
              onChange={(e) => setConfirmThreshold(Number(e.target.value))}
            />
          </label>
          <label className="uitest-field uitest-field--checkbox">
            <input
              type="checkbox"
              checked={disabled}
              onChange={(e) => setDisabled(e.target.checked)}
            />
            <span className="uitest-field__label">Disabled</span>
          </label>
          <label className="uitest-field uitest-field--checkbox">
            <input
              type="checkbox"
              checked={showIcon}
              onChange={(e) => setShowIcon(e.target.checked)}
            />
            <span className="uitest-field__label">Morpheum logo icon</span>
          </label>
        </div>
        <PreviewCanvas minHeight={120}>
          <SliderConfirmBar
            onConfirm={handleConfirm}
            label={label}
            disabled={disabled}
            confirmThreshold={confirmThreshold}
            icon={
              showIcon ? (
                <MorpheumLogo fill="var(--terminal-bg-deep)" />
              ) : undefined
            }
          />
          <p className="uitest-field__label" style={{ marginTop: 12 }}>
            Confirmed {confirmCount} time{confirmCount === 1 ? "" : "s"}
          </p>
        </PreviewCanvas>
      </DocSection>

      <DocSection
        title="Variants"
        description="Default arrow, transfer-modal logo thumb, and disabled state."
      >
        <VariantGrid columns={1}>
          <VariantTile label="Default arrow">
            <SliderConfirmBar
              onConfirm={() => {}}
              label="Slide to confirm"
            />
          </VariantTile>
          <VariantTile label="Transfer modal — logo icon">
            <SliderConfirmBar
              onConfirm={() => {}}
              label="Slide to confirm"
              icon={<MorpheumLogo fill="var(--terminal-bg-deep)" />}
            />
          </VariantTile>
          <VariantTile label="Disabled">
            <SliderConfirmBar
              onConfirm={() => {}}
              label="Slide to confirm"
              disabled
              icon={<MorpheumLogo fill="var(--terminal-bg-deep)" />}
            />
          </VariantTile>
        </VariantGrid>
      </DocSection>
    </ComponentDocPage>
  );
}
