import { useState } from "react";

import { BellIcon } from "@mormlayer/components/ui/icons/BellIcon";

import { ComponentDocPage } from "../layout/ComponentDocPage";
import { DocSection } from "../layout/DocSection";
import { PreviewCanvas } from "../layout/PreviewCanvas";
import { VariantGrid, VariantTile } from "../layout/VariantGrid";

const SIZES = [
  { label: "14px", width: 14, height: 14 },
  { label: "18px (default)", width: 18, height: 18 },
  { label: "24px", width: 24, height: 24 },
  { label: "32px", width: 32, height: 32 },
] as const;

const COLOR_CLASSES = [
  { label: "Default", className: "uitest-bell-icon--default" },
  { label: "Brand", className: "uitest-bell-icon--brand" },
  { label: "Muted", className: "uitest-bell-icon--muted" },
  { label: "Warning", className: "uitest-bell-icon--warning" },
] as const;

export function BellIconPage(): JSX.Element {
  const [width, setWidth] = useState(18);
  const [height, setHeight] = useState(18);
  const [className, setClassName] = useState("uitest-bell-icon--default");

  return (
    <ComponentDocPage
      title="Bell icon"
      description="Notification bell outline icon. Stroke uses currentColor — set color via className."
    >
      <style>{`
        .uitest-bell-icon--default { color: var(--terminal-text-primary); }
        .uitest-bell-icon--brand { color: var(--terminal-brand); }
        .uitest-bell-icon--muted { color: var(--terminal-text-muted); }
        .uitest-bell-icon--warning { color: var(--terminal-warning, #f5a623); }
      `}</style>

      <DocSection
        title="Default"
        description="18×18 notification bell."
      >
        <PreviewCanvas minHeight={120}>
          <BellIcon />
        </PreviewCanvas>
      </DocSection>

      <DocSection
        title="Customization"
        description="Adjust width, height, and className for stroke color."
      >
        <div className="uitest-controls">
          <label className="uitest-field">
            <span className="uitest-field__label">Width ({width}px)</span>
            <input
              className="uitest-input"
              type="range"
              min={12}
              max={40}
              step={2}
              value={width}
              onChange={(e) => setWidth(Number(e.target.value))}
            />
          </label>
          <label className="uitest-field">
            <span className="uitest-field__label">Height ({height}px)</span>
            <input
              className="uitest-input"
              type="range"
              min={12}
              max={40}
              step={2}
              value={height}
              onChange={(e) => setHeight(Number(e.target.value))}
            />
          </label>
          <label className="uitest-field">
            <span className="uitest-field__label">Color class</span>
            <select
              className="uitest-input"
              value={className}
              onChange={(e) => setClassName(e.target.value)}
            >
              {COLOR_CLASSES.map((preset) => (
                <option key={preset.className} value={preset.className}>
                  {preset.label}
                </option>
              ))}
            </select>
          </label>
        </div>
        <PreviewCanvas minHeight={120}>
          <BellIcon width={width} height={height} className={className} />
        </PreviewCanvas>
      </DocSection>

      <DocSection title="Sizes" description="Common bell icon dimensions.">
        <VariantGrid columns={4}>
          {SIZES.map((size) => (
            <VariantTile key={size.label} label={size.label}>
              <BellIcon width={size.width} height={size.height} />
            </VariantTile>
          ))}
        </VariantGrid>
      </DocSection>

      <DocSection
        title="Color classes"
        description="Stroke inherits currentColor from className."
      >
        <VariantGrid columns={4}>
          {COLOR_CLASSES.map((preset) => (
            <VariantTile key={preset.className} label={preset.label}>
              <BellIcon width={24} height={24} className={preset.className} />
            </VariantTile>
          ))}
        </VariantGrid>
      </DocSection>
    </ComponentDocPage>
  );
}
