import type { AgentTask, ReportTier } from "../../store/types";
import type { AutonomyPolicy } from "./autonomyPolicy";
import { HIGH_AGENCY_AUTONOMY } from "./autonomyPolicy";
import {
  compareGuardrailRisk,
  getGuardrailMeta,
  type RequiredGuardrailMeta,
} from "./guardrailMeta";

export interface TaskReportingMeta extends RequiredGuardrailMeta {
  reportTier: ReportTier;
  tierReason: string;
  approveBy?: string;
}

const INCIDENT_NOTE_RE =
  /circuit-breaker|kill-switch|scope breach|auto-de-risk|hard stop/i;

function hasIncidentHistory(task: AgentTask): boolean {
  return task.statusHistory.some((e) =>
    INCIDENT_NOTE_RE.test(e.note ?? ""),
  );
}

function isScopeBreach(meta: RequiredGuardrailMeta): boolean {
  return (
    meta.riskImpact === "high" &&
    /breach|cap|exposure|scope|notional/i.test(meta.simulationNote)
  );
}

function computeApproveBy(minutes: number): string {
  return new Date(Date.now() + minutes * 60 * 1000).toISOString();
}

export function deriveReportTier(
  task: AgentTask,
  policy: AutonomyPolicy = HIGH_AGENCY_AUTONOMY,
): Pick<TaskReportingMeta, "reportTier" | "tierReason" | "approveBy"> {
  const meta = getGuardrailMeta(task);
  const gateable =
    task.status === "pending" || task.status === "watching";

  if (hasIncidentHistory(task)) {
    return {
      reportTier: "T4",
      tierReason: "Hard stop or scope incident recorded in audit trail.",
    };
  }

  if (gateable) {
    if (isScopeBreach(meta)) {
      return {
        reportTier: "T4",
        tierReason: `Out-of-policy size or scope (${meta.simulationNote}).`,
      };
    }
    if (policy.preset === "manual") {
      return {
        reportTier: "T3",
        tierReason: "Manual mode — all gateable intents require your approval.",
        approveBy: computeApproveBy(policy.t3ApproveByMinutes),
      };
    }
    if (
      meta.riskImpact === "high" ||
      meta.confidencePct < policy.gateMinConfidence
    ) {
      return {
        reportTier: "T3",
        tierReason:
          meta.riskImpact === "high"
            ? `High risk impact — confidence ${meta.confidencePct}%.`
            : `Confidence ${meta.confidencePct}% below gate threshold ${policy.gateMinConfidence}%.`,
        approveBy: computeApproveBy(policy.t3ApproveByMinutes),
      };
    }
    if (
      meta.confidencePct >= policy.silentMinConfidence &&
      meta.riskImpact === "low"
    ) {
      return {
        reportTier: "T0",
        tierReason: "Within silent policy bounds.",
      };
    }
    if (meta.confidencePct < policy.silentMinConfidence) {
      return {
        reportTier: "T2",
        tierReason: `FYI — confidence ${meta.confidencePct}% below ambient band.`,
      };
    }
    return {
      reportTier: "T1",
      tierReason: "Ambient monitoring — within policy bounds.",
    };
  }

  if (task.status === "executing") {
    if (meta.riskImpact === "high") {
      return {
        reportTier: "T2",
        tierReason: "Live execution with elevated risk.",
      };
    }
    return {
      reportTier: "T1",
      tierReason: "Live execution within policy.",
    };
  }

  if (task.status === "paused") {
    return {
      reportTier: "T2",
      tierReason: "Paused — operator intervention.",
    };
  }

  return {
    reportTier: "T0",
    tierReason: "Logged — no surface action required.",
  };
}

export function getTaskReportingMeta(
  task: AgentTask,
  policy: AutonomyPolicy = HIGH_AGENCY_AUTONOMY,
): TaskReportingMeta {
  const base = getGuardrailMeta(task);
  const seeded = task.guardrail;
  const tierFields = deriveReportTier(task, policy);
  return {
    confidencePct: base.confidencePct,
    riskImpact: base.riskImpact,
    expectedFillImpactBps: base.expectedFillImpactBps,
    simulationNote: base.simulationNote,
    reportTier: seeded?.reportTier ?? tierFields.reportTier,
    tierReason: seeded?.tierReason ?? tierFields.tierReason,
    approveBy: seeded?.approveBy ?? tierFields.approveBy,
  };
}

export function isGatedTier(tier: ReportTier): boolean {
  return tier === "T3" || tier === "T4";
}

export function isNeedsYouTask(
  task: AgentTask,
  policy: AutonomyPolicy = HIGH_AGENCY_AUTONOMY,
): boolean {
  const { reportTier } = getTaskReportingMeta(task, policy);
  if (reportTier === "T4") return true;
  if (
    reportTier === "T3" &&
    (task.status === "pending" || task.status === "watching")
  ) {
    return true;
  }
  return false;
}

export function selectSpotlightIntent(
  tasks: AgentTask[],
  policy: AutonomyPolicy = HIGH_AGENCY_AUTONOMY,
): AgentTask | null {
  const needsYou = tasks.filter((t) => isNeedsYouTask(t, policy));
  if (needsYou.length === 0) return null;

  const t4 = needsYou.filter(
    (t) => getTaskReportingMeta(t, policy).reportTier === "T4",
  );
  if (t4.length > 0) {
    return [...t4].sort(compareGuardrailRisk)[0] ?? null;
  }

  const t3 = needsYou.filter(
    (t) => getTaskReportingMeta(t, policy).reportTier === "T3",
  );
  if (t3.length === 0) return null;

  return [...t3].sort((a, b) => {
    const metaA = getTaskReportingMeta(a, policy);
    const metaB = getTaskReportingMeta(b, policy);
    if (metaA.approveBy && metaB.approveBy) {
      const diff =
        new Date(metaA.approveBy).getTime() -
        new Date(metaB.approveBy).getTime();
      if (diff !== 0) return diff;
    }
    return compareGuardrailRisk(a, b);
  })[0] ?? null;
}

export type TierCounts = Record<ReportTier, number>;

export function countByReportTier(
  tasks: AgentTask[],
  policy: AutonomyPolicy = HIGH_AGENCY_AUTONOMY,
): TierCounts {
  const counts: TierCounts = {
    T0: 0,
    T1: 0,
    T2: 0,
    T3: 0,
    T4: 0,
  };
  for (const task of tasks) {
    if (task.status === "completed" || task.status === "rejected") continue;
    const tier = getTaskReportingMeta(task, policy).reportTier;
    counts[tier] += 1;
  }
  return counts;
}

export function countNeedsYou(
  tasks: AgentTask[],
  policy: AutonomyPolicy = HIGH_AGENCY_AUTONOMY,
): number {
  return tasks.filter((t) => isNeedsYouTask(t, policy)).length;
}

const TIER_SORT: Record<ReportTier, number> = {
  T4: 0,
  T3: 1,
  T2: 2,
  T1: 3,
  T0: 4,
};

export function compareReportTier(
  a: AgentTask,
  b: AgentTask,
  policy: AutonomyPolicy = HIGH_AGENCY_AUTONOMY,
): number {
  const tierA = getTaskReportingMeta(a, policy).reportTier;
  const tierB = getTaskReportingMeta(b, policy).reportTier;
  const diff = TIER_SORT[tierA] - TIER_SORT[tierB];
  if (diff !== 0) return diff;
  return compareGuardrailRisk(a, b);
}

export function sortByReportTier(
  tasks: AgentTask[],
  policy: AutonomyPolicy = HIGH_AGENCY_AUTONOMY,
): AgentTask[] {
  return [...tasks].sort((a, b) => compareReportTier(a, b, policy));
}

export type TaskPolicyResolver = (task: AgentTask) => AutonomyPolicy;

function resolveTaskPolicy(
  task: AgentTask,
  policyOrResolver: AutonomyPolicy | TaskPolicyResolver,
): AutonomyPolicy {
  return typeof policyOrResolver === "function"
    ? policyOrResolver(task)
    : policyOrResolver;
}

export function getTaskReportingMetaResolved(
  task: AgentTask,
  policyOrResolver: AutonomyPolicy | TaskPolicyResolver,
): TaskReportingMeta {
  return getTaskReportingMeta(task, resolveTaskPolicy(task, policyOrResolver));
}

export function isNeedsYouTaskResolved(
  task: AgentTask,
  policyOrResolver: AutonomyPolicy | TaskPolicyResolver,
): boolean {
  return isNeedsYouTask(task, resolveTaskPolicy(task, policyOrResolver));
}

export function selectSpotlightIntentResolved(
  tasks: AgentTask[],
  policyOrResolver: AutonomyPolicy | TaskPolicyResolver,
): AgentTask | null {
  const needsYou = tasks.filter((t) =>
    isNeedsYouTaskResolved(t, policyOrResolver),
  );
  if (needsYou.length === 0) return null;

  const t4 = needsYou.filter(
    (t) =>
      getTaskReportingMetaResolved(t, policyOrResolver).reportTier === "T4",
  );
  if (t4.length > 0) {
    return [...t4].sort(compareGuardrailRisk)[0] ?? null;
  }

  const t3 = needsYou.filter(
    (t) =>
      getTaskReportingMetaResolved(t, policyOrResolver).reportTier === "T3",
  );
  if (t3.length === 0) return null;

  return [...t3].sort((a, b) => {
    const metaA = getTaskReportingMetaResolved(a, policyOrResolver);
    const metaB = getTaskReportingMetaResolved(b, policyOrResolver);
    if (metaA.approveBy && metaB.approveBy) {
      const diff =
        new Date(metaA.approveBy).getTime() -
        new Date(metaB.approveBy).getTime();
      if (diff !== 0) return diff;
    }
    return compareGuardrailRisk(a, b);
  })[0] ?? null;
}

export function countByReportTierResolved(
  tasks: AgentTask[],
  policyOrResolver: AutonomyPolicy | TaskPolicyResolver,
): TierCounts {
  const counts: TierCounts = {
    T0: 0,
    T1: 0,
    T2: 0,
    T3: 0,
    T4: 0,
  };
  for (const task of tasks) {
    if (task.status === "completed" || task.status === "rejected") continue;
    const tier = getTaskReportingMetaResolved(task, policyOrResolver).reportTier;
    counts[tier] += 1;
  }
  return counts;
}

export function countNeedsYouResolved(
  tasks: AgentTask[],
  policyOrResolver: AutonomyPolicy | TaskPolicyResolver,
): number {
  return tasks.filter((t) => isNeedsYouTaskResolved(t, policyOrResolver)).length;
}

export function compareReportTierResolved(
  a: AgentTask,
  b: AgentTask,
  policyOrResolver: AutonomyPolicy | TaskPolicyResolver,
): number {
  const tierA = getTaskReportingMetaResolved(a, policyOrResolver).reportTier;
  const tierB = getTaskReportingMetaResolved(b, policyOrResolver).reportTier;
  const diff = TIER_SORT[tierA] - TIER_SORT[tierB];
  if (diff !== 0) return diff;
  return compareGuardrailRisk(a, b);
}

export function sortByReportTierResolved(
  tasks: AgentTask[],
  policyOrResolver: AutonomyPolicy | TaskPolicyResolver,
): AgentTask[] {
  return [...tasks].sort((a, b) =>
    compareReportTierResolved(a, b, policyOrResolver),
  );
}

export function reportTierLabel(tier: ReportTier): string {
  switch (tier) {
    case "T0":
      return "Silent";
    case "T1":
      return "Ambient";
    case "T2":
      return "FYI";
    case "T3":
      return "Gate";
    case "T4":
      return "Incident";
  }
}

const STATUS_GATE_DISPLAY: Record<AgentTask["status"], string> = {
  pending: "Pending",
  watching: "Watching",
  executing: "Executing",
  paused: "Held",
  completed: "Done",
  rejected: "Rejected",
};

/** UI display label for Status / Gate column (plain text, no tier styling). */
export function getIntentGateDisplayLabel(
  task: AgentTask,
  policyOrResolver: AutonomyPolicy | TaskPolicyResolver = HIGH_AGENCY_AUTONOMY,
): string {
  if (isNeedsYouTaskResolved(task, policyOrResolver)) {
    return "Needs you";
  }
  return STATUS_GATE_DISPLAY[task.status] ?? task.status;
}

const GATE_LABEL_PRIORITY: Record<string, number> = {
  "Needs you": 0,
  Executing: 1,
  Watching: 2,
  Pending: 3,
  Held: 4,
  Done: 5,
  Rejected: 6,
};

/** Worst gate label across intents sharing an objective (Needs you wins). */
export function rollUpObjectiveGateLabel(
  intents: AgentTask[],
  policyOrResolver: AutonomyPolicy | TaskPolicyResolver = HIGH_AGENCY_AUTONOMY,
): string {
  let worstLabel = "Rejected";
  let worstPriority = Number.POSITIVE_INFINITY;

  for (const task of intents) {
    const label = getIntentGateDisplayLabel(task, policyOrResolver);
    const priority = GATE_LABEL_PRIORITY[label] ?? 99;
    if (priority < worstPriority) {
      worstPriority = priority;
      worstLabel = label;
    }
  }

  return worstLabel;
}
