import React, { type CSSProperties, type ReactNode } from "react";
import "../../smartlayout/layout.css";
import "./staggeredOverlay.css";

type StaggeredOverlayRootProps = {
  className?: string;
  passThrough?: boolean;
  style?: CSSProperties;
  children: ReactNode;
};

export function StaggeredOverlayRoot({
  className,
  passThrough = false,
  style,
  children,
}: StaggeredOverlayRootProps): JSX.Element {
  const rootClassName = [
    "modal-overlay",
    "staggered-overlay-shell",
    passThrough ? "staggered-overlay-shell--pass-through" : "",
    className,
  ]
    .filter(Boolean)
    .join(" ");

  return (
    <div className={rootClassName} style={style} role="presentation">
      {children}
    </div>
  );
}

type StaggeredOverlayBackdropProps = {
  visible: boolean;
  onClose: () => void;
  style?: CSSProperties;
  className?: string;
};

export function StaggeredOverlayBackdrop({
  visible,
  onClose,
  style,
  className,
}: StaggeredOverlayBackdropProps): JSX.Element {
  const backdropClassName = [
    "staggered-overlay-backdrop",
    visible ? "is-visible" : "",
    className,
  ]
    .filter(Boolean)
    .join(" ");

  return (
    <div
      className={backdropClassName}
      style={style}
      onClick={onClose}
      aria-hidden="true"
    />
  );
}

type StaggeredOverlayPanelProps = {
  open: boolean;
  className?: string;
  style?: CSSProperties;
  children: ReactNode;
  "aria-label": string;
  role?: "dialog" | "menu";
  "aria-modal"?: boolean;
};

export function StaggeredOverlayPanel({
  open,
  className,
  style,
  children,
  role = "dialog",
  "aria-label": ariaLabel,
  "aria-modal": ariaModal = true,
}: StaggeredOverlayPanelProps): JSX.Element {
  const panelClassName = [
    "staggered-overlay-panel",
    className,
    open ? "is-open" : "",
  ]
    .filter(Boolean)
    .join(" ");

  return (
    <div
      className={panelClassName}
      style={style}
      onClick={(e) => e.stopPropagation()}
      role={role}
      aria-modal={role === "dialog" ? ariaModal : undefined}
      aria-label={ariaLabel}
    >
      {children}
    </div>
  );
}
