/**
 * Generate left/right skewed random number in [a, b] using power transform.
 * k > 1 → strong right skew (as used here with k=7.4)
 * k < 1 → left skew
 */
export function skewedRandom(a: number = 0.01, b: number = 20, k: number = 7.4): number {
  const u = Math.random();
  return a + (b - a) * Math.pow(u, k);
}

/** Inter-trade delay in milliseconds sampled from skewedRandom (seconds). */
export function nextTradeDelayMs(a: number = 0.01, b: number = 20, k: number = 7.4): number {
  return skewedRandom(a, b, k) * 1000;
}
