import React from "react";

import { stripInlineTabCount } from "./tabLabels";

export interface TabHeaderLabelProps {
  full: string;
  short?: string;
  title?: string;
}

/**
 * Responsive tab label: shows `full` on wide tab strips, `short` when the strip is narrow.
 * Always one line — parent `.btn-tab` enforces `white-space: nowrap` (no ellipsis).
 */
export function TabHeaderLabel({
  full,
  short,
  title,
}: TabHeaderLabelProps): JSX.Element {
  const tooltip = title ?? stripInlineTabCount(full);
  const baseFull = stripInlineTabCount(full);
  const hasShort = short != null && short !== baseFull;

  if (!hasShort) {
    return (
      <span className="tab-header-label" title={tooltip}>
        {full}
      </span>
    );
  }

  return (
    <span className="tab-header-label" title={tooltip}>
      <span className="tab-header-label--full">{full}</span>
      <span className="tab-header-label--short" aria-hidden="true">
        {short}
      </span>
    </span>
  );
}
