import type * as JellyHeavy from "./jellyHeavyChunk";

let bundle: typeof JellyHeavy | null = null;
let loadPromise: Promise<typeof JellyHeavy> | null = null;

export function isJellyBundleLoaded(): boolean {
  return bundle !== null;
}

export function getJellyBundle(): typeof JellyHeavy | null {
  return bundle;
}

/** Load heavy JELLY datasets on demand (separate Vite chunk). */
export async function ensureJellyBundleLoaded(): Promise<typeof JellyHeavy> {
  if (bundle) return bundle;
  if (!loadPromise) {
    loadPromise = import("./jellyHeavyChunk").then((loaded) => {
      bundle = loaded;
      return loaded;
    });
  }
  return loadPromise;
}
