import React, {
  createContext,
  useCallback,
  useContext,
  useEffect,
  useMemo,
  useRef,
  useState,
  type ReactNode,
} from "react";
import { toast } from "sonner";
import type { CrossChainFlowStep } from "../../types/crossChainFlow";
import { isDesktopTourBreakpoint } from "../welcome-tour/constants";
import type { DepositTourEntryPath } from "./constants";
import { inferTourBreakpointFromWidth } from "./depositTourFlowSync";
import { nextFlowState } from "./depositTourFlowState";

// Registration APIs are stable useCallback([]); consumers must not depend on whole context in useEffect deps.

export interface DepositTourFlowState {
  flowStep: CrossChainFlowStep;
  mode: "deposit" | "withdraw";
  isCrossChainModalOpen: boolean;
}

export interface StartDepositTourOptions {
  entry?: DepositTourEntryPath;
}

export interface DepositTourContextValue {
  runTour: boolean;
  entryPath: DepositTourEntryPath | null;
  stepIndex: number;
  currentBreakpoint: string;
  flowState: DepositTourFlowState | null;
  startDepositTour: (options?: StartDepositTourOptions) => void;
  stopTour: () => void;
  onTourComplete: () => void;
  setStepIndex: (index: number | ((prev: number) => number)) => void;
  registerFlowState: (getter: () => DepositTourFlowState | null) => () => void;
  registerOpenDepositForTour: (fn: () => void) => () => void;
  registerBreakpoint: (getter: () => string) => () => void;
  /** Stop the other spotlight tour before deposit tour starts (e.g. welcome tour). */
  registerTourMutex: (fn: () => void) => () => void;
}

const DepositTourContext = createContext<DepositTourContextValue | undefined>(
  undefined,
);

export interface DepositTourProviderProps {
  children: ReactNode;
  onDepositTourSeen?: () => void;
}

export function DepositTourProvider({
  children,
  onDepositTourSeen,
}: DepositTourProviderProps): JSX.Element {
  const [runTour, setRunTour] = useState(false);
  const [entryPath, setEntryPath] = useState<DepositTourEntryPath | null>(null);
  const [stepIndex, setStepIndex] = useState(0);
  const [currentBreakpoint, setCurrentBreakpointState] = useState("lg");
  const [flowState, setFlowState] = useState<DepositTourFlowState | null>(null);

  const flowStateRef = useRef<(() => DepositTourFlowState | null) | null>(null);
  const openDepositRef = useRef<(() => void) | null>(null);
  const breakpointRef = useRef<(() => string) | null>(null);
  const tourMutexRef = useRef<(() => void) | null>(null);

  const stopTour = useCallback(() => {
    setRunTour(false);
    setEntryPath(null);
    setStepIndex(0);
  }, []);

  const onTourComplete = useCallback(() => {
    setRunTour(false);
    setEntryPath(null);
    setStepIndex(0);
    onDepositTourSeen?.();
  }, [onDepositTourSeen]);

  const startDepositTour = useCallback(
    (options?: StartDepositTourOptions) => {
      const entry = options?.entry ?? "wallet-menu";
      const breakpoint = breakpointRef.current?.() ?? currentBreakpoint;
      if (!isDesktopTourBreakpoint(breakpoint)) {
        toast.info(
          "Deposit tour is available on desktop and tablet view. Widen your window to explore step-by-step.",
        );
        return;
      }
      tourMutexRef.current?.();
      setEntryPath(entry);
      setStepIndex(0);
      setRunTour(true);
      if (entry === "deposit-form") {
        requestAnimationFrame(() => {
          openDepositRef.current?.();
        });
      }
    },
    [currentBreakpoint],
  );

  const registerFlowState = useCallback(
    (getter: () => DepositTourFlowState | null) => {
      flowStateRef.current = getter;
      setFlowState((prev) => nextFlowState(prev, getter()));
      const interval = window.setInterval(() => {
        if (flowStateRef.current) {
          setFlowState((prev) => nextFlowState(prev, flowStateRef.current!()));
        }
      }, 200);
      return () => {
        window.clearInterval(interval);
        if (flowStateRef.current === getter) {
          flowStateRef.current = null;
        }
      };
    },
    [],
  );

  const registerOpenDepositForTour = useCallback((fn: () => void) => {
    openDepositRef.current = fn;
    return () => {
      if (openDepositRef.current === fn) {
        openDepositRef.current = null;
      }
    };
  }, []);

  const registerBreakpoint = useCallback((getter: () => string) => {
    breakpointRef.current = getter;
    setCurrentBreakpointState((prev) => {
      const next = getter();
      return prev === next ? prev : next;
    });
    return () => {
      if (breakpointRef.current === getter) {
        breakpointRef.current = null;
      }
    };
  }, []);

  const registerTourMutex = useCallback((fn: () => void) => {
    tourMutexRef.current = fn;
    return () => {
      if (tourMutexRef.current === fn) {
        tourMutexRef.current = null;
      }
    };
  }, []);

  useEffect(() => {
    const syncBreakpoint = () => {
      const bp =
        breakpointRef.current?.() ??
        inferTourBreakpointFromWidth(window.innerWidth);
      setCurrentBreakpointState((prev) => (prev === bp ? prev : bp));
    };
    syncBreakpoint();
    window.addEventListener("resize", syncBreakpoint);
    const interval = window.setInterval(syncBreakpoint, 300);
    return () => {
      window.removeEventListener("resize", syncBreakpoint);
      window.clearInterval(interval);
    };
  }, []);

  const value = useMemo<DepositTourContextValue>(
    () => ({
      runTour,
      entryPath,
      stepIndex,
      currentBreakpoint,
      flowState,
      startDepositTour,
      stopTour,
      onTourComplete,
      setStepIndex,
      registerFlowState,
      registerOpenDepositForTour,
      registerBreakpoint,
      registerTourMutex,
    }),
    [
      runTour,
      entryPath,
      stepIndex,
      currentBreakpoint,
      flowState,
      startDepositTour,
      stopTour,
      onTourComplete,
      registerFlowState,
      registerOpenDepositForTour,
      registerBreakpoint,
      registerTourMutex,
    ],
  );

  return (
    <DepositTourContext.Provider value={value}>
      {children}
    </DepositTourContext.Provider>
  );
}

export function useDepositTour(): DepositTourContextValue {
  const ctx = useContext(DepositTourContext);
  if (!ctx) {
    throw new Error("useDepositTour must be used within DepositTourProvider");
  }
  return ctx;
}

export function useOptionalDepositTour(): DepositTourContextValue | undefined {
  return useContext(DepositTourContext);
}
