import type { TabSectionTabId } from "../tables/TabSection";

export const HIL_SAFETY_PINNED_TABS: TabSectionTabId[] = [
  "memoryAudit",
  "agentTasks",
];

export const HIL_SAFETY_OPTIONAL_TABS: TabSectionTabId[] = [
  "positions",
  "openOrders",
  "tradeHistory",
  "history",
  "fundingHistory",
  "buckets",
];

export const DEFAULT_HIL_SAFETY_OPTIONAL_TABS: TabSectionTabId[] = [
  "positions",
  "buckets",
];

const OPTIONAL_TAB_SET = new Set<string>(HIL_SAFETY_OPTIONAL_TABS);

export interface HilSafetyTabsPrefs {
  visibleOptionalTabs: TabSectionTabId[];
}

export const DEFAULT_HIL_SAFETY_TABS_PREFS: HilSafetyTabsPrefs = {
  visibleOptionalTabs: DEFAULT_HIL_SAFETY_OPTIONAL_TABS,
};

/** Filter to valid optional tab IDs, dedupe, preserve order. Allows empty. */
export function sanitizeHilSafetyOptionalTabs(
  input: unknown,
): TabSectionTabId[] {
  if (!Array.isArray(input)) return [];

  const seen = new Set<string>();
  const sanitized: TabSectionTabId[] = [];

  for (const item of input) {
    if (typeof item !== "string" || !OPTIONAL_TAB_SET.has(item) || seen.has(item)) {
      continue;
    }
    seen.add(item);
    sanitized.push(item as TabSectionTabId);
  }

  return sanitized;
}

/** Load/migrate prefs: missing or non-array input falls back to default. */
export function normalizeHilSafetyOptionalTabs(input: unknown): TabSectionTabId[] {
  if (!Array.isArray(input)) {
    return [...DEFAULT_HIL_SAFETY_OPTIONAL_TABS];
  }
  return sanitizeHilSafetyOptionalTabs(input);
}

export function buildHilSafetyTabOrder(
  visibleOptional: TabSectionTabId[],
): TabSectionTabId[] {
  const optional = sanitizeHilSafetyOptionalTabs(visibleOptional);
  return [...HIL_SAFETY_PINNED_TABS, ...optional];
}

export function toggleHilSafetyOptionalTab(
  visibleOptional: TabSectionTabId[],
  tabId: TabSectionTabId,
  enabled: boolean,
): TabSectionTabId[] {
  if (!OPTIONAL_TAB_SET.has(tabId)) return visibleOptional;

  if (enabled) {
    if (visibleOptional.includes(tabId)) return visibleOptional;
    return [...visibleOptional, tabId];
  }

  return visibleOptional.filter((id) => id !== tabId);
}

export function moveHilSafetyOptionalTab(
  visibleOptional: TabSectionTabId[],
  tabId: TabSectionTabId,
  direction: "up" | "down",
): TabSectionTabId[] {
  const index = visibleOptional.indexOf(tabId);
  if (index === -1) return visibleOptional;

  const swapIndex = direction === "up" ? index - 1 : index + 1;
  if (swapIndex < 0 || swapIndex >= visibleOptional.length) {
    return visibleOptional;
  }

  const next = [...visibleOptional];
  [next[index], next[swapIndex]] = [next[swapIndex]!, next[index]!];
  return next;
}

export function getHilSafetyTabsDisplayOrder(
  visibleOptional: TabSectionTabId[],
): TabSectionTabId[] {
  const visible = sanitizeHilSafetyOptionalTabs(visibleOptional);
  const hidden = HIL_SAFETY_OPTIONAL_TABS.filter((id) => !visible.includes(id));
  return [...visible, ...hidden];
}
