import React, { useMemo } from "react";
import type { TabSectionTabId } from "../tables/TabSection";
import { getTabLabel, getTerminalTabLabel } from "../smartlayout";
import type { HighAgencyTabsPrefs } from "../tradeagent/highAgencyTabs";
import {
  getHighAgencyTabsDisplayOrder,
  HIGH_AGENCY_OPTIONAL_TABS,
  moveHighAgencyOptionalTab,
  toggleHighAgencyOptionalTab,
} from "../tradeagent/highAgencyTabs";

export interface HighAgencyTabsSettingsProps {
  prefs: HighAgencyTabsPrefs;
  onChange: (prefs: HighAgencyTabsPrefs) => void;
}

function HighAgencyTabsSettings({
  prefs,
  onChange,
}: HighAgencyTabsSettingsProps): JSX.Element {
  const visibleOptional = prefs.visibleOptionalTabs;

  const displayOrder = useMemo(
    () => getHighAgencyTabsDisplayOrder(visibleOptional),
    [visibleOptional],
  );

  const setVisibleOptional = (next: TabSectionTabId[]) => {
    onChange({ visibleOptionalTabs: next });
  };

  return (
    <div className="hil-safety-tabs-settings">
      <p className="settings-chart-overlay-hint hil-safety-tabs-settings-intro">
        Applies to the Agent tab set only. Raw Pro tables are unchanged.
      </p>

      <div className="hil-safety-tabs-settings-section">
        <p className="hil-safety-tabs-settings-section-label">Always shown</p>
        <label className="settings-toggle hil-safety-tabs-row hil-safety-tabs-row--pinned">
          <input type="checkbox" checked disabled readOnly />
          <span>{getTabLabel("agentTasks").full}</span>
        </label>
      </div>

      <div className="hil-safety-tabs-settings-section">
        <p className="hil-safety-tabs-settings-section-label">
          Optional tables
        </p>
        {displayOrder.map((tabId) => {
          const isVisible = visibleOptional.includes(tabId);
          const visibleIndex = visibleOptional.indexOf(tabId);
          const tabLabel = getTerminalTabLabel(tabId);

          return (
            <div
              key={tabId}
              className={`hil-safety-tabs-row${isVisible ? " is-visible" : ""}`}
            >
              <label className="settings-toggle hil-safety-tabs-row-check">
                <input
                  type="checkbox"
                  checked={isVisible}
                  onChange={(e) =>
                    setVisibleOptional(
                      toggleHighAgencyOptionalTab(
                        visibleOptional,
                        tabId,
                        e.target.checked,
                      ),
                    )
                  }
                />
                <span>{tabLabel}</span>
              </label>
              <div className="hil-safety-tabs-row-actions">
                <button
                  type="button"
                  className="hil-safety-tabs-move-btn"
                  aria-label={`Move ${tabLabel} up`}
                  disabled={!isVisible || visibleIndex <= 0}
                  onClick={() =>
                    setVisibleOptional(
                      moveHighAgencyOptionalTab(visibleOptional, tabId, "up"),
                    )
                  }
                >
                  ↑
                </button>
                <button
                  type="button"
                  className="hil-safety-tabs-move-btn"
                  aria-label={`Move ${tabLabel} down`}
                  disabled={
                    !isVisible || visibleIndex >= visibleOptional.length - 1
                  }
                  onClick={() =>
                    setVisibleOptional(
                      moveHighAgencyOptionalTab(visibleOptional, tabId, "down"),
                    )
                  }
                >
                  ↓
                </button>
              </div>
            </div>
          );
        })}
        <p className="settings-chart-overlay-hint">
          Hidden: {HIGH_AGENCY_OPTIONAL_TABS.length - visibleOptional.length} of{" "}
          {HIGH_AGENCY_OPTIONAL_TABS.length} optional tables.
        </p>
      </div>
    </div>
  );
}

export default React.memo(HighAgencyTabsSettings);
