import React, { useState, useRef, useEffect } from "react";
import "./layout.css";

export interface SliderConfirmBarProps {
  onConfirm: () => void;
  label?: string;
  confirmThreshold?: number; // Percentage (0-100) to trigger confirmation, default 90
  disabled?: boolean;
  icon?: React.ReactNode; // Icon to render on the thumb button
}

/**
 * Slider confirm bar - drag to the right end to confirm.
 * Uses Pointer Events so drag works on mouse, touch, and pen.
 */
export function SliderConfirmBar({
  onConfirm,
  label = "Slide to confirm",
  confirmThreshold = 90,
  disabled = false,
  icon,
}: SliderConfirmBarProps): JSX.Element {
  const [dragProgress, setDragProgress] = useState(0);
  const [isDragging, setIsDragging] = useState(false);
  const sliderRef = useRef<HTMLDivElement>(null);
  const dragProgressRef = useRef(0);

  const handlePointerDown = (e: React.PointerEvent<HTMLDivElement>) => {
    if (disabled) return;
    e.preventDefault();
    e.currentTarget.setPointerCapture(e.pointerId);
    setIsDragging(true);
  };

  useEffect(() => {
    if (!isDragging) return;

    const updateProgress = (clientX: number) => {
      if (!sliderRef.current || disabled) return;

      const rect = sliderRef.current.getBoundingClientRect();
      const x = clientX - rect.left;
      const progress = Math.max(0, Math.min(100, (x / rect.width) * 100));
      dragProgressRef.current = progress;
      setDragProgress(progress);
    };

    const finishDrag = () => {
      if (disabled) return;

      if (dragProgressRef.current >= confirmThreshold) {
        onConfirm();
        setTimeout(() => {
          dragProgressRef.current = 0;
          setDragProgress(0);
        }, 200);
      } else {
        dragProgressRef.current = 0;
        setDragProgress(0);
      }
      setIsDragging(false);
    };

    const handlePointerMove = (e: PointerEvent) => {
      updateProgress(e.clientX);
    };

    window.addEventListener("pointermove", handlePointerMove);
    window.addEventListener("pointerup", finishDrag);
    window.addEventListener("pointercancel", finishDrag);

    return () => {
      window.removeEventListener("pointermove", handlePointerMove);
      window.removeEventListener("pointerup", finishDrag);
      window.removeEventListener("pointercancel", finishDrag);
    };
  }, [isDragging, confirmThreshold, onConfirm, disabled]);

  const isConfirmed = dragProgress >= confirmThreshold;

  return (
    <div
      ref={sliderRef}
      className={`slider-confirm-bar ${disabled ? "disabled" : ""} ${isDragging ? "dragging" : ""}`}
    >
      {/* Progress fill */}
      <div
        className={`slider-confirm-bar-progress ${isConfirmed ? "confirmed" : "default"} ${isDragging ? "no-transition" : ""}`}
        style={{
          width: `${dragProgress}%`,
        }}
      />
      {/* Label */}
      <div className="slider-confirm-bar-label">
        {isConfirmed ? "Release to confirm" : label}
      </div>
      {/* Draggable thumb */}
      <div
        onPointerDown={handlePointerDown}
        className={`slider-confirm-bar-thumb ${disabled ? "disabled" : ""} ${isDragging ? "dragging" : ""} ${isConfirmed ? "confirmed" : ""}`}
        style={{
          left: `${dragProgress}%`,
        }}
      >
        {icon ? (
          <span className={`slider-confirm-bar-thumb-icon ${isConfirmed ? "confirmed" : ""}`}>
            {icon}
          </span>
        ) : (
          <span className={`slider-confirm-bar-thumb-arrow ${isConfirmed ? "confirmed" : ""}`}>
            →
          </span>
        )}
      </div>
    </div>
  );
}
