import { getAgentProfileById } from "./agentProfile";
import { ALL_CATALOG_AGENT_SEEDS } from "./agentCatalogSeeds";
import { getFleetAgentByDid, mockEvmAddress } from "./fleetCatalog";
import { mockHashId } from "./mockHashId";

export type AgentTokenProfile = {
  agentDid: string;
  seedKey: string;
  rank?: number;
  chain: string;
  fullyDilutedValuation: string;
  circulatingSupply: string;
  totalSupply: string;
  maxSupply: string;
  explorerLabel: string;
  categories: string[];
  /** ISO 8601 — set when fleet has a deployed token. */
  tokenIssuedAt?: string;
  /** On-chain fee recipient from the token contract. */
  feeRecipient?: string;
};

function formatSupplyBillions(value: number): string {
  if (value >= 1) {
    return `${value.toFixed(2)}B`;
  }
  return `${(value * 1000).toFixed(0)}M`;
}

const TOKEN_ISSUED_MIN_DAYS_AFTER_DEPLOY = 1;
const TOKEN_ISSUED_MAX_DAYS_AFTER_DEPLOY = 30;

function deterministicTokenIssuedAt(
  seedKey: string,
  agentDeployedAt: string,
): string {
  const hash = mockHashId(`fleet:token-issued-at:${seedKey}`);
  const daySpan =
    TOKEN_ISSUED_MAX_DAYS_AFTER_DEPLOY - TOKEN_ISSUED_MIN_DAYS_AFTER_DEPLOY;
  const dayOffset =
    TOKEN_ISSUED_MIN_DAYS_AFTER_DEPLOY
    + (Number.parseInt(hash.slice(0, 6), 16) % (daySpan + 1));
  const deployedMs = Date.parse(agentDeployedAt);
  const issuedMs = deployedMs + dayOffset * 24 * 60 * 60 * 1000;
  return new Date(issuedMs).toISOString();
}

function buildTokenProfile(seedKey: string, agentDid: string): AgentTokenProfile {
  const profile = getAgentProfileById(seedKey);
  const fleet = getFleetAgentByDid(agentDid);
  const seed = mockHashId(`agent-token:${seedKey}`);
  const rankBase = Number.parseInt(seed.slice(0, 4), 16);
  const rank = 1800 + (rankBase % 1200);
  const supplyBase = 2 + (Number.parseInt(seed.slice(4, 8), 16) % 80) / 10;
  const circulatingRatio = 0.35 + (Number.parseInt(seed.slice(8, 12), 16) % 40) / 100;
  const circulating = supplyBase * circulatingRatio;
  const total = supplyBase * 0.95;
  const max = supplyBase;

  const fdvMultiplier = 1.15 + (Number.parseInt(seed.slice(12, 16), 16) % 25) / 100;
  const marketCapRaw = profile?.marketCap ?? "$10.0M";
  const capMatch = marketCapRaw.match(/\$?([\d.]+)\s*([MmKk])?/);
  const capValue = capMatch ? Number.parseFloat(capMatch[1]) : 10;
  const capUnit = capMatch?.[2]?.toUpperCase() ?? "M";
  const fdvValue = capValue * fdvMultiplier;
  const fdv = `$${fdvValue.toFixed(1)}${capUnit}`;

  const sector = profile?.sector ?? "Trading";
  const product = profile?.product ?? "Perp";

  const hasToken = Boolean(fleet?.tokenAddress?.trim());

  return {
    agentDid,
    seedKey,
    rank,
    chain: "Hyperliquid Perp",
    fullyDilutedValuation: fdv,
    circulatingSupply: formatSupplyBillions(circulating),
    totalSupply: formatSupplyBillions(total),
    maxSupply: formatSupplyBillions(max),
    explorerLabel: "Fleet explorer",
    categories: [`${sector} agent`, product, profile?.strategy ?? "Execution"],
    tokenIssuedAt:
      hasToken && fleet?.agentDeployedAt
        ? deterministicTokenIssuedAt(seedKey, fleet.agentDeployedAt)
        : undefined,
    feeRecipient: hasToken
      ? mockEvmAddress(`fleet:fee-recipient:${seedKey}`)
      : undefined,
  };
}

const tokenProfileByAgentDid = new Map(
  ALL_CATALOG_AGENT_SEEDS.map((seed) => [
    seed.did,
    buildTokenProfile(seed.id, seed.did),
  ]),
);

export function getAgentTokenProfile(
  agentDid: string,
): AgentTokenProfile | undefined {
  const fleet = getFleetAgentByDid(agentDid);
  if (!fleet?.tokenAddress?.trim()) {
    return undefined;
  }
  return tokenProfileByAgentDid.get(fleet.agentDid);
}
