import { create } from "zustand";
import { cloneMockFleetSupervisors } from "../../offline/mock_data/fleetSupervisors";
import { cloneMockTradingAgents } from "../../offline/mock_data";
import type {
  AgentListingPatch,
  AgentListingStatus,
  AgentMemoryItem,
  FleetSupervisor,
  TradingAgent,
  TradingAgentStoreState,
} from "./types";
import { MOCK_FLEET_IDS, MOCK_SUPERVISOR_IDS } from "../../offline/mock_data/fleetSupervisors";
import { BASE_AGENT_ALLOCATION_MB } from "./memoryPoolStore";

function generateHashId(): string {
  if (typeof crypto !== "undefined" && crypto.randomUUID) {
    return crypto.randomUUID().replace(/-/g, "").slice(0, 16);
  }
  return `${Date.now().toString(16)}${Math.random().toString(16).slice(2, 10)}`.slice(
    0,
    16,
  );
}

function nowIso(): string {
  return new Date().toISOString();
}

export function deriveSelectedAgentId(
  selectedAgentIds: string[],
): string | null {
  return selectedAgentIds.length === 1 ? selectedAgentIds[0]! : null;
}

export const useTradingAgentStore = create<TradingAgentStoreState>(
  (set, get) => ({
    agents: cloneMockTradingAgents() as TradingAgent[],
    supervisors: cloneMockFleetSupervisors() as FleetSupervisor[],
    selectedAgentIds: [],

    addAgent: (input) => {
      const timestamp = nowIso();
      const id = input.id ?? generateHashId();
      const agent: TradingAgent = {
        id,
        displayName: input.displayName,
        icon: input.icon ?? "🤖",
        memory: input.memory ?? [],
        memoryCapacity: input.memoryCapacity ?? {
          allocatedMb: BASE_AGENT_ALLOCATION_MB,
          tier: "base",
        },
        revenue30d: input.revenue30d,
        riskScore: input.riskScore,
        status: input.status ?? "idle",
        supervisorId: input.supervisorId ?? MOCK_SUPERVISOR_IDS.soloDesk,
        fleetId: input.fleetId ?? MOCK_FLEET_IDS.soloDesk,
        role: input.role ?? "executor",
        did: input.did ?? `did:morpheum:agent:${id}`,
        handle: input.handle,
        versionTag: input.versionTag ?? "v1",
        permissionMode: input.permissionMode ?? "watch_only",
        marketSymbol: input.marketSymbol,
        provisioningStatus: input.provisioningStatus ?? "ready",
        gatewayEnabled: input.gatewayEnabled ?? false,
        walletAddress: input.walletAddress,
        vaultAddress: input.vaultAddress,
        listingStatus: input.listingStatus ?? "private",
        listingType: input.listingType,
        listingCategory: input.listingCategory,
        listingDescription: input.listingDescription,
        listingVisibility: input.listingVisibility,
        paymentState: input.paymentState,
        spendCapDailyUsd: input.spendCapDailyUsd,
        spendUsedDailyUsd: input.spendUsedDailyUsd,
        counterpartyAllowlistCount: input.counterpartyAllowlistCount,
        paymentOut30dUsd: input.paymentOut30dUsd,
        paymentIn30dUsd: input.paymentIn30dUsd,
        mandateSummary: input.mandateSummary,
        createdAt: input.createdAt ?? timestamp,
        updatedAt: input.updatedAt ?? timestamp,
      };
      set((state) => ({
        agents: [...state.agents, agent],
      }));

      if (agent.provisioningStatus === "provisioning") {
        window.setTimeout(() => {
          get().updateAgentProvisioningStatus(agent.id, "ready");
        }, 1500);
      }

      return agent;
    },

    updateAgentMemory: (agentId, memory) => {
      const at = nowIso();
      set((state) => ({
        agents: state.agents.map((agent) =>
          agent.id === agentId
            ? { ...agent, memory, updatedAt: at }
            : agent,
        ),
      }));
    },

    appendMemoryNote: (agentId, text) => {
      const trimmed = text.trim();
      if (!trimmed) return;
      const at = nowIso();
      const item: AgentMemoryItem = {
        id: generateHashId(),
        text: trimmed,
        at,
      };
      set((state) => ({
        agents: state.agents.map((agent) =>
          agent.id === agentId
            ? {
                ...agent,
                memory: [...agent.memory, item],
                updatedAt: at,
              }
            : agent,
        ),
      }));
    },

    setSelectedAgentId: (id) => {
      set({ selectedAgentIds: id ? [id] : [] });
    },

    toggleFleetAgent: (id) => {
      set((state) => {
        const has = state.selectedAgentIds.includes(id);
        const next = has
          ? state.selectedAgentIds.filter((agentId) => agentId !== id)
          : [...state.selectedAgentIds, id];
        return { selectedAgentIds: next };
      });
    },

    selectAllAgents: () => {
      set({ selectedAgentIds: [] });
    },

    clearFleetSelection: () => {
      set({ selectedAgentIds: [] });
    },

    getAgentById: (id) => {
      return get().agents.find((agent) => agent.id === id);
    },

    getSupervisorById: (id) => {
      return get().supervisors.find((supervisor) => supervisor.id === id);
    },

    getAgentsBySupervisor: (supervisorId) => {
      return get().agents.filter((agent) => agent.supervisorId === supervisorId);
    },

    getAgentsByFleet: (fleetId) => {
      return get().agents.filter((agent) => agent.fleetId === fleetId);
    },

    resolveDefaultAgentId: () => {
      const state = get();
      const derived = deriveSelectedAgentId(state.selectedAgentIds);
      if (derived) {
        const exists = state.agents.some((a) => a.id === derived);
        if (exists) return derived;
      }
      if (state.agents.length > 0) {
        return state.agents[0]!.id;
      }
      const created = get().addAgent({
        displayName: "default_agent",
        icon: "🤖",
        status: "active",
        riskScore: "Medium",
        role: "executor",
        did: `did:morpheum:agent:default`,
        versionTag: "v1",
        listingStatus: "private",
      });
      return created.id;
    },

    updateAgentListingStatus: (agentId, listingStatus) => {
      get().patchAgentListing(agentId, { listingStatus });
    },

    patchAgentListing: (agentId, patch: AgentListingPatch) => {
      const at = nowIso();
      set((state) => ({
        agents: state.agents.map((agent) =>
          agent.id === agentId
            ? {
                ...agent,
                ...(patch.listingStatus !== undefined
                  ? { listingStatus: patch.listingStatus }
                  : {}),
                ...(patch.listingType !== undefined
                  ? { listingType: patch.listingType }
                  : {}),
                ...(patch.listingCategory !== undefined
                  ? { listingCategory: patch.listingCategory }
                  : {}),
                ...(patch.listingDescription !== undefined
                  ? { listingDescription: patch.listingDescription }
                  : {}),
                ...(patch.listingVisibility !== undefined
                  ? { listingVisibility: patch.listingVisibility }
                  : {}),
                updatedAt: at,
              }
            : agent,
        ),
      }));
    },

    updateAgentProvisioningStatus: (agentId, provisioningStatus) => {
      const at = nowIso();
      set((state) => ({
        agents: state.agents.map((agent) =>
          agent.id === agentId
            ? { ...agent, provisioningStatus, updatedAt: at }
            : agent,
        ),
      }));
    },

    updateAgentStatus: (agentId, status) => {
      const at = nowIso();
      set((state) => ({
        agents: state.agents.map((agent) =>
          agent.id === agentId ? { ...agent, status, updatedAt: at } : agent,
        ),
      }));
    },
  }),
);

export function selectAgentCount(agents: TradingAgent[]): number {
  return agents.length;
}

export function selectMemoryPreview(agent: TradingAgent | undefined): string {
  if (!agent || agent.memory.length === 0) return "";
  return agent.memory[agent.memory.length - 1]?.text ?? "";
}
