import { JELLY_ANCHOR_INDEX } from "./jellyConstants";

let replayFrameIndex: number = JELLY_ANCHOR_INDEX;

export function setJellyReplayFrameIndex(index: number): void {
  replayFrameIndex = index;
}

export function getJellyReplayFrameIndex(): number {
  return replayFrameIndex;
}

export function resetJellyReplayFrameIndex(): void {
  replayFrameIndex = JELLY_ANCHOR_INDEX;
}
