import { createPortal } from "react-dom";
import type { JSX } from "react";
import {
  formatNumber,
  formatOrderbookPrice,
  formatPercentage,
  formatSize,
} from "../../sdk/utils/display";
import type { OrderbookHoverMetrics } from "./orderbookHoverMetrics";
import type { OrderbookDepthTooltipPlacement } from "./orderbookDepthTooltipLayout";
import { useOrderbookDepthTooltipLayout } from "./useOrderbookDepthTooltipLayout";

export interface OrderbookDepthTooltipProps {
  metrics: OrderbookHoverMetrics;
  anchorEl: HTMLElement;
  panelEl: HTMLElement;
  scrollContainerEl?: HTMLElement | null;
  baseAsset: string;
  quoteAsset: string;
  placement?: OrderbookDepthTooltipPlacement;
}

function TooltipRow({
  label,
  value,
}: {
  label: string;
  value: string;
}): JSX.Element {
  return (
    <div className="orderbook-depth-tooltip__row">
      <span className="orderbook-depth-tooltip__label">{label}</span>
      <span className="orderbook-depth-tooltip__value">{value}</span>
    </div>
  );
}

function OrderbookDepthTooltip({
  metrics,
  anchorEl,
  panelEl,
  scrollContainerEl = null,
  baseAsset,
  quoteAsset,
  placement = "auto",
}: OrderbookDepthTooltipProps): JSX.Element | null {
  const { tooltipRef, layout } = useOrderbookDepthTooltipLayout({
    anchorEl,
    panelEl,
    isActive: true,
    placement,
    scrollContainerEl,
    measureDeps: [
      metrics.distanceFromMid,
      metrics.averagePrice,
      metrics.totalBase,
      metrics.totalQuote,
      baseAsset,
      quoteAsset,
    ],
  });

  const content = (
    <div
      ref={tooltipRef}
      className={`orderbook-depth-tooltip orderbook-depth-tooltip--${layout.side}`}
      style={{
        left: layout.left,
        top: layout.top,
      }}
      role="tooltip"
    >
      <TooltipRow
        label="Distance from Mid"
        value={formatPercentage(metrics.distanceFromMid)}
      />
      <TooltipRow
        label="Average Price"
        value={formatOrderbookPrice(metrics.averagePrice)}
      />
      <TooltipRow
        label={`Total (${baseAsset})`}
        value={formatSize(metrics.totalBase)}
      />
      <TooltipRow
        label={`Total (${quoteAsset})`}
        value={formatNumber(metrics.totalQuote, 0, 0)}
      />
    </div>
  );

  return createPortal(content, document.body);
}

export default OrderbookDepthTooltip;
