/** Bucket-level autonomy preset stored on copy relations (matches AutonomyPreset in mormv1). */
export type CopyAutonomyPreset = "manual" | "guarded" | "highAgency";

export type CopyBucketMode = "new" | "existing";

/** @deprecated Legacy risk level — migrated on load in fleetCopyStore. */
export type CopyRiskLevel = "low" | "medium" | "high";

export type CopySettings = {
  bucketId: string;
  bucketMode: CopyBucketMode;
  /** Set when bucketMode === "new". */
  startingMargin?: number;
  copySizePct: number;
  autonomyPreset: CopyAutonomyPreset;
  startedAt: string;
};

export type CopyRelation = {
  id: string;
  copierWallet: string;
  targetAgentDid: string;
  copySettings: CopySettings;
};

export const FLEET_COPY_STORAGE_PREFIX = "fleet_copy:v1:";

export function fleetCopyStorageKey(copierWallet: string): string {
  return `${FLEET_COPY_STORAGE_PREFIX}${copierWallet.trim().toLowerCase()}`;
}

/** Map legacy risk level to autonomy preset. */
export function copyRiskLevelToAutonomyPreset(
  riskLevel: CopyRiskLevel,
): CopyAutonomyPreset {
  return riskLevel === "low" ? "guarded" : "highAgency";
}
