import type { AgentKpiSummary } from "./agentKpiHistory.types";
import { computeReputationScore } from "./fleetReputationScore";
import { mockHashId } from "./mockHashId";

export type CopyReputationBand = "A" | "B" | "C" | "D" | "E";

export const COPY_COUNT_BAND_RANGES: Record<CopyReputationBand, readonly [number, number]> = {
  A: [6000, 12_000],
  B: [3000, 6000],
  C: [1200, 3000],
  D: [400, 1200],
  E: [80, 400],
};

export function parseCopyReputationBand(riskLabel: string): CopyReputationBand {
  if (riskLabel.startsWith("A")) return "A";
  if (riskLabel.startsWith("B")) return "B";
  if (riskLabel.startsWith("C")) return "C";
  if (riskLabel.startsWith("D")) return "D";
  if (riskLabel.startsWith("E")) return "E";
  return "C";
}

/** Deterministic copier count scaled by reputation band and composite score. */
export function deriveCopyCountFromReputation(
  summary: AgentKpiSummary,
  seedKey: string,
): number {
  const band = parseCopyReputationBand(summary.riskLabel);
  const [min, max] = COPY_COUNT_BAND_RANGES[band];
  const score = computeReputationScore(summary);
  const t = Math.min(1, Math.max(0, score / 100));
  const jitter =
    Number.parseInt(mockHashId(`copy:jitter:${seedKey}`).slice(0, 4), 16) % 1000;
  const span = max - min;
  const raw = min + span * t + jitter * 0.1;
  return Math.round(Math.min(max + 200, Math.max(min, raw)));
}

export function isPopularCopyCount(copyCount: number, riskLabel: string): boolean {
  const band = parseCopyReputationBand(riskLabel);
  return band === "A" || band === "B" || copyCount >= 3000;
}

export function buildCopyCountSeries(
  finalCopyCount: number,
  pointCount: number,
  catalogIndex: number,
): number[] {
  const copyStart = Math.max(
    80,
    finalCopyCount - 900 - (catalogIndex % 5) * 120,
  );
  const series: number[] = [];
  for (let i = 0; i < pointCount; i += 1) {
    const t = pointCount > 1 ? i / (pointCount - 1) : 1;
    series.push(Math.round(copyStart + (finalCopyCount - copyStart) * t));
  }
  series[series.length - 1] = finalCopyCount;
  return series;
}
