import React from "react";

import "./terminalHeroHeader.css";

function joinClassNames(
  ...parts: Array<string | false | null | undefined>
): string {
  return parts.filter(Boolean).join(" ");
}

export type TerminalHeroLayout = "stack" | "grid";
export type TerminalHeroSettingsReveal = "always" | "hover";

export interface TerminalHeroHeaderProps {
  /** Page slot wrapper classes, e.g. `markets-slot markets-header-band`. */
  className?: string;
  height?: string;
  layout?: TerminalHeroLayout;
  /** Vertical alignment for stack layout. */
  stackAlign?: "center" | "start";
  /** Reveal settings control on hover (desktop). */
  settingsReveal?: TerminalHeroSettingsReveal;
  /** Reserve right padding for the settings gear. */
  settingsPadding?: boolean;
  /** Single-column grid (e.g. staking disconnected). */
  gridSingleColumn?: boolean;
  /** Row layout with trailing actions (e.g. vault list mobile). */
  inlineTrailing?: boolean;
  breadcrumb?: React.ReactNode;
  /** Plain string renders `h1.terminal-hero-title`. */
  title?: React.ReactNode;
  /** Full title row; overrides `title` / `titleTrailing`. */
  titleRow?: React.ReactNode;
  /** Rendered below the title row. */
  subtitle?: React.ReactNode;
  /** Inline content after the title in the title row. */
  titleTrailing?: React.ReactNode;
  /** `space-between` on the title row (index detail + price). */
  titleRowSpread?: boolean;
  /** Prevent the H1 from shrinking in a crowded title row. */
  titleFixed?: boolean;
  /** Wider gap between breadcrumb and title row (agent detail). */
  contentGap?: "sm" | "md";
  /** Settings gear and similar chrome. */
  actions?: React.ReactNode;
  /** Second grid column or inline trailing slot. */
  trailing?: React.ReactNode;
}

function TerminalHeroHeader({
  className,
  height = "100%",
  layout = "stack",
  stackAlign = "center",
  settingsReveal = "always",
  settingsPadding = false,
  gridSingleColumn = false,
  inlineTrailing = false,
  breadcrumb,
  title,
  titleRow,
  subtitle,
  titleTrailing,
  titleRowSpread = false,
  titleFixed = false,
  contentGap = "sm",
  actions,
  trailing,
}: TerminalHeroHeaderProps): JSX.Element {
  const hasTitleBlock = titleRow != null || title != null || titleTrailing != null;

  const titleRowContent =
    titleRow ??
    (hasTitleBlock ? (
      <>
        {typeof title === "string" ? (
          <h1
            className={joinClassNames(
              "terminal-hero-title",
              titleFixed && "terminal-hero-title--fixed",
            )}
          >
            {title}
          </h1>
        ) : (
          title
        )}
        {titleTrailing}
      </>
    ) : null);

  const content =
    breadcrumb || hasTitleBlock || subtitle ? (
      <div
        className={joinClassNames(
          "terminal-hero-header__content",
          contentGap === "md" && "terminal-hero-header__content--gap-md",
        )}
      >
        {breadcrumb}
        {titleRowContent ? (
          <div
            className={joinClassNames(
              "terminal-hero-title-row",
              titleRowSpread && "terminal-hero-title-row--spread",
            )}
          >
            {titleRowContent}
          </div>
        ) : null}
        {subtitle ? (
          <div className="terminal-hero-header__subtitle">{subtitle}</div>
        ) : null}
      </div>
    ) : null;

  return (
    <div
      className={joinClassNames(
        "terminal-hero-header",
        layout === "grid"
          ? "terminal-hero-header--grid"
          : joinClassNames(
              "terminal-hero-header--stack",
              stackAlign === "start" && "terminal-hero-header--stack-start",
              inlineTrailing && "terminal-hero-header--inline-trailing",
            ),
        settingsReveal === "hover" && "terminal-hero-header--settings-hover",
        settingsPadding && "terminal-hero-header--settings-padding",
        gridSingleColumn && "terminal-hero-header--grid-single",
        className,
      )}
      style={{ height }}
    >
      {actions ? (
        <div className="terminal-header-band-actions">{actions}</div>
      ) : null}
      {content}
      {trailing}
    </div>
  );
}

export default React.memo(TerminalHeroHeader);
