import { mockHashId } from "./mockHashId";
import { MOCK_AGENT_IDS } from "./tradingAgents";

/** Catalog seed keys linked to wallet-owned trading agents (same DID on list). */
export const TRADING_AGENT_CATALOG_SEED_KEYS: Record<string, keyof typeof MOCK_AGENT_IDS> = {
  alphabot: "alphaArb",
  quantpup: "ethScalper",
  volthawk: "solRunner",
  "neural-hedger": "takeProfitBot",
};

export function mockTradingAgentDid(agentHexId: string): string {
  return `did:morpheum:agent:${agentHexId.trim()}`;
}

/** Deterministic DID for a marketplace catalog seed (PRNG anchor stays on seedKey). */
export function mockCatalogAgentDid(seedKey: string): string {
  const normalized = seedKey.trim().toLowerCase();
  const tradingKey = TRADING_AGENT_CATALOG_SEED_KEYS[normalized];
  if (tradingKey) {
    return mockTradingAgentDid(MOCK_AGENT_IDS[tradingKey]);
  }
  return `did:morpheum:agent:${mockHashId(`catalog:${normalized}`)}`;
}

/** URL-safe storage key for mock JSON filenames and route segments. */
export function agentDidToStorageKey(did: string): string {
  return mockHashId(`agent-did:${did.trim()}`);
}

export function agentDidToRouteParam(did: string): string {
  return agentDidToStorageKey(did);
}

export function resolveAgentDid(input: string | null | undefined): string | null {
  const trimmed = input?.trim();
  if (!trimmed) return null;
  if (trimmed.startsWith("did:morpheum:agent:")) return trimmed;

  const lower = trimmed.toLowerCase();
  const bySeed = SEED_KEY_TO_DID.get(lower);
  if (bySeed) return bySeed;

  const byStorage = STORAGE_KEY_TO_DID.get(lower);
  if (byStorage) return byStorage;

  return null;
}

export function resolveCatalogSeedKey(input: string): string | null {
  const trimmed = input.trim();
  if (!trimmed) return null;

  const lower = trimmed.toLowerCase();
  if (SEED_KEY_TO_DID.has(lower)) return lower;

  if (trimmed.startsWith("did:morpheum:agent:")) {
    return DID_TO_SEED_KEY.get(trimmed) ?? null;
  }

  return STORAGE_KEY_TO_SEED_KEY.get(lower) ?? null;
}

const SEED_KEY_TO_DID = new Map<string, string>();
const DID_TO_SEED_KEY = new Map<string, string>();
const STORAGE_KEY_TO_DID = new Map<string, string>();
const STORAGE_KEY_TO_SEED_KEY = new Map<string, string>();

export function registerCatalogAgentIdentity(seedKey: string, did: string): void {
  const normalizedSeed = seedKey.trim().toLowerCase();
  SEED_KEY_TO_DID.set(normalizedSeed, did);
  DID_TO_SEED_KEY.set(did, normalizedSeed);
  const storageKey = agentDidToStorageKey(did);
  STORAGE_KEY_TO_DID.set(storageKey, did);
  STORAGE_KEY_TO_SEED_KEY.set(storageKey, normalizedSeed);
}

export function getCatalogSeedKeyForDid(did: string): string | undefined {
  return DID_TO_SEED_KEY.get(did.trim());
}

export function getAgentDidForSeedKey(seedKey: string): string | undefined {
  return SEED_KEY_TO_DID.get(seedKey.trim().toLowerCase());
}

/** True when input resolves to the same agent as agentDid/seedKey (DID, storage key, or legacy seed). */
export function agentIdentityMatches(
  agentDid: string,
  seedKey: string | undefined,
  input: string | null | undefined,
): boolean {
  const trimmed = input?.trim();
  if (!trimmed) return false;
  const lower = trimmed.toLowerCase();
  if (agentDid === trimmed || agentDid.toLowerCase() === lower) return true;
  if (seedKey && seedKey.toLowerCase() === lower) return true;
  if (agentDidToStorageKey(agentDid).toLowerCase() === lower) return true;
  const resolved = resolveAgentDid(trimmed);
  return resolved != null && resolved === agentDid;
}

/** Normalize copy-relation / lookup input to canonical agent DID when possible. */
export function normalizeAgentDidInput(input: string): string {
  const trimmed = input.trim();
  const resolved = resolveAgentDid(trimmed);
  return resolved ?? trimmed;
}
