import { create } from "zustand";

const STORAGE_KEY = "morpheum:memory-pool";

export const DEFAULT_POOL_MB = 512;
export const DEFAULT_RESERVED_MB = 340;
export const BASE_AGENT_ALLOCATION_MB = 4;
export const DEFAULT_TOP_UP_MB = 64;

interface MemoryPoolPersisted {
  poolMb: number;
  reservedMb: number;
}

export interface MemoryPoolStoreState {
  poolMb: number;
  reservedMb: number;
  baseAgentAllocationMb: number;
  canMint: (allocationMb?: number) => boolean;
  reserveForMint: (allocationMb?: number) => boolean;
  topUpMemory: (additionalMb?: number) => void;
  resetPool: () => void;
}

function loadPersisted(): MemoryPoolPersisted {
  if (typeof sessionStorage === "undefined") {
    return { poolMb: DEFAULT_POOL_MB, reservedMb: DEFAULT_RESERVED_MB };
  }
  try {
    const raw = sessionStorage.getItem(STORAGE_KEY);
    if (!raw) {
      return { poolMb: DEFAULT_POOL_MB, reservedMb: DEFAULT_RESERVED_MB };
    }
    const parsed = JSON.parse(raw) as MemoryPoolPersisted;
    return {
      poolMb: parsed.poolMb ?? DEFAULT_POOL_MB,
      reservedMb: parsed.reservedMb ?? DEFAULT_RESERVED_MB,
    };
  } catch {
    return { poolMb: DEFAULT_POOL_MB, reservedMb: DEFAULT_RESERVED_MB };
  }
}

function persist(state: MemoryPoolPersisted): void {
  if (typeof sessionStorage === "undefined") return;
  sessionStorage.setItem(STORAGE_KEY, JSON.stringify(state));
}

const initial = loadPersisted();

export const useMemoryPoolStore = create<MemoryPoolStoreState>((set, get) => ({
  poolMb: initial.poolMb,
  reservedMb: initial.reservedMb,
  baseAgentAllocationMb: BASE_AGENT_ALLOCATION_MB,

  canMint: (allocationMb) => {
    const mb = allocationMb ?? get().baseAgentAllocationMb;
    const { poolMb, reservedMb } = get();
    return reservedMb + mb <= poolMb;
  },

  reserveForMint: (allocationMb) => {
    const mb = allocationMb ?? get().baseAgentAllocationMb;
    if (!get().canMint(mb)) return false;
    set((state) => {
      const next = { ...state, reservedMb: state.reservedMb + mb };
      persist({ poolMb: next.poolMb, reservedMb: next.reservedMb });
      return next;
    });
    return true;
  },

  topUpMemory: (additionalMb = DEFAULT_TOP_UP_MB) => {
    set((state) => {
      const next = { ...state, poolMb: state.poolMb + additionalMb };
      persist({ poolMb: next.poolMb, reservedMb: next.reservedMb });
      return next;
    });
  },

  resetPool: () => {
    const next = { poolMb: DEFAULT_POOL_MB, reservedMb: DEFAULT_RESERVED_MB };
    persist(next);
    set((state) => ({ ...state, ...next }));
  },
}));
