import type { PendingOrder } from "../../sdk/types/data";
import type { AgentTask } from "../../store/types";
import {
  classifyChartOrderCategory,
  isChartEligibleOrder,
  isPendingOrderStatus,
  isScaleOrderType,
  type PendingOrderLineCategory,
} from "../../sdk/utils/orderFilters";
import {
  resolveChartSide,
  resolveMarkerKind,
  resolveMarkerLabel,
  type ExecutionMarkerKind,
} from "./chartMarkers";
import { toNumberFromSatoshi } from "../../sdk/utils/math";

export const MAX_VISIBLE_ORDER_LINES = 20;

export type { PendingOrderLineCategory };

export interface PendingOrderLineFilters {
  agent: boolean;
  manual: boolean;
  scale: boolean;
  limit: boolean;
  stopLimit: boolean;
}

export const DEFAULT_PENDING_ORDER_LINE_FILTERS: PendingOrderLineFilters = {
  agent: true,
  manual: true,
  scale: true,
  limit: true,
  stopLimit: true,
};

export interface ChartPendingOrderLine {
  lineId: string;
  orderId: string;
  price: number;
  side: "Buy" | "Sell";
  kind: ExecutionMarkerKind;
  agentTaskId?: string;
  label: string;
  remainingQuantity: number;
  isScaleLeg: boolean;
  orderTypeCategory: PendingOrderLineCategory;
  parentOrderId?: string;
  memberLineIds?: string[];
}

export interface ChartPendingOrderLineMeta extends ChartPendingOrderLine {
  task?: AgentTask;
}

export interface PendingOrdersToChartLinesOptions {
  currentPrice?: number | null;
  maxVisible?: number;
  tickSize?: number;
  filters?: PendingOrderLineFilters;
}

export interface PendingOrdersToChartLinesResult {
  lines: ChartPendingOrderLine[];
  metaByLineId: Map<string, ChartPendingOrderLineMeta>;
  overflowCount: number;
}

interface ScaleOrderLegRaw {
  orderId?: string;
  price: number | string;
  quantity?: number | string;
  status?: string;
}

function buildTaskMap(tasks: AgentTask[]): Map<string, AgentTask> {
  return new Map(tasks.map((task) => [task.id, task]));
}

function parseLegNumber(value: number | string | undefined, fallback = 0): number {
  if (value == null) return fallback;
  if (typeof value === "number") {
    return Number.isFinite(value) ? value : fallback;
  }
  const str = String(value).trim();
  if (str === "") return fallback;
  if (str.includes(".")) {
    const decimal = parseFloat(str);
    return Number.isFinite(decimal) ? decimal : fallback;
  }
  const fromSatoshi = toNumberFromSatoshi(str);
  if (fromSatoshi > 0) return fromSatoshi;
  const parsed = parseFloat(str);
  return Number.isFinite(parsed) ? parsed : fallback;
}

function readScaleLegs(raw: Record<string, unknown> | undefined): ScaleOrderLegRaw[] | null {
  if (!raw) return null;
  const candidates = [raw.legs, raw.ordersList, raw.childOrders];
  for (const candidate of candidates) {
    if (Array.isArray(candidate) && candidate.length > 0) {
      return candidate as ScaleOrderLegRaw[];
    }
  }
  return null;
}

function resolveOrderTypeCategory(order: PendingOrder): PendingOrderLineCategory {
  const raw = order.raw as Record<string, unknown> | undefined;
  const orderType = raw?.orderType ?? order.type ?? "";
  return classifyChartOrderCategory(orderType);
}

function buildLineFromOrder(
  order: PendingOrder,
  overrides: Partial<ChartPendingOrderLine> & Pick<ChartPendingOrderLine, "lineId" | "price" | "remainingQuantity">,
): ChartPendingOrderLine {
  const kind = resolveMarkerKind(order.agentTaskId);
  const side = resolveChartSide(order.side);
  return {
    lineId: overrides.lineId,
    orderId: overrides.orderId ?? order.orderId,
    price: overrides.price,
    side,
    kind,
    agentTaskId: order.agentTaskId ?? undefined,
    label: resolveMarkerLabel(kind, order.agentTaskId),
    remainingQuantity: overrides.remainingQuantity,
    isScaleLeg: overrides.isScaleLeg ?? false,
    orderTypeCategory: overrides.orderTypeCategory ?? resolveOrderTypeCategory(order),
    parentOrderId: overrides.parentOrderId,
    memberLineIds: overrides.memberLineIds,
  };
}

/**
 * Expand a pending order into chart lines. Scale parents require `raw.legs`,
 * `raw.ordersList`, or `raw.childOrders` with `{ orderId?, price, quantity? }`.
 */
export function expandPendingOrderToLines(order: PendingOrder): ChartPendingOrderLine[] {
  if (!isPendingOrderStatus(String(order.status ?? ""))) {
    return [];
  }

  const raw = order.raw as Record<string, unknown> | undefined;
  const orderType = String(raw?.orderType ?? order.type ?? "");

  if (isScaleOrderType(orderType)) {
    const legs = readScaleLegs(raw);
    if (!legs) {
      if (process.env.NODE_ENV !== "production") {
        console.warn(
          "[chartOrderLines] Scale order missing leg array:",
          order.orderId,
        );
      }
      return [];
    }

    return legs
      .map((leg, index) => {
        const legStatus = leg.status != null ? String(leg.status) : order.status;
        if (!isPendingOrderStatus(legStatus)) return null;

        const price = parseLegNumber(leg.price, order.price);
        const quantity = parseLegNumber(leg.quantity, order.remainingQuantity);
        const legOrderId = leg.orderId ?? `${order.orderId}:leg:${index}`;

        return buildLineFromOrder(order, {
          lineId: `${order.orderId}:leg:${index}`,
          orderId: legOrderId,
          price,
          remainingQuantity: quantity,
          isScaleLeg: true,
          orderTypeCategory: "scale",
          parentOrderId: order.orderId,
        });
      })
      .filter((line): line is ChartPendingOrderLine => line != null);
  }

  if (!isChartEligibleOrder(order)) {
    return [];
  }

  return [
    buildLineFromOrder(order, {
      lineId: order.orderId,
      price: order.price,
      remainingQuantity: order.remainingQuantity,
    }),
  ];
}

export function filterPendingOrdersForMarket(
  orders: PendingOrder[],
  marketId: string,
): PendingOrder[] {
  if (!marketId) return [];
  return orders.filter((order) => String(order.marketId) === String(marketId));
}

export function matchesPendingOrderLineFilters(
  line: ChartPendingOrderLine,
  filters: PendingOrderLineFilters,
): boolean {
  if (line.kind === "agent" && !filters.agent) return false;
  if (line.kind === "manual" && !filters.manual) return false;
  if (line.orderTypeCategory === "scale" && !filters.scale) return false;
  if (line.orderTypeCategory === "limit" && !filters.limit) return false;
  if (line.orderTypeCategory === "stop_limit" && !filters.stopLimit) return false;
  return true;
}

export function filterChartPendingOrderLines(
  lines: readonly ChartPendingOrderLine[],
  filters: PendingOrderLineFilters,
): ChartPendingOrderLine[] {
  return lines.filter((line) => matchesPendingOrderLineFilters(line, filters));
}

function bucketKey(line: ChartPendingOrderLine, tickSize: number): string {
  const bucketPrice = Math.round(line.price / tickSize) * tickSize;
  return `${line.side}:${line.kind}:${bucketPrice.toFixed(8)}`;
}

export function derivePriceTickSize(prices: number[], currentPrice?: number | null): number {
  if (prices.length === 0) {
    return currentPrice != null && currentPrice >= 1000 ? 1 : 0.01;
  }
  const sorted = [...prices].sort((a, b) => a - b);
  let minGap = Infinity;
  for (let i = 1; i < sorted.length; i++) {
    const gap = Math.abs(sorted[i]! - sorted[i - 1]!);
    if (gap > 0 && gap < minGap) minGap = gap;
  }
  if (!Number.isFinite(minGap) || minGap === Infinity) {
    const ref = currentPrice ?? sorted[0] ?? 100;
    return ref >= 1000 ? 1 : ref >= 10 ? 0.01 : 0.0001;
  }
  const magnitude = Math.pow(10, Math.floor(Math.log10(minGap)));
  return Math.max(magnitude / 10, 0.0001);
}

export function bucketChartOrderLines(
  lines: ChartPendingOrderLine[],
  tickSize: number,
): ChartPendingOrderLine[] {
  const buckets = new Map<string, ChartPendingOrderLine>();

  for (const line of lines) {
    const key = bucketKey(line, tickSize);
    const existing = buckets.get(key);
    if (!existing) {
      buckets.set(key, {
        ...line,
        memberLineIds: [line.lineId],
      });
      continue;
    }

    const memberLineIds = [...(existing.memberLineIds ?? [existing.lineId]), line.lineId];
    const extraCount = memberLineIds.length - 1;
    buckets.set(key, {
      ...existing,
      remainingQuantity: existing.remainingQuantity + line.remainingQuantity,
      memberLineIds,
      label: extraCount > 0 ? `${existing.label} +${extraCount}` : existing.label,
    });
  }

  return [...buckets.values()];
}

function lineDistanceFromPrice(line: ChartPendingOrderLine, currentPrice: number | null | undefined): number {
  if (currentPrice == null || !Number.isFinite(currentPrice)) return Infinity;
  return Math.abs(line.price - currentPrice);
}

function compareLinePriority(
  a: ChartPendingOrderLine,
  b: ChartPendingOrderLine,
  currentPrice: number | null | undefined,
): number {
  const distA = lineDistanceFromPrice(a, currentPrice);
  const distB = lineDistanceFromPrice(b, currentPrice);
  if (distA !== distB) return distA - distB;
  if (a.kind !== b.kind) {
    return a.kind === "manual" ? -1 : 1;
  }
  return a.price - b.price;
}

export function capChartOrderLines(
  lines: ChartPendingOrderLine[],
  maxVisible: number,
  currentPrice?: number | null,
): { lines: ChartPendingOrderLine[]; overflowCount: number } {
  if (lines.length <= maxVisible) {
    return { lines, overflowCount: 0 };
  }
  const sorted = [...lines].sort((a, b) => compareLinePriority(a, b, currentPrice));
  return {
    lines: sorted.slice(0, maxVisible),
    overflowCount: sorted.length - maxVisible,
  };
}

export function pendingOrderLinePriceRange(
  lines: readonly ChartPendingOrderLine[],
  paddingRatio = 0.08,
): { from: number; to: number } | null {
  if (lines.length === 0) return null;

  const prices = lines.map((line) => line.price);
  let min = Math.min(...prices);
  let max = Math.max(...prices);

  if (min === max) {
    const floor = Math.max(Math.abs(min) * 0.001, 1);
    min -= floor;
    max += floor;
  }

  const span = max - min;
  const pad = span * paddingRatio;
  return { from: min - pad, to: max + pad };
}

export function pendingOrdersToChartLines(
  orders: PendingOrder[],
  tasks: AgentTask[],
  marketId: string,
  options: PendingOrdersToChartLinesOptions = {},
): PendingOrdersToChartLinesResult {
  const maxVisible = options.maxVisible ?? MAX_VISIBLE_ORDER_LINES;
  const taskMap = buildTaskMap(tasks);
  const marketOrders = filterPendingOrdersForMarket(orders, marketId);

  const expanded = marketOrders.flatMap((order) => expandPendingOrderToLines(order));
  const filters = options.filters ?? DEFAULT_PENDING_ORDER_LINE_FILTERS;
  const filtered = filterChartPendingOrderLines(expanded, filters);
  const tickSize = options.tickSize ?? derivePriceTickSize(
    filtered.map((line) => line.price),
    options.currentPrice,
  );
  const bucketed = bucketChartOrderLines(filtered, tickSize);
  const { lines, overflowCount } = capChartOrderLines(
    bucketed,
    maxVisible,
    options.currentPrice,
  );

  const metaByLineId = new Map<string, ChartPendingOrderLineMeta>();
  for (const line of lines) {
    metaByLineId.set(line.lineId, {
      ...line,
      task: line.agentTaskId ? taskMap.get(line.agentTaskId) : undefined,
    });
  }

  return { lines, metaByLineId, overflowCount };
}
