import React, {
  createContext,
  useContext,
  type ReactNode,
} from "react";

export interface DemoGuideActions {
  startJellyIncident?: () => void;
  openNetworkHealth?: () => void;
  openWelcomeHub?: () => void;
}

const DemoGuideActionsContext = createContext<DemoGuideActions | undefined>(
  undefined,
);

export interface DemoGuideActionsProviderProps {
  children: ReactNode;
  value: DemoGuideActions;
}

export function DemoGuideActionsProvider({
  children,
  value,
}: DemoGuideActionsProviderProps): JSX.Element {
  return (
    <DemoGuideActionsContext.Provider value={value}>
      {children}
    </DemoGuideActionsContext.Provider>
  );
}

export function useDemoGuideActions(): DemoGuideActions | undefined {
  return useContext(DemoGuideActionsContext);
}
