import React, { type CSSProperties, type JSX } from "react";
import { MorpheumLogoPaths, MORPHEUM_LOGO_VIEWBOX } from "./MorpheumLogo";
import { useMatrixText } from "./useMatrixText";
import "./morpheum-loading.css";

export type MorpheumLoadingOverlayLayout = "absolute" | "fixed";

export interface MorpheumLoadingOverlayProps {
  label?: string;
  layout?: MorpheumLoadingOverlayLayout;
  matrixText?: boolean;
  className?: string;
  style?: CSSProperties;
}

export function MorpheumLoadingOverlay({
  label = "Loading...",
  layout = "absolute",
  matrixText = false,
  className,
  style,
}: MorpheumLoadingOverlayProps): JSX.Element {
  const displayLabel = useMatrixText(label, matrixText);
  const layoutClass =
    layout === "fixed"
      ? "morpheum-loading-overlay--fixed"
      : "morpheum-loading-overlay--absolute";

  return (
    <div
      className={["morpheum-loading-overlay", layoutClass, className]
        .filter(Boolean)
        .join(" ")}
      style={style}
      role="status"
      aria-live="polite"
    >
      <svg
        className="morpheum-loading-logo"
        viewBox={MORPHEUM_LOGO_VIEWBOX}
        fill="none"
        xmlns="http://www.w3.org/2000/svg"
        aria-hidden="true"
      >
        <g className="morpheum-loading-logo__ghost">
          <MorpheumLogoPaths fill="#C8F5A8" />
        </g>
        <g className="morpheum-loading-logo__fill">
          <MorpheumLogoPaths fill="#C8F5A8" />
        </g>
      </svg>
      <span
        className={[
          "morpheum-loading-label",
          "terminal-label",
          matrixText ? "morpheum-loading-label--matrix" : "",
        ]
          .filter(Boolean)
          .join(" ")}
        aria-label={label}
      >
        {displayLabel}
      </span>
    </div>
  );
}

export default MorpheumLoadingOverlay;
