export const DECORATIVE_CARD_NORMAL_TYPES = [
  "transparent",
  "transparent-gradient",
  "brand-dark",
  "brand-light",
  "gray-dark",
  "gray-light",
] as const;

export const DECORATIVE_CARD_STRIP_TYPES = [
  "transparent-strip",
  "gray-strip",
  "gradient-strip",
  "salmon-strip",
] as const;

export const DECORATIVE_CARD_VERTICAL_STRIP_TYPES = [
  "gray-strip-vertical",
  "gradient-strip-vertical",
  "salmon-strip-vertical",
] as const;

export type DecorativeCardType =
  | (typeof DECORATIVE_CARD_NORMAL_TYPES)[number]
  | (typeof DECORATIVE_CARD_STRIP_TYPES)[number]
  | (typeof DECORATIVE_CARD_VERTICAL_STRIP_TYPES)[number];

export function isStripType(type: DecorativeCardType): boolean {
  return (DECORATIVE_CARD_STRIP_TYPES as readonly string[]).includes(type);
}

export function isVerticalStripType(type: DecorativeCardType): boolean {
  return (DECORATIVE_CARD_VERTICAL_STRIP_TYPES as readonly string[]).includes(type);
}

export function isGradientDiffusorType(type: DecorativeCardType): boolean {
  return type === "transparent-gradient";
}
