export type MockAgentTaskStatus =
  | "pending"
  | "watching"
  | "executing"
  | "completed"
  | "paused";

export type MockAgentTaskStatusEvent = {
  status: MockAgentTaskStatus;
  at: string;
  note?: string;
};

export type MockAgentTaskGuardrailMeta = {
  confidencePct?: number;
  riskImpact?: "low" | "moderate" | "high";
  expectedFillImpactBps?: number;
  simulationNote?: string;
};

export type MockAgentTask = {
  id: string;
  agentId: string;
  description: string;
  status: MockAgentTaskStatus;
  marketId: string | null;
  bucketId: string | null;
  trigger: string;
  eta: string | null;
  createdAt: string;
  updatedAt: string;
  isNew: boolean;
  statusBeforePause?: MockAgentTaskStatus;
  statusHistory: MockAgentTaskStatusEvent[];
  guardrail?: MockAgentTaskGuardrailMeta;
  objectiveId?: string | null;
  objectiveSummary?: string;
};

const SEED_BUCKET_IDS = [BUCKET_CROSS_1, BUCKET_ISOLATED_1, BUCKET_CROSS_2];

const MOCK_TASK_ID_SET = new Set<string>(Object.values(MOCK_TASK_IDS));

export function isMockSeedTaskId(id: string): boolean {
  return MOCK_TASK_ID_SET.has(id);
}

function resolveBucketId(bucketIds: string[], slot: number): string | null {
  if (bucketIds.length === 0) return null;
  const index = Math.min(slot, bucketIds.length - 1);
  return bucketIds[index] ?? null;
}

