function buildSeedTasks(bucketIds: string[]): MockAgentTask[] {
  const tasks = SEED_TASK_DEFINITIONS.map((task, index) => ({
    ...task,
    bucketId: resolveBucketId(
      bucketIds,
      SEED_TASK_BUCKET_SLOTS[index] ?? 0,
    ),
  }));

  return applyObjectiveGrouping(tasks);
}

const LATE_CYCLE_SUMMARY =
  "Exit late-cycle positions across BTC, ETH, and SOL on drawdown triggers";

const BOOK_SCALE_SUMMARY =
  "Scale into BTC breakout and ETH range on cross-margin book";

function applyObjectiveGrouping(tasks: MockAgentTask[]): MockAgentTask[] {
  const lateCycleIds = new Set([
    MOCK_TASK_IDS.btcLateExit,
    MOCK_TASK_IDS.ethLateExit,
    MOCK_TASK_IDS.solLateExit,
  ]);
  const bookScaleIds = new Set([MOCK_TASK_IDS.btcWatching, MOCK_TASK_IDS.ethScale]);

  return tasks.map((task) => {
    if (lateCycleIds.has(task.id as (typeof MOCK_TASK_IDS)[keyof typeof MOCK_TASK_IDS])) {
      return {
        ...task,
        objectiveId: MOCK_OBJECTIVE_IDS.lateCycleExit,
        objectiveSummary: LATE_CYCLE_SUMMARY,
      };
    }
    if (bookScaleIds.has(task.id as (typeof MOCK_TASK_IDS)[keyof typeof MOCK_TASK_IDS])) {
      return {
        ...task,
        objectiveId: MOCK_OBJECTIVE_IDS.bookScale,
        objectiveSummary: BOOK_SCALE_SUMMARY,
      };
    }
    return task;
  });
}

export const mockAgentTasks: MockAgentTask[] = buildSeedTasks(SEED_BUCKET_IDS);

export function cloneMockAgentTasks(): MockAgentTask[] {
  return mockAgentTasks.map((task) => ({
    ...task,
    guardrail: task.guardrail ? { ...task.guardrail } : undefined,
    statusHistory: task.statusHistory.map((event) => ({ ...event })),
  }));
}

export function linkMockAgentTasksToBucketIds<T extends { id: string; bucketId: string | null }>(
  tasks: T[],
  bucketIds: string[],
): T[] {
  if (bucketIds.length === 0) return tasks;

  const seedSlotById = new Map<string, number>(
    SEED_TASK_DEFINITIONS.map((task, index) => [
      task.id,
      SEED_TASK_BUCKET_SLOTS[index] ?? 0,
    ]),
  );

  return tasks.map((task) => {
    if (!MOCK_TASK_ID_SET.has(task.id)) return task;
    const slot = seedSlotById.get(task.id);
    if (slot == null) return task;
    return {
      ...task,
      bucketId: resolveBucketId(bucketIds, slot),
    };
  });
}
