import { useState } from "react";

import { ExpandCollapseIcon } from "@mormlayer/components/ui/ExpandCollapseIcon";
import type { ExpandCollapseIconProps } from "@mormlayer/components/ui/ExpandCollapseIcon";

import { ComponentDocPage } from "../layout/ComponentDocPage";
import { DocSection } from "../layout/DocSection";
import { PreviewCanvas } from "../layout/PreviewCanvas";
import { VariantGrid, VariantTile } from "../layout/VariantGrid";

const SIZES = [12, 16, 20, 24] as const;
const STROKE_WIDTHS = [1, 2, 3] as const;

export function ExpandCollapseIconPage(): JSX.Element {
  const [expanded, setExpanded] = useState(false);
  const [direction, setDirection] = useState<ExpandCollapseIconProps["direction"]>("down");
  const [size, setSize] = useState(16);
  const [strokeWidth, setStrokeWidth] = useState(2);

  return (
    <ComponentDocPage
      title="Expand collapse icon"
      description="Chevron-with-bar icon for panel expand/collapse affordances. Rotates for bottom-anchored surfaces."
    >
      <DocSection
        title="Default"
        description="Collapsed state, direction down, 16px."
      >
        <PreviewCanvas minHeight={120}>
          <ExpandCollapseIcon expanded={false} />
        </PreviewCanvas>
      </DocSection>

      <DocSection
        title="Customization"
        description="Toggle expanded state, direction, size, and stroke width."
      >
        <div className="uitest-controls">
          <label className="uitest-field uitest-field--checkbox">
            <input
              type="checkbox"
              checked={expanded}
              onChange={(e) => setExpanded(e.target.checked)}
            />
            <span className="uitest-field__label">Expanded</span>
          </label>
          <label className="uitest-field">
            <span className="uitest-field__label">Direction</span>
            <select
              className="uitest-input"
              value={direction}
              onChange={(e) =>
                setDirection(e.target.value as ExpandCollapseIconProps["direction"])
              }
            >
              <option value="down">Down</option>
              <option value="up">Up</option>
            </select>
          </label>
          <label className="uitest-field">
            <span className="uitest-field__label">Size ({size}px)</span>
            <input
              className="uitest-input"
              type="range"
              min={12}
              max={32}
              step={2}
              value={size}
              onChange={(e) => setSize(Number(e.target.value))}
            />
          </label>
          <label className="uitest-field">
            <span className="uitest-field__label">Stroke width ({strokeWidth})</span>
            <input
              className="uitest-input"
              type="range"
              min={1}
              max={4}
              step={0.5}
              value={strokeWidth}
              onChange={(e) => setStrokeWidth(Number(e.target.value))}
            />
          </label>
        </div>
        <PreviewCanvas minHeight={120}>
          <ExpandCollapseIcon
            expanded={expanded}
            direction={direction}
            size={size}
            strokeWidth={strokeWidth}
          />
        </PreviewCanvas>
      </DocSection>

      <DocSection
        title="Expanded vs collapsed"
        description="Chevron points down when collapsed; up with horizontal bar when expanded."
      >
        <VariantGrid columns={2}>
          <VariantTile label="Collapsed">
            <ExpandCollapseIcon expanded={false} size={20} />
          </VariantTile>
          <VariantTile label="Expanded">
            <ExpandCollapseIcon expanded size={20} />
          </VariantTile>
        </VariantGrid>
      </DocSection>

      <DocSection
        title="Direction"
        description="Rotate 180° for bottom-anchored panels such as Agent Console."
      >
        <VariantGrid columns={2}>
          <VariantTile label="Direction down">
            <ExpandCollapseIcon expanded={false} direction="down" size={20} />
          </VariantTile>
          <VariantTile label="Direction up">
            <ExpandCollapseIcon expanded={false} direction="up" size={20} />
          </VariantTile>
        </VariantGrid>
      </DocSection>

      <DocSection title="Sizes" description="Common icon sizes in px.">
        <VariantGrid columns={4}>
          {SIZES.map((iconSize) => (
            <VariantTile key={iconSize} label={`${iconSize}px`}>
              <ExpandCollapseIcon expanded={false} size={iconSize} />
            </VariantTile>
          ))}
        </VariantGrid>
      </DocSection>

      <DocSection title="Stroke width" description="Stroke weight variants.">
        <VariantGrid columns={3}>
          {STROKE_WIDTHS.map((weight) => (
            <VariantTile key={weight} label={`${weight}px stroke`}>
              <ExpandCollapseIcon expanded={false} size={20} strokeWidth={weight} />
            </VariantTile>
          ))}
        </VariantGrid>
      </DocSection>
    </ComponentDocPage>
  );
}
