/**
 * Binance Spot kline types.
 * REST: https://developers.binance.com/docs/binance-spot-api-docs/rest-api/market-data-endpoints#klinecandlestick-data
 * WS:   https://developers.binance.com/docs/binance-spot-api-docs/web-socket-streams
 */

/** REST kline row: [openTime, open, high, low, close, volume, closeTime, ...] */
export type BinanceKlineRow = [
  number, // openTime (ms)
  string, // open
  string, // high
  string, // low
  string, // close
  string, // volume
  number, // closeTime (ms)
  ...unknown[],
];

export interface BinanceWsKlinePayload {
  e: "kline";
  E: number;
  s: string;
  k: BinanceWsKline;
}

export interface BinanceWsKline {
  t: number; // open time (ms)
  T: number; // close time (ms)
  s: string;
  i: string; // interval
  o: string;
  c: string;
  h: string;
  l: string;
  v: string;
  n: number;
  x: boolean; // is closed
  q: string;
  V: string;
  Q: string;
}

export interface BinanceClientConfig {
  /** Default "/api/binance" in browser (Vite proxy); override for server-side or custom gateway. */
  restBaseUrl?: string;
}

export const BINANCE_SPOT_REST_DEFAULT = "https://api.binance.com";
export const BINANCE_SPOT_WS_BASE = "wss://stream.binance.com:9443/ws";
