export type VaultListLayoutMode = "classic" | "tablet";

export interface VaultListPrefs {
  layout: VaultListLayoutMode;
  /** Set when the user picks a layout in Settings; absent for legacy/auto-saved prefs. */
  explicitChoice?: boolean;
}

export const DEFAULT_VAULT_LIST_PREFS: VaultListPrefs = {
  layout: "classic",
};

export function normalizeVaultListPrefs(
  prefs: Partial<VaultListPrefs> | null | undefined,
): VaultListPrefs {
  const layout =
    prefs?.layout === "tablet" ? "tablet" : DEFAULT_VAULT_LIST_PREFS.layout;
  return {
    layout,
    ...(prefs?.explicitChoice ? { explicitChoice: true } : {}),
  };
}

/** Classic unless the user explicitly chose tablet in Settings. */
export function resolveVaultListLayoutMode(
  prefs: Partial<VaultListPrefs> | null | undefined,
): VaultListLayoutMode {
  const normalized = normalizeVaultListPrefs(prefs);
  if (normalized.layout === "tablet" && normalized.explicitChoice) {
    return "tablet";
  }
  return "classic";
}
