import { create } from "zustand";

import { mockHashId } from "../../offline/mock_data";
import { normalizeAgentDidInput } from "../../offline/mock_data/agentIdentity";
import type {
  CopyRelation,
  CopyRiskLevel,
  CopySettings,
} from "../../offline/mock_data/fleetCopyRelations";
import {
  copyRiskLevelToAutonomyPreset,
  fleetCopyStorageKey,
} from "../../offline/mock_data/fleetCopyRelations";

type FleetCopyStoreState = {
  copierWallet: string | null;
  relations: CopyRelation[];
  hydrated: boolean;
  hydrate: (copierWallet: string | null) => void;
  addCopyRelation: (
    copierWallet: string,
    targetAgentDid: string,
    copySettings: Omit<CopySettings, "startedAt"> & { startedAt?: string },
  ) => CopyRelation;
  removeCopyRelation: (relationId: string) => void;
  hasActiveCopy: (targetAgentDid: string) => boolean;
  getRelationForAgent: (targetAgentDid: string) => CopyRelation | undefined;
};

function isCopyRiskLevel(value: unknown): value is CopyRiskLevel {
  return value === "low" || value === "medium" || value === "high";
}

function migrateCopySettings(raw: unknown): CopySettings | null {
  if (!raw || typeof raw !== "object") return null;
  const record = raw as Record<string, unknown>;
  const startedAt =
    typeof record.startedAt === "string"
      ? record.startedAt
      : new Date().toISOString();

  if (typeof record.copySizePct === "number") {
    const preset =
      record.autonomyPreset === "highAgency" ? "highAgency" : "guarded";
    return {
      bucketId: typeof record.bucketId === "string" ? record.bucketId : "",
      bucketMode: record.bucketMode === "existing" ? "existing" : "new",
      startingMargin:
        typeof record.startingMargin === "number"
          ? record.startingMargin
          : undefined,
      copySizePct: record.copySizePct,
      autonomyPreset: preset,
      startedAt,
    };
  }

  if (typeof record.sizePct === "number") {
    const riskLevel = isCopyRiskLevel(record.riskLevel) ? record.riskLevel : "medium";
    return {
      bucketId: "",
      bucketMode: "new",
      copySizePct: record.sizePct,
      autonomyPreset: copyRiskLevelToAutonomyPreset(riskLevel),
      startedAt,
    };
  }

  return null;
}

function migrateTargetAgentDid(record: Record<string, unknown>): string | null {
  const raw =
    typeof record.targetAgentDid === "string"
      ? record.targetAgentDid
      : typeof record.targetAgentDid === "string"
        ? record.targetAgentDid
        : null;
  if (!raw?.trim()) return null;
  return normalizeAgentDidInput(raw);
}

function migrateRelation(raw: unknown): CopyRelation | null {
  if (!raw || typeof raw !== "object") return null;
  const record = raw as Record<string, unknown>;
  if (typeof record.id !== "string" || typeof record.copierWallet !== "string") {
    return null;
  }
  const targetAgentDid = migrateTargetAgentDid(record);
  if (!targetAgentDid) return null;
  const copySettings = migrateCopySettings(record.copySettings);
  if (!copySettings) return null;
  return {
    id: record.id,
    copierWallet: record.copierWallet,
    targetAgentDid,
    copySettings,
  };
}

function loadRelations(copierWallet: string): CopyRelation[] {
  if (typeof window === "undefined") return [];
  try {
    const raw = window.localStorage.getItem(fleetCopyStorageKey(copierWallet));
    if (!raw) return [];
    const parsed = JSON.parse(raw) as unknown[];
    if (!Array.isArray(parsed)) return [];
    return parsed
      .map((entry) => migrateRelation(entry))
      .filter((relation): relation is CopyRelation => relation !== null);
  } catch {
    return [];
  }
}

function persistRelations(copierWallet: string, relations: CopyRelation[]): void {
  if (typeof window === "undefined") return;
  window.localStorage.setItem(
    fleetCopyStorageKey(copierWallet),
    JSON.stringify(relations),
  );
}

function normalizeDidForCompare(did: string): string {
  return normalizeAgentDidInput(did).toLowerCase();
}

export const useFleetCopyStore = create<FleetCopyStoreState>((set, get) => ({
  copierWallet: null,
  relations: [],
  hydrated: false,

  hydrate: (copierWallet) => {
    const normalized = copierWallet?.trim().toLowerCase() ?? null;
    if (!normalized) {
      set({ copierWallet: null, relations: [], hydrated: true });
      return;
    }
    set({
      copierWallet: normalized,
      relations: loadRelations(normalized),
      hydrated: true,
    });
  },

  addCopyRelation: (copierWallet, targetAgentDid, copySettings) => {
    const normalizedWallet = copierWallet.trim().toLowerCase();
    const normalizedAgent = normalizeAgentDidInput(targetAgentDid);
    const existing = get().relations.find(
      (relation) =>
        normalizeDidForCompare(relation.targetAgentDid)
          === normalizeDidForCompare(normalizedAgent),
    );

    const settings: CopySettings = {
      ...copySettings,
      startedAt: copySettings.startedAt ?? new Date().toISOString(),
    };

    const nextRelation: CopyRelation = existing
      ? {
          ...existing,
          targetAgentDid: normalizedAgent,
          copySettings: settings,
        }
      : {
          id: mockHashId(
            `fleet:copy:${normalizedWallet}:${normalizeDidForCompare(normalizedAgent)}`,
          ),
          copierWallet: normalizedWallet,
          targetAgentDid: normalizedAgent,
          copySettings: settings,
        };

    const withoutDup = get().relations.filter(
      (relation) =>
        normalizeDidForCompare(relation.targetAgentDid)
          !== normalizeDidForCompare(normalizedAgent),
    );
    const relations = [...withoutDup, nextRelation];
    persistRelations(normalizedWallet, relations);
    set({ copierWallet: normalizedWallet, relations, hydrated: true });
    return nextRelation;
  },

  removeCopyRelation: (relationId) => {
    const { copierWallet, relations } = get();
    if (!copierWallet) return;
    const next = relations.filter((relation) => relation.id !== relationId);
    persistRelations(copierWallet, next);
    set({ relations: next });
  },

  hasActiveCopy: (targetAgentDid) => {
    const normalized = normalizeDidForCompare(targetAgentDid);
    return get().relations.some(
      (relation) =>
        normalizeDidForCompare(relation.targetAgentDid) === normalized,
    );
  },

  getRelationForAgent: (targetAgentDid) => {
    const normalized = normalizeDidForCompare(targetAgentDid);
    return get().relations.find(
      (relation) =>
        normalizeDidForCompare(relation.targetAgentDid) === normalized,
    );
  },
}));
