import React, { type JSX } from "react";
import { OrderbookLevel } from "../../sdk/types/data";

/** Level may include display-only flags (e.g. isPending from enhancement layer). */
export type OrderbookLevelFragmentLevel = OrderbookLevel & { isPending?: boolean };

interface OrderbookLevelFragmentProps {
  level: OrderbookLevelFragmentLevel;
  index: number;
  isLast: boolean;
  depthPercent: number;
  formatPrice: (price: number) => string;
  formatSize: (size: number) => string;
  onPriceClick?: (price: number) => void;
  /** When set, shows a total column instead of the depth indicator bar. */
  displayTotal?: number;
  /** When false, suppresses flash highlight on size changes. Defaults to true. */
  animationEnabled?: boolean;
  onRowHover?: (index: number, el: HTMLElement) => void;
  onRowLeave?: () => void;
  isHovered?: boolean;
}

function resolveFlashClass(
  flash: OrderbookLevel["flash"],
  side: "ask" | "bid",
  animationEnabled: boolean,
): string {
  if (!animationEnabled || !flash) return "";
  if (flash === "up") return "flash-up";
  return side === "ask" ? "flash-down-ask" : "flash-down-bid";
}

function DepthBar({
  side,
  depthPercent,
}: {
  side: "ask" | "bid";
  depthPercent: number;
}): JSX.Element {
  return (
    <div
      className={`orderbook-depth-bar ${side}`}
      style={{ width: `${depthPercent}%` }}
    />
  );
}

function PriceCell({
  side,
  price,
  formattedPrice,
  onPriceClick,
}: {
  side: "ask" | "bid";
  price: number;
  formattedPrice: string;
  onPriceClick?: (price: number) => void;
}): JSX.Element {
  const handlePriceClick = () => {
    if (onPriceClick) onPriceClick(price);
  };

  return (
    <div
      className={`orderbook-level-content ${side}`}
      onClick={handlePriceClick}
      style={{ cursor: onPriceClick ? "pointer" : "default" }}
    >
      {formattedPrice}
    </div>
  );
}

export const AskLevelFragment: React.FC<OrderbookLevelFragmentProps> = ({
  level,
  index,
  isLast,
  depthPercent,
  formatPrice,
  formatSize,
  onPriceClick,
  displayTotal,
  animationEnabled = true,
  onRowHover,
  onRowLeave,
  isHovered = false,
}) => {
  const flashClass = resolveFlashClass(level.flash, "ask", animationEnabled);
  const pendingClass = level.isPending ? " pending" : "";
  const hoveredClass = isHovered ? " is-depth-hovered" : "";

  return (
    <div
      className={`orderbook-level ask${displayTotal != null ? " with-total" : ""}${pendingClass}${hoveredClass} ${flashClass}`}
      style={{
        borderBottom: isLast ? "none" : undefined,
      }}
      onMouseEnter={(e) => onRowHover?.(index, e.currentTarget)}
      onMouseLeave={() => onRowLeave?.()}
    >
      <DepthBar side="ask" depthPercent={depthPercent} />
      <PriceCell
        side="ask"
        price={level.price}
        formattedPrice={formatPrice(level.price)}
        onPriceClick={onPriceClick}
      />
      <div className="orderbook-level-content right">
        {formatSize(level.size)}
      </div>
      {displayTotal != null ? (
        <div className="orderbook-level-content right">
          {formatSize(displayTotal)}
        </div>
      ) : (
        <div className="orderbook-depth-indicator">
          <div className="orderbook-depth-line ask" />
        </div>
      )}
    </div>
  );
};

