import type { MockRawTrade } from "./demoData";
import { mockHashId } from "./mockHashId";
import {
  getMockOrderbookMid,
  getMockOrderbookSequenceId,
} from "./mockOrderbookEngine";
import { nextTradeDelayMs } from "../util/skewedRandom";
import { resolveBinanceKlineSymbol } from "../../mormv1/components/tradingview/symbols";
import {
  acquireBinanceReferencePrice,
  getBinanceReferencePrice,
  releaseBinanceReferencePrice,
  subscribeBinanceReferencePrice,
} from "./binanceReferencePrice";

const MOCK_WALLET_ADDRESS = "0x9f2a9e1f4a9b8c7d6e5f1234567890abcdef1234";

const SATOSHI = 100_000_000;
const MAX_TRADE_HISTORY = 100;

type TradeMeta = {
  isBuyerMaker: boolean;
};

type MarketTradeState = {
  trades: MockRawTrade[];
  metaByTradeId: Map<string, TradeMeta>;
  sequence: number;
  rng: () => number;
};

type ActiveGenerator = {
  marketId: string;
  baseAsset: string;
  timerId: ReturnType<typeof setTimeout> | null;
  unsubPrice: (() => void) | null;
  seeded: boolean;
};

const tradeStates = new Map<string, MarketTradeState>();
const tradeListeners = new Set<(marketId: string) => void>();
let activeGenerator: ActiveGenerator | null = null;

function hashSeed(value: string): number {
  let hash = 0;
  for (let i = 0; i < value.length; i += 1) {
    hash = (hash * 31 + value.charCodeAt(i)) | 0;
  }
  return Math.abs(hash) || 1;
}

function mulberry32(seed: number): () => number {
  let state = seed;
  return () => {
    state |= 0;
    state = (state + 0x6d2b79f5) | 0;
    let t = Math.imul(state ^ (state >>> 15), 1 | state);
    t = (t + Math.imul(t ^ (t >>> 7), 61 | t)) ^ t;
    return ((t ^ (t >>> 14)) >>> 0) / 4294967296;
  };
}

function decimalToSatoshiString(value: number): string {
  return String(Math.round(value * SATOSHI));
}

function mockTradePriceStep(price: number): number {
  if (price < 1) return 0.0001;
  if (price < 100) return 0.05;
  if (price < 1000) return 1;
  return 20;
}

function roundToTick(price: number, tick: number): number {
  const decimals = tick < 0.0001 ? 8 : tick < 0.01 ? 6 : tick < 1 ? 4 : 2;
  return Number((Math.round(price / tick) * tick).toFixed(decimals));
}

function baseSizeForPrice(price: number): number {
  if (price >= 10_000) return 0.15;
  if (price >= 1_000) return 0.4;
  if (price >= 100) return 1.2;
  if (price >= 1) return 8;
  return 500;
}

function roundSize(size: number): number {
  return Number(Math.max(0.0001, size).toFixed(4));
}

function ensureTradeState(marketId: string): MarketTradeState {
  const existing = tradeStates.get(marketId);
  if (existing) return existing;

  const state: MarketTradeState = {
    trades: [],
    metaByTradeId: new Map(),
    sequence: 0,
    rng: mulberry32(hashSeed(`trades:${marketId}`)),
  };
  tradeStates.set(marketId, state);
  return state;
}

function notifyTradeListeners(marketId: string): void {
  tradeListeners.forEach((listener) => listener(marketId));
}

function appendTrade(
  marketId: string,
  price: number,
  size: number,
  isBuyerMaker: boolean,
  timestamp: number,
): MockRawTrade {
  const state = ensureTradeState(marketId);
  state.sequence += 1;
  const tradeId = `${marketId}-mock-t${state.sequence}`;
  const trade: MockRawTrade = {
    tradeId,
    buyOrderId: mockHashId(`mock:trade:${marketId}:buy:${state.sequence}`),
    sellOrderId: mockHashId(`mock:trade:${marketId}:sell:${state.sequence}`),
    price: decimalToSatoshiString(price),
    quantity: decimalToSatoshiString(size),
    timestamp: String(timestamp),
    marketIndex: marketId,
    makerFee: "0",
    takerFee: "0",
    dualWriteId: "",
    sequenceId: getMockOrderbookSequenceId(marketId),
    tradeType: state.sequence === 1 ? "INITIAL" : "FILL",
    buyAddress: isBuyerMaker
      ? "0x0000000000000000000000000000000000000002"
      : MOCK_WALLET_ADDRESS,
    sellAddress: isBuyerMaker
      ? MOCK_WALLET_ADDRESS
      : "0x0000000000000000000000000000000000000001",
  };
  state.trades.push(trade);
  state.metaByTradeId.set(tradeId, { isBuyerMaker });
  if (state.trades.length > MAX_TRADE_HISTORY) {
    const removed = state.trades.shift();
    if (removed) state.metaByTradeId.delete(removed.tradeId);
  }
  return trade;
}

function seedTradesAtPrice(marketId: string, mid: number): MockRawTrade[] {
  const state = ensureTradeState(marketId);
  if (state.trades.length > 0) {
    return state.trades.map((trade) => ({ ...trade }));
  }

  const tick = mockTradePriceStep(mid);
  const now = Date.now();
  const count = 8 + Math.floor(state.rng() * 5);

  for (let i = 0; i < count; i += 1) {
    const offset = Math.round((state.rng() * 6 - 3)) * tick;
    const price = roundToTick(Math.max(tick, mid + offset), tick);
    const size = roundSize(baseSizeForPrice(mid) * (0.5 + state.rng() * 0.8));
    const isBuyerMaker = state.rng() < 0.5;
    appendTrade(marketId, price, size, isBuyerMaker, now - (count - i) * 2500);
  }

  return state.trades.map((trade) => ({ ...trade }));
}

function generateAnchoredTrade(
  marketId: string,
  baseAsset: string,
): MockRawTrade | null {
  const refPrice = getBinanceReferencePrice(baseAsset);
  if (refPrice == null || refPrice <= 0) return null;

  const state = ensureTradeState(marketId);
  const tick = mockTradePriceStep(refPrice);
  const offsetSteps = Math.round(state.rng() * 5 - 2);
  const price = roundToTick(Math.max(tick, refPrice + offsetSteps * tick), tick);
  const size = roundSize(baseSizeForPrice(refPrice) * (0.65 + state.rng() * 0.7));
  const isBuyerMaker = state.rng() < 0.5;
  const trade = appendTrade(marketId, price, size, isBuyerMaker, Date.now());
  notifyTradeListeners(marketId);
  return trade;
}

function clearGeneratorTimer(generator: ActiveGenerator): void {
  if (generator.timerId !== null) {
    clearTimeout(generator.timerId);
    generator.timerId = null;
  }
}

function scheduleNextTrade(generator: ActiveGenerator): void {
  clearGeneratorTimer(generator);
  generator.timerId = setTimeout(() => {
    if (activeGenerator !== generator) return;
    generateAnchoredTrade(generator.marketId, generator.baseAsset);
    scheduleNextTrade(generator);
  }, nextTradeDelayMs(0.4,12,8.1));
}

function trySeedFromReference(generator: ActiveGenerator): void {
  if (generator.seeded) return;
  const refPrice = getBinanceReferencePrice(generator.baseAsset);
  if (refPrice == null || refPrice <= 0) return;

  seedTradesAtPrice(generator.marketId, refPrice);
  generator.seeded = true;
  notifyTradeListeners(generator.marketId);
}

function stopActiveGenerator(marketId?: string): void {
  if (!activeGenerator) return;
  if (marketId && activeGenerator.marketId !== marketId) return;

  clearGeneratorTimer(activeGenerator);
  activeGenerator.unsubPrice?.();
  releaseBinanceReferencePrice(activeGenerator.baseAsset);
  activeGenerator = null;
}

export function resetMockTrades(marketId: string): void {
  tradeStates.delete(marketId);
}

export function seedMockTrades(marketId: string, anchorPrice?: number): MockRawTrade[] {
  const mid = anchorPrice ?? getMockOrderbookMid(marketId);
  return seedTradesAtPrice(marketId, mid);
}

export function generateMockTradeOnMidShift(marketId: string): MockRawTrade | null {
  const mid = getMockOrderbookMid(marketId);
  if (mid <= 0) return null;

  const state = ensureTradeState(marketId);
  const size = roundSize(baseSizeForPrice(mid) * (0.65 + state.rng() * 0.7));
  const isBuyerMaker = state.rng() < 0.5;
  const trade = appendTrade(marketId, mid, size, isBuyerMaker, Date.now());
  notifyTradeListeners(marketId);
  return trade;
}

export function startBinanceAnchoredTradeGenerator(
  marketId: string,
  baseAsset: string,
): () => void {
  if (!resolveBinanceKlineSymbol(baseAsset)) {
    return () => {};
  }

  stopActiveGenerator();

  const acquired = acquireBinanceReferencePrice(baseAsset);
  if (!acquired) {
    return () => {};
  }

  const generator: ActiveGenerator = {
    marketId,
    baseAsset,
    timerId: null,
    unsubPrice: null,
    seeded: false,
  };
  activeGenerator = generator;

  const onPriceUpdate = () => {
    if (activeGenerator !== generator) return;
    trySeedFromReference(generator);
  };

  generator.unsubPrice = subscribeBinanceReferencePrice(baseAsset, onPriceUpdate);
  trySeedFromReference(generator);
  scheduleNextTrade(generator);

  return () => stopActiveGenerator(marketId);
}

export function stopBinanceAnchoredTradeGenerator(marketId?: string): void {
  stopActiveGenerator(marketId);
}

export function getMockRawTrades(marketId: string): MockRawTrade[] {
  const state = tradeStates.get(marketId);
  if (!state || state.trades.length === 0) {
    return seedMockTrades(marketId);
  }
  return state.trades.map((trade) => ({ ...trade }));
}

export function getMockTradeIsBuyerMaker(
  marketId: string,
  tradeId: string,
): boolean | undefined {
  return tradeStates.get(marketId)?.metaByTradeId.get(tradeId)?.isBuyerMaker;
}

export function subscribeMockTrades(
  listener: (marketId: string) => void,
): () => void {
  tradeListeners.add(listener);
  return () => tradeListeners.delete(listener);
}

/** Test-only: expose active generator market id. */
export function getActiveBinanceTradeGeneratorMarketIdForTest(): string | null {
  return activeGenerator?.marketId ?? null;
}
