import type { ReactNode } from "react";

export interface PreviewCanvasProps {
  children: ReactNode;
  className?: string;
  minHeight?: number;
}

export function PreviewCanvas({
  children,
  className,
  minHeight = 220,
}: PreviewCanvasProps): JSX.Element {
  const canvasClassName = ["uitest-preview-canvas", className]
    .filter(Boolean)
    .join(" ");

  return (
    <div className={canvasClassName} style={{ minHeight }}>
      {children}
    </div>
  );
}
