import type {
  AgentTask,
  AgentTaskGuardrailMeta,
  AgentTaskGuardrailRiskImpact,
} from "../../store/types";

export type RequiredGuardrailMeta = Required<AgentTaskGuardrailMeta>;

const RISK_IMPACTS: AgentTaskGuardrailRiskImpact[] = [
  "low",
  "moderate",
  "high",
];

function hashSeed(input: string): number {
  let h = 2166136261;
  for (let i = 0; i < input.length; i++) {
    h ^= input.charCodeAt(i);
    h = Math.imul(h, 16777619);
  }
  return h >>> 0;
}

export function deriveGuardrailMeta(
  task: Pick<AgentTask, "id" | "agentId">,
): RequiredGuardrailMeta {
  const seed = hashSeed(`${task.id}:${task.agentId}`);
  const confidencePct = 55 + (seed % 41);
  const riskImpact = RISK_IMPACTS[seed % RISK_IMPACTS.length] ?? "moderate";
  const expectedFillImpactBps = Number(
    (((seed >> 8) % 80) / 10 + 0.5).toFixed(1),
  );
  const simulationNote =
    riskImpact === "high"
      ? "Approving may increase cross-market exposure."
      : riskImpact === "moderate"
        ? "Moderate fill impact on active book depth."
        : "Low slippage expected at current size.";

  return {
    confidencePct,
    riskImpact,
    expectedFillImpactBps,
    simulationNote,
  };
}

export function getGuardrailMeta(task: AgentTask): RequiredGuardrailMeta {
  const derived = deriveGuardrailMeta(task);
  const g = task.guardrail;
  return {
    confidencePct: g?.confidencePct ?? derived.confidencePct,
    riskImpact: g?.riskImpact ?? derived.riskImpact,
    expectedFillImpactBps:
      g?.expectedFillImpactBps ?? derived.expectedFillImpactBps,
    simulationNote: g?.simulationNote ?? derived.simulationNote,
  };
}

const RISK_SORT: Record<AgentTaskGuardrailRiskImpact, number> = {
  high: 0,
  moderate: 1,
  low: 2,
};

export function compareGuardrailRisk(
  a: AgentTask,
  b: AgentTask,
): number {
  const metaA = getGuardrailMeta(a);
  const metaB = getGuardrailMeta(b);
  const riskDiff = RISK_SORT[metaA.riskImpact] - RISK_SORT[metaB.riskImpact];
  if (riskDiff !== 0) return riskDiff;
  return metaB.confidencePct - metaA.confidencePct;
}

export function riskImpactLabel(
  impact: AgentTaskGuardrailRiskImpact,
): string {
  switch (impact) {
    case "low":
      return "Low";
    case "moderate":
      return "Moderate";
    case "high":
      return "High";
  }
}
