import React, {
  createContext,
  useCallback,
  useContext,
  useEffect,
  useMemo,
  useRef,
  useState,
  type ReactNode,
} from "react";
import {
  DEFAULT_JELLY_DEMO_CONFIG,
  JELLY_ANCHOR_INDEX,
  JELLY_EVENT_DATE,
  JELLY_MARKET_INDEX,
  JELLY_PLACEHOLDER_ROW,
  ensureJellyBundleLoaded,
  getJellyReplayRange,
  getJellyRow,
  setJellyModeActive,
  resetJellyReplayFrameIndex,
  resetJellyTradeHistory,
  setJellyReplayFrameIndex,
  clearJellyOrderbookCache,
  type JellyDemoConfig,
  type JellyRow,
} from "../../offline/mock_data/jellyevent";

export type JellyReplayPhase = "intro" | "replaying" | "finished";

export type { JellyDemoConfig };

/** ~26h replay at 1 frame/minute finishes in ~10.5 minutes. */
const REPLAY_FRAME_MS = 400;

export type JellyModeContextValue = {
  isJellyMode: boolean;
  /** Heavy jelly datasets finished loading (separate chunk). */
  jellyBundleReady: boolean;
  enterJellyMode: () => void;
  toggleJellyMode: () => void;
  showIntroModal: boolean;
  openIntroModal: () => void;
  replayPhase: JellyReplayPhase;
  frameIndex: number;
  demoConfig: JellyDemoConfig;
  eventDate: typeof JELLY_EVENT_DATE;
  currentRow: JellyRow;
  startReplay: (config: JellyDemoConfig) => void;
  dismissIntroAndStart: () => void;
  registerMarketSelector: (
    selectMarket: (marketId: string) => void,
    getSelectedMarketId: () => string,
  ) => void;
};

const JellyModeContext = createContext<JellyModeContextValue | undefined>(undefined);

export interface JellyModeProviderProps {
  children: ReactNode;
}

export function JellyModeProvider({ children }: JellyModeProviderProps): JSX.Element {
  const anchorIndex = JELLY_ANCHOR_INDEX;

  const [isJellyMode, setIsJellyMode] = useState(() => {
    if (typeof window === "undefined") return false;
    return sessionStorage.getItem("jelly_mode_active") === "1";
  });
  const [jellyBundleReady, setJellyBundleReady] = useState(false);
  const [showIntroModal, setShowIntroModal] = useState(false);
  const [replayPhase, setReplayPhase] = useState<JellyReplayPhase>("intro");
  const [frameIndex, setFrameIndex] = useState(anchorIndex);
  const [demoConfig, setDemoConfig] = useState<JellyDemoConfig>(DEFAULT_JELLY_DEMO_CONFIG);

  const selectMarketRef = useRef<((marketId: string) => void) | null>(null);
  const getSelectedMarketRef = useRef<(() => string) | null>(null);
  const previousMarketIdRef = useRef<string | null>(null);
  const replayTimerRef = useRef<ReturnType<typeof setInterval> | null>(null);

  const currentRow =
    jellyBundleReady
      ? (getJellyRow(frameIndex) ?? JELLY_PLACEHOLDER_ROW)
      : JELLY_PLACEHOLDER_ROW;

  useEffect(() => {
    if (!isJellyMode) {
      setJellyBundleReady(false);
      return;
    }
    let cancelled = false;
    void ensureJellyBundleLoaded().then(() => {
      if (!cancelled) setJellyBundleReady(true);
    });
    return () => {
      cancelled = true;
    };
  }, [isJellyMode]);

  const stopReplayTimer = useCallback(() => {
    if (replayTimerRef.current) {
      clearInterval(replayTimerRef.current);
      replayTimerRef.current = null;
    }
  }, []);

  const resetJellySession = useCallback(() => {
    stopReplayTimer();
    setShowIntroModal(false);
    setReplayPhase("intro");
    setFrameIndex(anchorIndex);
    setDemoConfig(DEFAULT_JELLY_DEMO_CONFIG);
    resetJellyReplayFrameIndex();
    resetJellyTradeHistory();
    clearJellyOrderbookCache();
  }, [anchorIndex, stopReplayTimer]);

  const startReplay = useCallback(
    (config: JellyDemoConfig) => {
      stopReplayTimer();
      resetJellyTradeHistory();
      clearJellyOrderbookCache();
      setDemoConfig(config);
      setShowIntroModal(false);
      setReplayPhase("replaying");
      setFrameIndex(anchorIndex);
      setJellyReplayFrameIndex(anchorIndex);

      const [, lastIndex] = getJellyReplayRange();
      let nextFrame = anchorIndex;

      replayTimerRef.current = setInterval(() => {
        nextFrame += 1;
        if (nextFrame > lastIndex) {
          setFrameIndex(lastIndex);
          setJellyReplayFrameIndex(lastIndex);
          setReplayPhase("finished");
          stopReplayTimer();
          return;
        }
        setFrameIndex(nextFrame);
        setJellyReplayFrameIndex(nextFrame);
      }, REPLAY_FRAME_MS);
    },
    [anchorIndex, stopReplayTimer],
  );

  const dismissIntroAndStart = useCallback(() => {
    startReplay(DEFAULT_JELLY_DEMO_CONFIG);
  }, [startReplay]);

  const openIntroModal = useCallback(() => {
    setShowIntroModal(true);
  }, []);

  useEffect(() => {
    setJellyReplayFrameIndex(frameIndex);
  }, [frameIndex]);

  useEffect(() => {
    setJellyModeActive(isJellyMode);
  }, [isJellyMode]);

  useEffect(() => () => stopReplayTimer(), [stopReplayTimer]);

  const registerMarketSelector = useCallback(
    (
      selectMarket: (marketId: string) => void,
      getSelectedMarketId: () => string,
    ) => {
      selectMarketRef.current = selectMarket;
      getSelectedMarketRef.current = getSelectedMarketId;
    },
    [],
  );

  const isJellyModeRef = useRef(isJellyMode);
  isJellyModeRef.current = isJellyMode;

  const activateJellyMode = useCallback(() => {
    if (isJellyModeRef.current) return;
    setJellyModeActive(true);
    const current = getSelectedMarketRef.current?.() ?? "";
    if (current && current !== JELLY_MARKET_INDEX) {
      previousMarketIdRef.current = current;
    }
    selectMarketRef.current?.(JELLY_MARKET_INDEX);
    setFrameIndex(anchorIndex);
    setJellyReplayFrameIndex(anchorIndex);
    resetJellyTradeHistory();
    setReplayPhase("intro");
    setDemoConfig(DEFAULT_JELLY_DEMO_CONFIG);
    setShowIntroModal(true);
    setIsJellyMode(true);
  }, [anchorIndex]);

  const enterJellyMode = useCallback(() => {
    activateJellyMode();
  }, [activateJellyMode]);

  const toggleJellyMode = useCallback(() => {
    if (isJellyModeRef.current) {
      setJellyModeActive(false);
      resetJellySession();
      const restore = previousMarketIdRef.current;
      if (restore) {
        selectMarketRef.current?.(restore);
      }
      previousMarketIdRef.current = null;
      setIsJellyMode(false);
      return;
    }
    activateJellyMode();
  }, [activateJellyMode, resetJellySession]);

  const value = useMemo<JellyModeContextValue>(
    () => ({
      isJellyMode,
      jellyBundleReady,
      enterJellyMode,
      toggleJellyMode,
      showIntroModal,
      openIntroModal,
      replayPhase,
      frameIndex,
      demoConfig,
      eventDate: JELLY_EVENT_DATE,
      currentRow,
      startReplay,
      dismissIntroAndStart,
      registerMarketSelector,
    }),
    [
      isJellyMode,
      jellyBundleReady,
      enterJellyMode,
      toggleJellyMode,
      showIntroModal,
      openIntroModal,
      replayPhase,
      frameIndex,
      demoConfig,
      currentRow,
      startReplay,
      dismissIntroAndStart,
      registerMarketSelector,
    ],
  );

  return <JellyModeContext.Provider value={value}>{children}</JellyModeContext.Provider>;
}

export function useJellyMode(): JellyModeContextValue {
  const ctx = useContext(JellyModeContext);
  if (!ctx) {
    throw new Error("useJellyMode must be used within JellyModeProvider");
  }
  return ctx;
}

export function useOptionalJellyMode(): JellyModeContextValue | null {
  return useContext(JellyModeContext) ?? null;
}
