export type GateIntentTimeoutAction = "approve" | "reject";

export interface GateIntentTimerPrefs {
  enabled: boolean;
  waitSeconds: number;
  onTimeout: GateIntentTimeoutAction;
}

export const GATE_INTENT_TIMER_MIN_SECONDS = 5;
export const GATE_INTENT_TIMER_MAX_SECONDS = 120;

export const DEFAULT_GATE_INTENT_TIMER_PREFS: GateIntentTimerPrefs = {
  enabled: false,
  waitSeconds: 15,
  onTimeout: "reject",
};

export function clampGateIntentWaitSeconds(seconds: number): number {
  return Math.min(
    GATE_INTENT_TIMER_MAX_SECONDS,
    Math.max(GATE_INTENT_TIMER_MIN_SECONDS, Math.round(seconds)),
  );
}

export function normalizeGateIntentTimerPrefs(
  parsed: Partial<GateIntentTimerPrefs> | undefined,
): GateIntentTimerPrefs {
  const defaults = DEFAULT_GATE_INTENT_TIMER_PREFS;
  if (!parsed) return defaults;

  return {
    enabled: typeof parsed.enabled === "boolean" ? parsed.enabled : defaults.enabled,
    waitSeconds:
      typeof parsed.waitSeconds === "number"
        ? clampGateIntentWaitSeconds(parsed.waitSeconds)
        : defaults.waitSeconds,
    onTimeout:
      parsed.onTimeout === "approve" || parsed.onTimeout === "reject"
        ? parsed.onTimeout
        : defaults.onTimeout,
  };
}
