import type { MenuBarNavItem } from "../vault/MenuBarVaultOperate";
import { APP_ROUTES } from "../../routes";

export type HeaderNavItemId =
  | "copytrade"
  | "trade"
  | "index"
  | "portfolio"
  | "vault"
  | "agents"
  | "staking";

export const HEADER_NAV_PINNED: HeaderNavItemId[] = ["trade"];

export const HEADER_NAV_OPTIONAL: HeaderNavItemId[] = [
  "copytrade",
  "index",
  "portfolio",
  "vault",
  "agents",
  "staking",
];

export const HEADER_NAV_CATALOG: Record<
  HeaderNavItemId,
  { label: string; href: string }
> = {
  copytrade: { label: "Copytrade", href: "/copytrade" },
  trade: { label: "Trade", href: "/trade" },
  index: { label: "Index", href: "/cindex" },
  portfolio: { label: "Portfolio", href: "/portfolio" },
  vault: { label: "Vault", href: "/vault" },
  agents: { label: "Agents", href: APP_ROUTES.myAgents },
  staking: { label: "Staking", href: "/staking" },
};

export const DEFAULT_HEADER_NAV_VISIBLE: HeaderNavItemId[] = [
  "copytrade",
  "trade",
  "index",
  "portfolio",
  "vault",
];

const ALL_NAV_IDS = new Set<string>([
  ...HEADER_NAV_PINNED,
  ...HEADER_NAV_OPTIONAL,
  "markets",
]);

const OPTIONAL_NAV_SET = new Set<string>(HEADER_NAV_OPTIONAL);

export interface HeaderNavPrefs {
  /** Ordered list of visible header nav item ids. Trade is always included. */
  visibleItems: HeaderNavItemId[];
}

export const DEFAULT_HEADER_NAV_PREFS: HeaderNavPrefs = {
  visibleItems: DEFAULT_HEADER_NAV_VISIBLE,
};

/** Filter to valid nav ids, dedupe, preserve order. */
export function sanitizeHeaderNavVisibleItems(
  input: unknown,
): HeaderNavItemId[] {
  if (!Array.isArray(input)) return [];

  const seen = new Set<string>();
  const sanitized: HeaderNavItemId[] = [];

  for (const item of input) {
    if (typeof item !== "string" || seen.has(item)) {
      continue;
    }
    const normalized = item === "markets" ? "copytrade" : item;
    if (!ALL_NAV_IDS.has(normalized)) {
      continue;
    }
    seen.add(normalized);
    sanitized.push(normalized as HeaderNavItemId);
  }

  return sanitized;
}

/** Load/migrate prefs: ensure trade is present; fall back to default when empty. */
export function normalizeHeaderNavVisibleItems(input: unknown): HeaderNavItemId[] {
  const sanitized = sanitizeHeaderNavVisibleItems(input);
  if (sanitized.length === 0) {
    return [...DEFAULT_HEADER_NAV_VISIBLE];
  }

  if (!sanitized.includes("trade")) {
    const tradeIndex = DEFAULT_HEADER_NAV_VISIBLE.indexOf("trade");
    const insertAt = Math.min(tradeIndex, sanitized.length);
    sanitized.splice(insertAt, 0, "trade");
  }

  return sanitized;
}

export function normalizeHeaderNavPrefs(
  input: Partial<HeaderNavPrefs> | undefined,
): HeaderNavPrefs {
  return {
    visibleItems: normalizeHeaderNavVisibleItems(input?.visibleItems),
  };
}

export function buildHeaderNavMenuItems(prefs: HeaderNavPrefs): MenuBarNavItem[] {
  const visible = normalizeHeaderNavVisibleItems(prefs.visibleItems);
  return visible.map((id) => {
    const entry = HEADER_NAV_CATALOG[id];
    return {
      label: entry.label,
      href: entry.href,
      id,
    };
  });
}

export function toggleHeaderNavItem(
  visibleItems: HeaderNavItemId[],
  itemId: HeaderNavItemId,
  enabled: boolean,
): HeaderNavItemId[] {
  if (itemId === "trade") return visibleItems;
  if (!OPTIONAL_NAV_SET.has(itemId)) return visibleItems;

  if (enabled) {
    if (visibleItems.includes(itemId)) return visibleItems;
    return [...visibleItems, itemId];
  }

  return visibleItems.filter((id) => id !== itemId);
}

export function moveHeaderNavItem(
  visibleItems: HeaderNavItemId[],
  itemId: HeaderNavItemId,
  direction: "up" | "down",
): HeaderNavItemId[] {
  const index = visibleItems.indexOf(itemId);
  if (index === -1) return visibleItems;

  const swapIndex = direction === "up" ? index - 1 : index + 1;
  if (swapIndex < 0 || swapIndex >= visibleItems.length) {
    return visibleItems;
  }

  const next = [...visibleItems];
  [next[index], next[swapIndex]] = [next[swapIndex]!, next[index]!];
  return next;
}

/** Visible items first (in order), then hidden optional items for the settings panel. */
export function getHeaderNavDisplayOrder(
  visibleItems: HeaderNavItemId[],
): HeaderNavItemId[] {
  const visible = normalizeHeaderNavVisibleItems(visibleItems);
  const hidden = HEADER_NAV_OPTIONAL.filter((id) => !visible.includes(id));
  return [...visible, ...hidden];
}
