import React, { useCallback, useMemo, useState } from "react";
import { Group } from "@visx/group";
import { ParentSize } from "@visx/responsive";
import { Pie, type PieArcDatum } from "@visx/shape";
import { TERMINAL_COLORS } from "../../constants/terminalColors";
import type { EquityBreakdownSegment } from "../../hooks/usePortfolioAnalytics";
import "./portfolio.css";

export type PortfolioEquityBreakdownChartLayout = "radial" | "stacked" | "inline";

export interface PortfolioEquityBreakdownChartProps {
  segments: EquityBreakdownSegment[];
  layout?: PortfolioEquityBreakdownChartLayout;
  title?: string;
  defaultCenterValue?: string;
  defaultCenterLabel?: string;
  maxLabeledSegments?: number;
  minLabelPct?: number;
  preserveSegments?: boolean;
  legendValueFormat?: "currency" | "percent";
  legendColumns?: number;
  hideCenterLabel?: boolean;
  /** When set, inline layout donut fills its box: radius = min(w,h)/2 − inset. */
  inlineDonutInset?: number;
}

const HIGHLIGHT_COLOR = TERMINAL_COLORS.brand;
const OTHER_COLOR = "#475569";
const DEFAULT_MIN_LABEL_PCT = 2.5;
const DEFAULT_MAX_LABELED_SEGMENTS = 8;

function formatPct(value: number): string {
  return `${value.toFixed(1)}%`;
}

function formatPctPrecise(value: number): string {
  return `${value.toFixed(2)}%`;
}

function formatCurrency(value: number): string {
  if (value >= 1_000_000) return `$${(value / 1_000_000).toFixed(2)}M`;
  if (value >= 1_000) return `$${(value / 1_000).toFixed(1)}k`;
  return `$${value.toFixed(2)}`;
}

function segmentClassName(...parts: Array<string | false | null | undefined>): string {
  return parts.filter(Boolean).join(" ");
}

function prepareChartSegments(
  segments: EquityBreakdownSegment[],
  maxLabeledSegments = DEFAULT_MAX_LABELED_SEGMENTS,
  minLabelPct = DEFAULT_MIN_LABEL_PCT,
): EquityBreakdownSegment[] {
  const positive = segments.filter((seg) => seg.value > 0);
  if (positive.length === 0) return [];

  const total = positive.reduce((sum, seg) => sum + seg.value, 0);
  if (total <= 0) return [];

  const sorted = [...positive].sort((a, b) => b.value - a.value);
  const largest = sorted[0];
  const labeled: EquityBreakdownSegment[] = [largest];
  let otherTotal = 0;

  for (const seg of sorted.slice(1)) {
    const pct = (seg.value / total) * 100;
    if (
      labeled.length < maxLabeledSegments - 1 &&
      pct >= minLabelPct
    ) {
      labeled.push(seg);
    } else {
      otherTotal += seg.value;
    }
  }

  if (otherTotal > 0) {
    labeled.push({
      id: "other",
      label: "Other",
      value: otherTotal,
      color: OTHER_COLOR,
    });
  }

  return labeled.map((seg) => ({
    ...seg,
    color: seg.id === "other" ? OTHER_COLOR : seg.color,
  }));
}

interface LabelLayout {
  arc: PieArcDatum<EquityBreakdownSegment>;
  pct: number;
  sx: number;
  sy: number;
  mx: number;
  my: number;
  ex: number;
  ey: number;
  textAnchor: "start" | "end";
  labelX: number;
  labelY: number;
}

function buildLabelLayout(
  arc: PieArcDatum<EquityBreakdownSegment>,
  total: number,
  outerRadius: number,
  labelRadius: number,
): LabelLayout {
  const midAngle = (arc.startAngle + arc.endAngle) / 2;
  const cos = Math.cos(midAngle - Math.PI / 2);
  const sin = Math.sin(midAngle - Math.PI / 2);
  const sx = cos * outerRadius;
  const sy = sin * outerRadius;
  const mx = cos * (outerRadius + 10);
  const my = sin * (outerRadius + 10);
  const ex = cos * labelRadius;
  const ey = sin * labelRadius;
  const textAnchor = cos >= 0 ? "start" : "end";
  const labelX = cos >= 0 ? ex + 8 : ex - 8;

  return {
    arc,
    pct: total > 0 ? (arc.data.value / total) * 100 : 0,
    sx,
    sy,
    mx,
    my,
    ex,
    ey,
    textAnchor,
    labelX,
    labelY: ey,
  };
}

interface ChartInteraction {
  activeId: string | null;
  hasFocus: boolean;
  handlePointerEnter: (segmentId: string) => void;
  handlePointerLeave: (event: React.PointerEvent) => void;
  handleSegmentClick: (segmentId: string) => void;
}

function useChartInteraction(): ChartInteraction {
  const [activeId, setActiveId] = useState<string | null>(null);

  const handlePointerEnter = useCallback((segmentId: string) => {
    setActiveId(segmentId);
  }, []);

  const handlePointerLeave = useCallback((event: React.PointerEvent) => {
    if (event.pointerType === "mouse") {
      setActiveId(null);
    }
  }, []);

  const handleSegmentClick = useCallback((segmentId: string) => {
    setActiveId((prev) => (prev === segmentId ? null : segmentId));
  }, []);

  return {
    activeId,
    hasFocus: activeId != null,
    handlePointerEnter,
    handlePointerLeave,
    handleSegmentClick,
  };
}

function resolveRadii(
  width: number,
  height: number,
  layout: PortfolioEquityBreakdownChartLayout,
  inlineDonutInset?: number,
): { outerRadius: number; innerRadius: number; labelRadius: number } {
  if (layout === "stacked") {
    const outerRadius = Math.min(width * 0.45, height * 0.48);
    return {
      outerRadius,
      innerRadius: outerRadius * 0.62,
      labelRadius: outerRadius,
    };
  }

  if (layout === "inline") {
    const outerRadius =
      inlineDonutInset != null
        ? Math.max(Math.min(width / 2, height / 2) - inlineDonutInset, 20)
        : Math.min(width, height) * 0.46;
    return {
      outerRadius,
      innerRadius: outerRadius * 0.62,
      labelRadius: outerRadius,
    };
  }

  const margin = 48;
  const size = Math.max(Math.min(width, height) - margin * 2, 120);
  const outerRadius = size * 0.38;
  return {
    outerRadius,
    innerRadius: size * 0.26,
    labelRadius: outerRadius + 28,
  };
}

interface DonutSvgProps {
  width: number;
  height: number;
  layout: PortfolioEquityBreakdownChartLayout;
  chartSegments: EquityBreakdownSegment[];
  total: number;
  activeId: string | null;
  hasFocus: boolean;
  activeSegment: EquityBreakdownSegment | undefined;
  activePct: number;
  defaultCenterValue?: string;
  defaultCenterLabel?: string;
  hideCenterLabel?: boolean;
  inlineDonutInset?: number;
  onPointerEnter: (segmentId: string) => void;
  onPointerLeave: (event: React.PointerEvent<SVGElement>) => void;
  onSegmentClick: (segmentId: string) => void;
}

function DonutSvg({
  width,
  height,
  layout,
  chartSegments,
  total,
  activeId,
  hasFocus,
  activeSegment,
  activePct,
  defaultCenterValue,
  defaultCenterLabel,
  hideCenterLabel = false,
  inlineDonutInset,
  onPointerEnter,
  onPointerLeave,
  onSegmentClick,
}: DonutSvgProps): JSX.Element {
  const centerX = width / 2;
  const centerY = height / 2;
  const { outerRadius, innerRadius, labelRadius } = resolveRadii(
    width,
    height,
    layout,
    inlineDonutInset,
  );
  const showRadialLabels = layout === "radial";
  const centerValue = hasFocus
    ? formatPct(activePct)
    : (defaultCenterValue ?? formatPct(activePct));
  const centerLabel = hasFocus
    ? (activeSegment?.label ?? "Total equity")
    : (defaultCenterLabel ?? activeSegment?.label ?? "Total equity");

  return (
    <svg
      width={width}
      height={height}
      className={segmentClassName(
        "portfolio-equity-breakdown-chart-svg",
        layout === "stacked" && "portfolio-equity-breakdown-chart-svg--stacked",
        layout === "inline" && "portfolio-equity-breakdown-chart-svg--inline",
      )}
      role="img"
      aria-label="Equity breakdown chart"
      onPointerLeave={onPointerLeave}
    >
      <Group top={centerY} left={centerX}>
        <Pie
          data={chartSegments}
          pieValue={(seg) => seg.value}
          outerRadius={outerRadius}
          innerRadius={innerRadius}
          padAngle={0.015}
          cornerRadius={2}
          pieSortValues={(a, b) => b - a}
        >
          {(pie) => {
            const labels = showRadialLabels
              ? pie.arcs.map((arc) =>
                  buildLabelLayout(arc, total, outerRadius, labelRadius),
                )
              : [];

            return (
              <>
                {pie.arcs.map((arc) => {
                  const segmentId = arc.data.id;
                  const isFocused = hasFocus && segmentId === activeId;
                  const isDimmed = hasFocus && segmentId !== activeId;
                  const segmentPct =
                    total > 0 ? (arc.data.value / total) * 100 : 0;

                  return (
                    <path
                      key={segmentId}
                      d={pie.path(arc) ?? ""}
                      fill={isFocused ? HIGHLIGHT_COLOR : arc.data.color}
                      stroke={TERMINAL_COLORS.bg}
                      strokeWidth={isFocused ? 3 : 2}
                      className={segmentClassName(
                        "portfolio-equity-breakdown-chart-segment",
                        isFocused &&
                          "portfolio-equity-breakdown-chart-segment--focused",
                        isDimmed &&
                          "portfolio-equity-breakdown-chart-segment--dimmed",
                      )}
                      onPointerEnter={() => onPointerEnter(segmentId)}
                      onClick={() => onSegmentClick(segmentId)}
                      aria-label={`${arc.data.label}: ${formatPct(segmentPct)}`}
                    />
                  );
                })}
                {labels.map((label) => {
                  const segmentId = label.arc.data.id;
                  const isDimmed = hasFocus && segmentId !== activeId;

                  return (
                    <g
                      key={segmentId}
                      className="portfolio-equity-breakdown-chart-label-group"
                      onPointerEnter={() => onPointerEnter(segmentId)}
                      onClick={() => onSegmentClick(segmentId)}
                    >
                      <polyline
                        className={segmentClassName(
                          "portfolio-equity-breakdown-chart-leader",
                          isDimmed &&
                            "portfolio-equity-breakdown-chart-leader--dimmed",
                        )}
                        points={`${label.sx},${label.sy} ${label.mx},${label.my} ${label.ex},${label.ey}`}
                        stroke={label.arc.data.color}
                        fill="none"
                      />
                      <text
                        className={segmentClassName(
                          "portfolio-equity-breakdown-chart-label",
                          isDimmed &&
                            "portfolio-equity-breakdown-chart-label--dimmed",
                        )}
                        x={label.labelX}
                        y={label.labelY}
                        textAnchor={label.textAnchor}
                        dominantBaseline="middle"
                        fill={TERMINAL_COLORS.textPrimary}
                      >
                        {label.arc.data.label}
                      </text>
                    </g>
                  );
                })}
              </>
            );
          }}
        </Pie>
        {!hideCenterLabel ? (
          <foreignObject
            x={-innerRadius}
            y={-innerRadius}
            width={innerRadius * 2}
            height={innerRadius * 2}
          >
            <div
              xmlns="http://www.w3.org/1999/xhtml"
              className={segmentClassName(
                "portfolio-equity-breakdown-chart-center",
                layout === "stacked" &&
                  "portfolio-equity-breakdown-chart-center--stacked",
                layout === "inline" &&
                  "portfolio-equity-breakdown-chart-center--inline",
              )}
            >
              <span className="portfolio-equity-breakdown-chart-center-value">
                {centerValue}
              </span>
              <span className="portfolio-equity-breakdown-chart-center-label">
                {centerLabel}
              </span>
            </div>
          </foreignObject>
        ) : null}
      </Group>
    </svg>
  );
}

interface ChartLegendProps {
  segments: EquityBreakdownSegment[];
  total: number;
  activeId: string | null;
  hasFocus: boolean;
  legendValueFormat?: "currency" | "percent";
  legendColumns?: number;
  onPointerEnter: (segmentId: string) => void;
  onPointerLeave: (event: React.PointerEvent) => void;
  onSegmentClick: (segmentId: string) => void;
}

function ChartLegend({
  segments,
  total,
  activeId,
  hasFocus,
  legendValueFormat = "currency",
  legendColumns,
  onPointerEnter,
  onPointerLeave,
  onSegmentClick,
}: ChartLegendProps): JSX.Element {
  return (
    <div
      className={segmentClassName(
        "portfolio-equity-breakdown-chart-legend",
        legendColumns === 3 && "portfolio-equity-breakdown-chart-legend--columns-3",
        legendColumns != null &&
          legendColumns !== 3 &&
          `portfolio-equity-breakdown-chart-legend--columns-${legendColumns}`,
      )}
      onPointerLeave={onPointerLeave}
    >
      {segments.map((seg) => {
        const isFocused = hasFocus && seg.id === activeId;
        const isDimmed = hasFocus && seg.id !== activeId;
        const segmentPct = total > 0 ? (seg.value / total) * 100 : 0;
        const valueLabel =
          legendValueFormat === "percent"
            ? formatPctPrecise(segmentPct)
            : formatCurrency(seg.value);

        return (
          <button
            key={seg.id}
            type="button"
            className={segmentClassName(
              "portfolio-equity-breakdown-chart-legend-row",
              "portfolio-attribution-row",
              legendValueFormat === "percent" &&
                "portfolio-equity-breakdown-chart-legend-row--percent",
              isFocused &&
                "portfolio-equity-breakdown-chart-legend-row--focused",
              isDimmed && "portfolio-equity-breakdown-chart-legend-row--dimmed",
            )}
            onPointerEnter={() => onPointerEnter(seg.id)}
            onClick={() => onSegmentClick(seg.id)}
            aria-label={`${seg.label}: ${formatPctPrecise(segmentPct)}`}
          >
            <span
              className="portfolio-attribution-dot"
              style={{ background: isFocused ? HIGHLIGHT_COLOR : seg.color }}
              aria-hidden
            />
            <span>{seg.label}</span>
            <strong>{valueLabel}</strong>
          </button>
        );
      })}
    </div>
  );
}

interface ChartBodyProps {
  segments: EquityBreakdownSegment[];
  layout: PortfolioEquityBreakdownChartLayout;
  title?: string;
  defaultCenterValue?: string;
  defaultCenterLabel?: string;
  maxLabeledSegments?: number;
  minLabelPct?: number;
  preserveSegments?: boolean;
  legendValueFormat?: "currency" | "percent";
  legendColumns?: number;
  hideCenterLabel?: boolean;
  inlineDonutInset?: number;
}

function ChartBody({
  segments,
  layout,
  title,
  defaultCenterValue,
  defaultCenterLabel,
  maxLabeledSegments,
  minLabelPct,
  preserveSegments = false,
  legendValueFormat = "currency",
  legendColumns,
  hideCenterLabel = false,
  inlineDonutInset,
}: ChartBodyProps): JSX.Element {
  const {
    activeId,
    hasFocus,
    handlePointerEnter,
    handlePointerLeave,
    handleSegmentClick,
  } = useChartInteraction();

  const chartSegments = useMemo(() => {
    if (preserveSegments) {
      return segments.filter((seg) => seg.value > 0);
    }
    return prepareChartSegments(
      segments,
      maxLabeledSegments ?? DEFAULT_MAX_LABELED_SEGMENTS,
      minLabelPct ?? DEFAULT_MIN_LABEL_PCT,
    );
  }, [segments, maxLabeledSegments, minLabelPct, preserveSegments]);

  const total = useMemo(
    () => chartSegments.reduce((sum, seg) => sum + seg.value, 0),
    [chartSegments],
  );

  const defaultSegment = chartSegments[0];
  const activeSegment =
    (activeId && chartSegments.find((s) => s.id === activeId)) || defaultSegment;
  const activePct =
    total > 0 && activeSegment ? (activeSegment.value / total) * 100 : 0;

  if (chartSegments.length === 0 || total <= 0) {
    return (
      <div className="portfolio-equity-breakdown-chart-empty">
        No equity data
      </div>
    );
  }

  const legendProps = {
    segments: chartSegments,
    total,
    activeId,
    hasFocus,
    legendValueFormat,
    legendColumns,
    onPointerEnter: handlePointerEnter,
    onPointerLeave: handlePointerLeave,
    onSegmentClick: handleSegmentClick,
  };

  const donutProps = {
    layout,
    chartSegments,
    total,
    activeId,
    hasFocus,
    activeSegment,
    activePct,
    defaultCenterValue,
    defaultCenterLabel,
    hideCenterLabel,
    inlineDonutInset,
    onPointerEnter: handlePointerEnter,
    onPointerLeave: handlePointerLeave,
    onSegmentClick: handleSegmentClick,
  };

  if (layout === "inline") {
    return (
      <div
        className="portfolio-equity-breakdown-chart portfolio-equity-breakdown-chart--inline"
        onPointerLeave={handlePointerLeave}
      >
        {title ? (
          <span className="portfolio-equity-breakdown-chart-inline-title">
            {title}
          </span>
        ) : null}
        <div className="portfolio-equity-breakdown-chart-donut-area portfolio-equity-breakdown-chart-donut-area--inline">
          <ParentSize debounceTime={10}>
            {({ width, height }) =>
              width > 0 && height > 0 ? (
                <DonutSvg width={width} height={height} {...donutProps} />
              ) : null
            }
          </ParentSize>
        </div>
        <ChartLegend {...legendProps} />
      </div>
    );
  }

  if (layout === "stacked") {
    return (
      <div
        className="portfolio-equity-breakdown-chart portfolio-equity-breakdown-chart--stacked"
        onPointerLeave={handlePointerLeave}
      >
        <div className="portfolio-equity-breakdown-chart-donut-area">
          <ParentSize debounceTime={10}>
            {({ width, height }) =>
              width > 0 && height > 0 ? (
                <DonutSvg width={width} height={height} {...donutProps} />
              ) : null
            }
          </ParentSize>
        </div>
        <ChartLegend {...legendProps} />
      </div>
    );
  }

  return (
    <div className="portfolio-equity-breakdown-chart">
      <ParentSize debounceTime={10}>
        {({ width, height }) =>
          width > 0 && height > 0 ? (
            <DonutSvg width={width} height={height} {...donutProps} />
          ) : null
        }
      </ParentSize>
    </div>
  );
}

function PortfolioEquityBreakdownChart({
  segments,
  layout = "radial",
  title,
  defaultCenterValue,
  defaultCenterLabel,
  maxLabeledSegments,
  minLabelPct,
  preserveSegments,
  legendValueFormat,
  legendColumns,
  hideCenterLabel,
  inlineDonutInset,
}: PortfolioEquityBreakdownChartProps): JSX.Element {
  return (
    <ChartBody
      segments={segments}
      layout={layout}
      title={title}
      defaultCenterValue={defaultCenterValue}
      defaultCenterLabel={defaultCenterLabel}
      maxLabeledSegments={maxLabeledSegments}
      minLabelPct={minLabelPct}
      preserveSegments={preserveSegments}
      legendValueFormat={legendValueFormat}
      legendColumns={legendColumns}
      hideCenterLabel={hideCenterLabel}
      inlineDonutInset={inlineDonutInset}
    />
  );
}

export default React.memo(PortfolioEquityBreakdownChart);
