import { NavLink, Outlet } from "react-router-dom";

import { CATALOG_ENTRIES } from "../catalog/catalogRegistry";

const groupedEntries = CATALOG_ENTRIES.reduce<
  Record<string, typeof CATALOG_ENTRIES[number][]>
>((acc, entry) => {
  const list = acc[entry.category] ?? [];
  list.push(entry);
  acc[entry.category] = list;
  return acc;
}, {});

export function UiTestShell(): JSX.Element {
  return (
    <div className="uitest-shell">
      <aside className="uitest-sidebar">
        <div className="uitest-sidebar__brand">
          <span className="uitest-sidebar__logo">M</span>
          <div>
            <p className="uitest-sidebar__title">UI Test</p>
            <p className="uitest-sidebar__subtitle">Component bench</p>
          </div>
        </div>

        <nav className="uitest-sidebar__nav" aria-label="Component catalog">
          <NavLink
            to="/"
            end
            className={({ isActive }) =>
              `uitest-sidebar__link${isActive ? " is-active" : ""}`
            }
          >
            Overview
          </NavLink>

          {Object.entries(groupedEntries).map(([category, entries]) => (
            <div key={category} className="uitest-sidebar__group">
              <p className="uitest-sidebar__group-label">{category}</p>
              {entries.map((entry) => (
                <NavLink
                  key={entry.slug}
                  to={`/components/${entry.slug}`}
                  className={({ isActive }) =>
                    `uitest-sidebar__link uitest-sidebar__link--nested${
                      isActive ? " is-active" : ""
                    }`
                  }
                >
                  {entry.title}
                </NavLink>
              ))}
            </div>
          ))}
        </nav>
      </aside>

      <main className="uitest-main">
        <Outlet />
      </main>
    </div>
  );
}
