export type AgentCustodyKind = "wallet" | "vault" | "did_only";

export function getAgentRoleLabel(role: AgentRole): string {
  return AGENT_ROLE_LABELS[role];
}

export function getListingLabel(status: AgentListingStatus): string {
  return AGENT_LISTING_LABELS[status];
}

export function truncateAddress(value: string, chars = 4): string {
  if (value.length <= chars * 2 + 2) return value;
  return `${value.slice(0, chars + 2)}…${value.slice(-chars)}`;
}

export function getAgentCustodyKind(agent: TradingAgent): AgentCustodyKind {
  if (agent.walletAddress) return "wallet";
  if (agent.vaultAddress) return "vault";
  return "did_only";
}

export function getAgentCustodyLabel(agent: TradingAgent): string {
  const kind = getAgentCustodyKind(agent);
  if (kind === "wallet") {
    return `Wallet ${truncateAddress(agent.walletAddress!)}`;
  }
  if (kind === "vault") {
    return `Vault ${truncateAddress(agent.vaultAddress!)}`;
  }
  return "DID only";
}

/** Compact custody kind for detail header / overview (no address truncation). */
export function getAgentCustodyKindLabel(agent: TradingAgent): string {
  const kind = getAgentCustodyKind(agent);
  if (kind === "wallet") return "Wallet";
  if (kind === "vault") return "Vault";
  return "DID only";
}

/** Custody tab label in the agent detail panel. */
export function getAgentCustodyTabLabel(agent: TradingAgent): string {
  const kind = getAgentCustodyKind(agent);
  if (kind === "wallet") return "Wallet";
  if (kind === "vault") return "Vault";
  return "Permissions";
}

export function agentHasWallet(agent: TradingAgent): boolean {
  return getAgentCustodyKind(agent) === "wallet";
}

export function resolveAgentPaymentState(agent: TradingAgent): AgentPaymentState {
  if (agent.paymentState) return agent.paymentState;
  const custodyKind = getAgentCustodyKind(agent);
  if (custodyKind === "did_only") return "no_payments";
  if (agent.status === "paused" && custodyKind === "wallet") return "spend_paused";
  if (custodyKind === "vault") return "pay_enabled";
  return "pay_enabled";
}

export function getAgentPaymentLabel(agent: TradingAgent): string {
  return AGENT_PAYMENT_LABELS[resolveAgentPaymentState(agent)];
}

export function getAgentPaymentShortLabel(agent: TradingAgent): string {
  const state = resolveAgentPaymentState(agent);
  if (state === "pay_enabled") return "⇅ Pay";
  if (state === "receive_only") return "↓ Recv";
  if (state === "spend_paused") return "⏸ Paused";
  return "—";
}

export function formatPaymentUsd(value: number | undefined): string {
  if (value == null) return "—";
  const sign = value < 0 ? "-" : "";
  const abs = Math.abs(value);
  if (abs >= 1_000_000) return `${sign}$${(abs / 1_000_000).toFixed(2)}M`;
  if (abs >= 1_000) return `${sign}$${(abs / 1_000).toFixed(1)}k`;
  return `${sign}$${abs.toFixed(0)}`;
}

export function formatSpendCapSummary(agent: TradingAgent): string {
  const state = resolveAgentPaymentState(agent);
  if (state === "no_payments") return "—";
  const cap = agent.spendCapDailyUsd;
  const used = agent.spendUsedDailyUsd ?? 0;
  if (cap == null) return "No cap set";
  return `${formatPaymentUsd(used)} / ${formatPaymentUsd(cap)} day`;
}

export function agentMatchesCustodyFilter(
  agent: TradingAgent,
  filter: string,
): boolean {
  if (filter === "All") return true;
  const kind = getAgentCustodyKind(agent);
  if (filter === "With wallet") return kind === "wallet" || kind === "vault";
  if (filter === "DID only") return kind === "did_only";
  return true;
}

export function agentMatchesPaymentFilter(
  agent: TradingAgent,
  filter: string,
): boolean {
  if (filter === "All") return true;
  return getAgentPaymentLabel(agent) === filter;
}

export function agentMatchesRoleFilter(agent: TradingAgent, filter: string): boolean {
  if (filter === "All") return true;
  return getAgentRoleLabel(agent.role) === filter;
}

export function agentMatchesListingFilter(
  agent: TradingAgent,
  filter: string,
): boolean {
  if (filter === "All") return true;
  return getListingLabel(agent.listingStatus) === filter;
}

export function agentMatchesModeFilter(agent: TradingAgent, filter: string): boolean {
  if (filter === "All") return true;
  return AGENT_STATUS_LABELS[agent.status] === filter;
}

export function isAgentProvisioning(agent: TradingAgent): boolean {
  return agent.provisioningStatus === "provisioning";
}

export function getAgentStatusDotClass(agent: TradingAgent): string {
  if (isAgentProvisioning(agent)) {
    return "agentroles-status-dot agentroles-status-dot--provisioning";
  }
  return `agentroles-status-dot agentroles-status-dot--${agent.status}`;
}

export function getAgentWorkCellLabel(
  agent: TradingAgent,
  activeTaskCount: number,
): string {
  if (isAgentProvisioning(agent)) return "Provisioning…";
  if (activeTaskCount > 0) return `${activeTaskCount} active`;
  return AGENT_STATUS_LABELS[agent.status];
}

export function formatAgentRevenue(value: number | undefined): string {
  if (value == null) return "—";
  const sign = value < 0 ? "-" : "";
  const abs = Math.abs(value);
  if (abs >= 1_000_000) return `${sign}$${(abs / 1_000_000).toFixed(2)}M`;
  if (abs >= 1_000) return `${sign}$${(abs / 1_000).toFixed(1)}k`;
  return `${sign}$${abs.toFixed(0)}`;
}

/** Storage key for operator-owned agent settings (route key from DID, else fleet id). */
export function resolveFleetAgentSettingsKey(agent: TradingAgent): string {
  if (agent.listingStatus === "listed" && agent.did.trim()) {
    return agentDidToRouteParam(agent.did);
  }
  return agent.id.trim();
}

