import type { AgentKpiSummary } from "./agentKpiHistory.types";

export function clampReputationScore(value: number): number {
  return Math.min(100, Math.max(0, value));
}

export type ReputationFactorId =
  | "roi30d"
  | "sharpe"
  | "maxDd"
  | "winRate"
  | "revenueStability";

export type ReputationFactorBreakdown = {
  id: ReputationFactorId;
  label: string;
  rawValue: string;
  subScore: number;
  weight: number;
  contribution: number;
};

export type ReputationPenalty = {
  label: string;
  amount: number;
};

export type ReputationBreakdown = {
  roi30dPct: number;
  factors: ReputationFactorBreakdown[];
  baseScore: number;
  penalties: ReputationPenalty[];
  penaltyTotal: number;
  composite: number;
};

const REPUTATION_FACTOR_WEIGHTS: Record<ReputationFactorId, number> = {
  roi30d: 0.25,
  sharpe: 0.25,
  maxDd: 0.2,
  winRate: 0.15,
  revenueStability: 0.15,
};

function buildReputationPenalties(summary: AgentKpiSummary): ReputationPenalty[] {
  const penalties: ReputationPenalty[] = [];

  if (summary.pnl30dUsd < 0) {
    const amount = Math.min(
      18,
      Math.abs(summary.pnl30dUsd / Math.max(summary.aumUsd, 1)) * 400,
    );
    if (amount > 0) {
      penalties.push({ label: "Negative 30d PnL", amount });
    }
  }
  if (summary.pnl30dUsd < -10_000) {
    penalties.push({ label: "30d PnL below −$10K", amount: 10 });
  }
  if (summary.pnl30dUsd < -25_000) {
    penalties.push({ label: "30d PnL below −$25K", amount: 8 });
  }
  if (summary.sharpe30d < -2) {
    penalties.push({
      label: "Sharpe below −2",
      amount: Math.min(12, Math.abs(summary.sharpe30d) * 2.5),
    });
  }

  return penalties;
}

function formatRoiRawValue(roi30dPct: number): string {
  return `${roi30dPct >= 0 ? "+" : ""}${roi30dPct.toFixed(1)}%`;
}

/** Composite 0–100 score with per-factor and penalty breakdown. */
export function computeReputationBreakdown(
  summary: AgentKpiSummary,
): ReputationBreakdown {
  const roi30dPct =
    summary.aumUsd > 0 ? (summary.pnl30dUsd / summary.aumUsd) * 100 : 0;
  const roiScore = clampReputationScore(50 + roi30dPct * 4);
  const sharpeScore = clampReputationScore(50 + summary.sharpe30d * 12);
  const ddScore = clampReputationScore(100 - summary.maxDdPct * 2.5);
  const winScore = clampReputationScore((summary.winRatePct - 40) * 1.5);
  const revStabScore = clampReputationScore(summary.revenueStability * 100);

  const factors: ReputationFactorBreakdown[] = [
    {
      id: "roi30d",
      label: "30d ROI",
      rawValue: formatRoiRawValue(roi30dPct),
      subScore: roiScore,
      weight: REPUTATION_FACTOR_WEIGHTS.roi30d,
      contribution: roiScore * REPUTATION_FACTOR_WEIGHTS.roi30d,
    },
    {
      id: "sharpe",
      label: "Sharpe",
      rawValue: summary.sharpe30d.toFixed(1),
      subScore: sharpeScore,
      weight: REPUTATION_FACTOR_WEIGHTS.sharpe,
      contribution: sharpeScore * REPUTATION_FACTOR_WEIGHTS.sharpe,
    },
    {
      id: "maxDd",
      label: "Max DD",
      rawValue: `${summary.maxDdPct.toFixed(1)}%`,
      subScore: ddScore,
      weight: REPUTATION_FACTOR_WEIGHTS.maxDd,
      contribution: ddScore * REPUTATION_FACTOR_WEIGHTS.maxDd,
    },
    {
      id: "winRate",
      label: "Win rate",
      rawValue: `${summary.winRatePct.toFixed(1)}%`,
      subScore: winScore,
      weight: REPUTATION_FACTOR_WEIGHTS.winRate,
      contribution: winScore * REPUTATION_FACTOR_WEIGHTS.winRate,
    },
    {
      id: "revenueStability",
      label: "Revenue stability",
      rawValue: summary.revenueStability.toFixed(2),
      subScore: revStabScore,
      weight: REPUTATION_FACTOR_WEIGHTS.revenueStability,
      contribution: revStabScore * REPUTATION_FACTOR_WEIGHTS.revenueStability,
    },
  ];

  const baseScore = clampReputationScore(
    factors.reduce((sum, factor) => sum + factor.contribution, 0),
  );
  const penalties = buildReputationPenalties(summary);
  const penaltyTotal = penalties.reduce((sum, penalty) => sum + penalty.amount, 0);
  const composite = clampReputationScore(baseScore - penaltyTotal);

  return {
    roi30dPct,
    factors,
    baseScore,
    penalties,
    penaltyTotal,
    composite,
  };
}

/** Composite 0–100 score aligned with Markets reputation bands (A=80–100 … E=0–19). */
export function computeReputationScore(summary: AgentKpiSummary): number {
  return computeReputationBreakdown(summary).composite;
}

export function scoreToRiskLabel(score: number, tieBreak: number): string {
  const mod = tieBreak % 3;
  if (score >= 80) {
    if (mod === 0) return "A+";
    if (mod === 1) return "A";
    return "A-";
  }
  if (score >= 60) {
    if (mod === 0) return "B+";
    if (mod === 1) return "B";
    return "B-";
  }
  if (score >= 40) {
    if (mod === 0) return "C+";
    if (mod === 1) return "C";
    return "C-";
  }
  if (score >= 20) {
    if (mod === 0) return "D+";
    if (mod === 1) return "D";
    return "D-";
  }
  return "E";
}

export function deriveRiskLabelFromSummary(
  summary: AgentKpiSummary,
  tieBreak: number,
): string {
  return scoreToRiskLabel(computeReputationScore(summary), tieBreak);
}

export const MIN_A_GRADED_AGENTS = 2;

const TOP_A_LABELS = ["A", "A-"] as const;

/** Ensure at least `MIN_A_GRADED_AGENTS` entries carry an A-band label (by rank). */
export function ensureMinimumAGrades<T extends { riskLabel: string }>(
  entries: T[],
  rankScore: (entry: T) => number,
): void {
  let aCount = entries.filter((entry) => entry.riskLabel.startsWith("A")).length;
  if (aCount >= MIN_A_GRADED_AGENTS) return;

  const ranked = [...entries].sort((a, b) => rankScore(b) - rankScore(a));
  for (const entry of ranked) {
    if (aCount >= MIN_A_GRADED_AGENTS) break;
    if (entry.riskLabel.startsWith("A")) continue;
    entry.riskLabel = TOP_A_LABELS[aCount] ?? "A-";
    aCount += 1;
  }
}

export function ensureMinimumAGradeLabels<T extends { reputationGrade: string }>(
  entries: T[],
  rankScore: (entry: T) => number,
): void {
  let aCount = entries.filter((entry) => entry.reputationGrade.startsWith("A")).length;
  if (aCount >= MIN_A_GRADED_AGENTS) return;

  const ranked = [...entries].sort((a, b) => rankScore(b) - rankScore(a));
  for (const entry of ranked) {
    if (aCount >= MIN_A_GRADED_AGENTS) break;
    if (entry.reputationGrade.startsWith("A")) continue;
    entry.reputationGrade = TOP_A_LABELS[aCount] ?? "A-";
    aCount += 1;
  }
}

/** Fleet trade rollup → synthetic KPI inputs for reputation grading. */
export function deriveFleetTradeReputationGrade(input: {
  closedPnl30dUsd: number;
  kpiPnl30dUsd: number;
  winRate30dPct: number;
  tieBreak: number;
}): string {
  const summary: AgentKpiSummary = {
    price: 1,
    change24h: 0,
    marketCapUsd: 1_000_000,
    revenue30dUsd: Math.max(0, input.closedPnl30dUsd * 8),
    pnl30dUsd: input.kpiPnl30dUsd,
    pnlAllTimeUsd: input.kpiPnl30dUsd * 2.5,
    sharpe30d: input.closedPnl30dUsd >= 0 ? 1.4 : -1.8,
    maxDdPct: input.closedPnl30dUsd >= 0 ? 8 : 14,
    winRatePct: input.winRate30dPct,
    aumUsd: 2_100_000,
    netExposureX: 1,
    copyCount: 100,
    volume24hUsd: 500_000,
    openInterestUsd: 100_000,
    annFundingPct: 10,
    revenueStability: 0.76,
    timeLivePct: 90,
    riskLabel: "B",
    riskScoreSuffix: "Active",
    leverage: 30,
    mandateCap: "1.3x gross cap",
  };
  return deriveRiskLabelFromSummary(summary, input.tieBreak);
}
