import type { CandlestickData, UTCTimestamp } from "lightweight-charts";
import type { BinanceKlineRow, BinanceWsKline } from "./types";

/** Default historical window for live kline charts (May 20, 2026 UTC). */
export const BINANCE_KLINE_DEFAULT_START_MS = Date.parse("2026-05-20T00:00:00.000Z");

const BINANCE_INTERVAL_MS: Record<string, number> = {
  "1s": 1000,
  "1m": 60_000,
  "3m": 3 * 60_000,
  "5m": 5 * 60_000,
  "15m": 15 * 60_000,
  "30m": 30 * 60_000,
  "1h": 60 * 60_000,
  "2h": 2 * 60 * 60_000,
  "4h": 4 * 60 * 60_000,
  "6h": 6 * 60 * 60_000,
  "8h": 8 * 60 * 60_000,
  "12h": 12 * 60 * 60_000,
  "1d": 24 * 60 * 60_000,
  "3d": 3 * 24 * 60 * 60_000,
  "1w": 7 * 24 * 60 * 60_000,
  "1M": 30 * 24 * 60 * 60_000,
};

export function binanceIntervalToMs(interval: string): number {
  return BINANCE_INTERVAL_MS[interval] ?? 5 * 60_000;
}

export interface BinanceKlineUpdate {
  openTime?: number;
  closeTime?: number;
  open: string | number;
  high: string | number;
  low: string | number;
  close: string | number;
  volume?: string | number;
}

function parseDecimal(value: string | number): number {
  if (typeof value === "number") return value;
  const parsed = parseFloat(value);
  return Number.isFinite(parsed) ? parsed : 0;
}

function toChartTime(openTime: number): UTCTimestamp {
  const ms = openTime < 1e12 ? openTime * 1000 : openTime;
  return Math.floor(ms / 1000) as UTCTimestamp;
}

/** Normalize symbol to Binance pair, e.g. BINANCE:BTCUSDT → BTCUSDT, BTC/USDC → BTCUSDC */
export function toBinanceSymbol(symbol: string): string {
  const trimmed = symbol.trim();
  if (!trimmed) return "BTCUSDT";

  const upper = trimmed.toUpperCase();
  if (upper.startsWith("BINANCE:")) {
    return upper.slice("BINANCE:".length);
  }
  return upper.replace(/[/\-_\s]/g, "");
}

/** Map TradingView interval (e.g. "5", "60", "D") to Binance interval (e.g. "5m", "1h", "1d"). */
export function toBinanceInterval(interval: string): string {
  const trimmed = interval.trim();
  if (!trimmed) return "5m";

  if (/^\d+[smhdwMy]$/.test(trimmed)) {
    return trimmed;
  }

  const upper = trimmed.toUpperCase();
  if (upper === "D" || upper === "1D") return "1d";
  if (upper === "W" || upper === "1W") return "1w";
  if (upper === "M" || upper === "1M") return "1M";

  const minutes = parseInt(trimmed, 10);
  if (!Number.isFinite(minutes) || minutes <= 0) return "5m";

  if (minutes === 1) return "1m";
  if (minutes === 3) return "3m";
  if (minutes === 5) return "5m";
  if (minutes === 15) return "15m";
  if (minutes === 30) return "30m";
  if (minutes === 60) return "1h";
  if (minutes === 120) return "2h";
  if (minutes === 240) return "4h";
  if (minutes === 360) return "6h";
  if (minutes === 480) return "8h";
  if (minutes === 720) return "12h";
  if (minutes === 1440) return "1d";
  if (minutes === 4320) return "3d";
  if (minutes % 60 === 0) return `${minutes / 60}h`;

  return `${minutes}m`;
}

export function binanceRestKlineToCandle(row: BinanceKlineRow): CandlestickData | null {
  const [openTime, open, high, low, close] = row;
  if (openTime == null || open == null || high == null || low == null || close == null) {
    return null;
  }

  return {
    time: toChartTime(openTime),
    open: parseDecimal(open),
    high: parseDecimal(high),
    low: parseDecimal(low),
    close: parseDecimal(close),
  };
}

export function binanceRestKlineVolume(row: BinanceKlineRow): { time: UTCTimestamp; volume: number } | null {
  const [openTime, , , , , volume] = row;
  if (openTime == null || volume == null) return null;
  const parsed = parseDecimal(volume);
  if (parsed <= 0) return null;
  return { time: toChartTime(openTime), volume: parsed };
}

export function mergeVolumeByTime(
  ...sources: ReadonlyMap<number, number>[]
): Map<number, number> {
  const merged = new Map<number, number>();
  for (const source of sources) {
    for (const [time, volume] of source) {
      merged.set(time, volume);
    }
  }
  return merged;
}

export function binanceWsKlineToUpdate(k: BinanceWsKline): BinanceKlineUpdate {
  return {
    openTime: k.t,
    closeTime: k.T,
    open: parseDecimal(k.o),
    high: parseDecimal(k.h),
    low: parseDecimal(k.l),
    close: parseDecimal(k.c),
    volume: parseDecimal(k.v),
  };
}

export function binanceWsKlineToCandle(k: BinanceWsKline): CandlestickData {
  return {
    time: toChartTime(k.t),
    open: parseDecimal(k.o),
    high: parseDecimal(k.h),
    low: parseDecimal(k.l),
    close: parseDecimal(k.c),
  };
}

export function mergeBinanceCandles(candles: CandlestickData[]): CandlestickData[] {
  const byTime = new Map<number, CandlestickData>();
  for (const candle of candles) {
    byTime.set(candle.time as number, candle);
  }
  return Array.from(byTime.values()).sort((a, b) => (a.time as number) - (b.time as number));
}
