import { selectMarketsFeaturedAgentIds } from "./marketsFeaturedAgents";

export type MaexIndexSlug = "MAEXALP" | "MAEXGEN" | "MAEXSOC";

export type MarketsAgentIndexMembership = {
  slug: MaexIndexSlug;
  label: string;
};

export const MARKETS_AGENT_INDEX_MEMBERSHIP: Record<
  string,
  MarketsAgentIndexMembership
> = {
  alphabot: { slug: "MAEXALP", label: "MAEX Alpha" },
  "ext-edge-badger": { slug: "MAEXALP", label: "MAEX Alpha" },
  "ext-grid-gecko": { slug: "MAEXALP", label: "MAEX Alpha" },
  "ext-ridge-raven": { slug: "MAEXGEN", label: "MAEX Genesis" },
  "ext-spark-whale": { slug: "MAEXGEN", label: "MAEX Genesis" },
  "ext-cipher-tiger": { slug: "MAEXGEN", label: "MAEX Genesis" },
  "neural-hedger": { slug: "MAEXSOC", label: "MAEX Social" },
  yieldfox: { slug: "MAEXSOC", label: "MAEX Social" },
  "ext-dune-crane": { slug: "MAEXSOC", label: "MAEX Social" },
};

export function getMarketsAgentIndexMembership(
  seedKey: string,
): MarketsAgentIndexMembership | undefined {
  return MARKETS_AGENT_INDEX_MEMBERSHIP[seedKey];
}

export function getIndexConstituentSeedKeys(slug: MaexIndexSlug): string[] {
  return Object.entries(MARKETS_AGENT_INDEX_MEMBERSHIP)
    .filter(([, membership]) => membership.slug === slug)
    .map(([seedKey]) => seedKey);
}

/** Featured agent seed keys with no index membership chip. */
export function getUnindexedFeaturedAgentSeedKeys(): string[] {
  const featured = selectMarketsFeaturedAgentIds();
  return featured.filter((seedKey) => !MARKETS_AGENT_INDEX_MEMBERSHIP[seedKey]);
}
