import React, { useMemo } from "react";
import { sliderProgressPct } from "./sliderProgressPct";
import "./filledRangeSlider.css";

export type FilledRangeVariant = "brand" | "info";
export type FilledRangeSize = "md" | "sm";

export interface FilledRangeSliderProps
  extends Omit<
    React.InputHTMLAttributes<HTMLInputElement>,
    "type" | "onChange" | "min" | "max" | "value"
  > {
  min: number;
  max: number;
  step?: number;
  value: number;
  onChange: (value: number) => void;
  variant?: FilledRangeVariant;
  size?: FilledRangeSize;
  className?: string;
}

export function FilledRangeSlider({
  min,
  max,
  step,
  value,
  onChange,
  variant = "brand",
  size = "md",
  className,
  style,
  ...rest
}: FilledRangeSliderProps): JSX.Element {
  const sliderProgress = useMemo(
    () => sliderProgressPct(value, min, max),
    [value, min, max],
  );

  const sliderClassName = [
    "filled-range-slider",
    `filled-range-slider--${variant}`,
    `filled-range-slider--${size}`,
    className,
  ]
    .filter(Boolean)
    .join(" ");

  return (
    <input
      type="range"
      min={min}
      max={max}
      step={step}
      value={value}
      className={sliderClassName}
      style={
        {
          ...style,
          "--slider-progress": sliderProgress,
        } as React.CSSProperties
      }
      onChange={(event) => onChange(Number(event.target.value))}
      {...rest}
    />
  );
}
