import { useState } from "react";

import {
  OVERLAY_TIMING,
  StaggeredOverlayBackdrop,
  StaggeredOverlayPanel,
  StaggeredOverlayRoot,
  useStaggeredOverlay,
} from "@mormlayer/components/ui/overlay";

import { ComponentDocPage } from "../layout/ComponentDocPage";
import { DocSection } from "../layout/DocSection";
import { PreviewCanvas } from "../layout/PreviewCanvas";

const PANEL_CONTENT = (
  <div style={{ padding: "20px 24px", minWidth: 320 }}>
    <h3 style={{ margin: "0 0 8px", fontSize: 16 }}>Staggered overlay panel</h3>
    <p style={{ margin: 0, fontSize: 13, opacity: 0.75, lineHeight: 1.5 }}>
      Panel scales in after mount; backdrop fades in on a staggered delay. Click
      the backdrop or Close to dismiss.
    </p>
    <div style={{ marginTop: 16, display: "flex", gap: 8, justifyContent: "flex-end" }}>
      <button type="button" className="btn btn-secondary" data-overlay-close>
        Close
      </button>
    </div>
  </div>
);

function StaggeredOverlayDemo({
  isOpen,
  onClose,
}: {
  isOpen: boolean;
  onClose: () => void;
}): JSX.Element | null {
  const { mounted, panelOpen, backdropVisible, backdropStyle } = useStaggeredOverlay({
    isOpen,
    panelDurationMs: OVERLAY_TIMING.desktopScaleMs,
  });

  if (!mounted) return null;

  return (
    <StaggeredOverlayRoot className="bucket-modal-overlay">
      <StaggeredOverlayBackdrop
        visible={backdropVisible}
        onClose={onClose}
        style={backdropStyle}
        className="staggered-overlay-backdrop--deep"
      />
      <StaggeredOverlayPanel
        open={panelOpen}
        className="modal-content staggered-overlay-panel--scale"
        aria-label="Staggered overlay demo"
        role="dialog"
        aria-modal={true}
      >
        <div
          onClick={(event) => {
            const target = event.target as HTMLElement;
            if (target.closest("[data-overlay-close]")) onClose();
          }}
        >
          {PANEL_CONTENT}
        </div>
      </StaggeredOverlayPanel>
    </StaggeredOverlayRoot>
  );
}

export function StaggeredOverlayPage(): JSX.Element {
  const [isOpen, setIsOpen] = useState(false);

  return (
    <ComponentDocPage
      title="Staggered overlay"
      description="Composable overlay shell with staggered backdrop and panel enter animations. Backdrop click closes the overlay."
    >
      <DocSection
        title="Interactive demo"
        description="Open the overlay, then close via the button or backdrop click."
      >
        <PreviewCanvas minHeight={120}>
          <button
            type="button"
            className="btn btn-primary"
            onClick={() => setIsOpen(true)}
          >
            Open overlay
          </button>
        </PreviewCanvas>
        <StaggeredOverlayDemo isOpen={isOpen} onClose={() => setIsOpen(false)} />
      </DocSection>

      <DocSection
        title="Timing"
        description={`Desktop scale duration: ${OVERLAY_TIMING.desktopScaleMs}ms panel, ${OVERLAY_TIMING.backdropFadeMs}ms backdrop fade.`}
      >
        <PreviewCanvas minHeight={80}>
          <p style={{ margin: 0, fontSize: 13, opacity: 0.75 }}>
            Uses <code>useStaggeredOverlay</code> with{" "}
            <code>OVERLAY_TIMING.desktopScaleMs</code> for the panel and default
            backdrop stagger.
          </p>
        </PreviewCanvas>
      </DocSection>
    </ComponentDocPage>
  );
}
