import type { OrderbookLevel } from "../../sdk/types/data";

export interface OrderbookHoverMetrics {
  distanceFromMid: number;
  averagePrice: number;
  totalBase: number;
  totalQuote: number;
}

function aggregateLevels(levels: OrderbookLevel[]): {
  totalBase: number;
  totalQuote: number;
  averagePrice: number;
} {
  let totalBase = 0;
  let totalQuote = 0;
  for (const level of levels) {
    totalBase += level.size;
    totalQuote += level.price * level.size;
  }
  return {
    totalBase,
    totalQuote,
    averagePrice: totalBase > 0 ? totalQuote / totalBase : 0,
  };
}

function sliceLevelsForHover(
  side: "ask" | "bid",
  index: number,
  asks: OrderbookLevel[],
  bids: OrderbookLevel[],
): OrderbookLevel[] {
  if (side === "bid") {
    if (index < 0 || index >= bids.length) return [];
    return bids.slice(0, index + 1);
  }
  if (index < 0 || index >= asks.length) return [];
  return [...asks.slice(index)].reverse();
}

export function computeOrderbookHoverMetrics(
  side: "ask" | "bid",
  index: number,
  asks: OrderbookLevel[],
  bids: OrderbookLevel[],
  midPrice: number,
): OrderbookHoverMetrics | null {
  if (midPrice <= 0) return null;

  const levels = sliceLevelsForHover(side, index, asks, bids);
  if (levels.length === 0) return null;

  const hoveredPrice =
    side === "bid" ? bids[index]!.price : asks[index]!.price;
  const { totalBase, totalQuote, averagePrice } = aggregateLevels(levels);

  return {
    distanceFromMid: Math.abs(hoveredPrice - midPrice) / midPrice,
    averagePrice,
    totalBase,
    totalQuote,
  };
}
