import { isOfflineMode } from "../../../mormv1/sdk/utils/onboardMock";

const JELLY_MODE_STORAGE_KEY = "jelly_mode_active";

let jellyModeActive = false;

export function setJellyModeActive(active: boolean): void {
  jellyModeActive = active;
  if (typeof window !== "undefined") {
    if (active) {
      sessionStorage.setItem(JELLY_MODE_STORAGE_KEY, "1");
    } else {
      sessionStorage.removeItem(JELLY_MODE_STORAGE_KEY);
    }
  }
}

export function getJellyModeActive(): boolean {
  if (jellyModeActive) return true;
  if (typeof window !== "undefined") {
    return sessionStorage.getItem(JELLY_MODE_STORAGE_KEY) === "1";
  }
  return false;
}

export function isJellyOverrideActive(baseURL: string, isJellyMode?: boolean): boolean {
  const active = isJellyMode ?? getJellyModeActive();
  return isOfflineMode(baseURL) && active;
}
