export const APP_ROUTES = {
  copytrade: "/copytrade",
  trade: "/trade",
  index: "/cindex",
  portfolio: "/portfolio",
  vault: "/vault",
  myAgents: "/myagents",
  staking: "/staking",
  agentCompare: "/agents/compare",
  quorum: "/explainations/quorum-intersection",
  networkHealth: "/explainations/networkhealth",
} as const;

export type AppRouteKey = keyof typeof APP_ROUTES;

export type MenuRouteKey =
  | "copytrade"
  | "trade"
  | "portfolio"
  | "vault"
  | "index"
  | "agents"
  | "staking"
  | "quorum"
  | "networkHealth";

export function getAppRoute(route: AppRouteKey): string {
  return APP_ROUTES[route];
}

export function resolveMenuRoute(id?: string, href?: string): string | undefined {
  if (id === "copytrade") return APP_ROUTES.copytrade;
  if (id === "trade") return APP_ROUTES.trade;
  if (id === "portfolio") return APP_ROUTES.portfolio;
  if (id === "vault") return APP_ROUTES.vault;
  if (id === "index") return APP_ROUTES.index;
  if (id === "agents") return APP_ROUTES.myAgents;
  if (id === "staking") return APP_ROUTES.staking;
  if (id === "quorum") return APP_ROUTES.quorum;
  if (id === "networkHealth") return APP_ROUTES.networkHealth;
  return href;
}

export function vaultDetailPath(vaultId: string): string {
  return `${APP_ROUTES.vault}/${encodeURIComponent(vaultId)}`;
}

export function vaultBucketPath(vaultId: string, bucketId: string): string {
  return `${APP_ROUTES.vault}/${encodeURIComponent(vaultId)}/bucket/${encodeURIComponent(bucketId)}`;
}

export function tradeVaultPath(vaultId: string): string {
  const params = new URLSearchParams({ vault: vaultId });
  return `${APP_ROUTES.trade}?${params.toString()}`;
}

export function agentRolesConsolePath(agentId: string): string {
  const params = new URLSearchParams({
    agent: agentId,
    console: "open",
  });
  return `${APP_ROUTES.trade}?${params.toString()}`;
}

/** Preserve vault-operate scope when navigating between app routes. */
export function appendVaultScope(path: string, vaultId: string | null): string {
  if (!vaultId?.trim()) return path;

  const [pathname, search = ""] = path.split("?");
  const params = new URLSearchParams(search);
  params.set("vault", vaultId);
  const query = params.toString();
  return query ? `${pathname}?${query}` : pathname;
}
