export interface MockOnboardResult {
  success: boolean;
  authToken: string;
  refreshToken: string;
  expiresAt: number;
}

export function isOfflineBaseURL(baseURL: string): boolean {
  return baseURL === "" || baseURL.startsWith("offline://");
}

/** Alias used by data hooks for offline/demo mode detection */
export const isOfflineMode = isOfflineBaseURL;

export function createMockOnboardResult(address: string): MockOnboardResult {
  const normalizedAddress = address.trim().toLowerCase();
  const authToken = `mock-auth-${normalizedAddress.slice(2, 10)}`;
  const refreshToken = `mock-refresh-${normalizedAddress.slice(-8)}`;
  const expiresAt = Math.floor(Date.now() / 1000) + 24 * 60 * 60;

  return {
    success: true,
    authToken,
    refreshToken,
    expiresAt,
  };
}
