import { useMemo, useState } from "react";

import PortfolioEquityBreakdownChart, {
  type PortfolioEquityBreakdownChartLayout,
} from "@mormlayer/components/portfolio/PortfolioEquityBreakdownChart";
import type { EquityBreakdownSegment } from "@mormlayer/hooks/usePortfolioAnalytics";
import "@mormlayer/components/portfolio/portfolio.css";

import { ComponentDocPage } from "../layout/ComponentDocPage";
import { DocSection } from "../layout/DocSection";
import { PreviewCanvas } from "../layout/PreviewCanvas";
import { VariantGrid, VariantTile } from "../layout/VariantGrid";

const PORTFOLIO_COLORS = [
  "#64748b",
  "#38bdf8",
  "#34d399",
  "#a78bfa",
  "#fbbf24",
  "#fb7185",
  "#94a3b8",
];

const DEMO_PORTFOLIO_SEGMENTS: EquityBreakdownSegment[] = [
  { id: "spot", label: "Spot wallet", value: 12_450, color: PORTFOLIO_COLORS[0]! },
  { id: "bucket-a", label: "Cross · a1b2c3…", value: 28_320, color: PORTFOLIO_COLORS[1]! },
  { id: "bucket-b", label: "Cross · d4e5f6…", value: 19_870, color: PORTFOLIO_COLORS[2]! },
  { id: "bucket-c", label: "Isolated · g7h8…", value: 8_640, color: PORTFOLIO_COLORS[3]! },
];

const DEMO_ASSET_SEGMENTS: EquityBreakdownSegment[] = [
  { id: "btc", label: "BTC", value: 42.5, color: "#38bdf8" },
  { id: "eth", label: "ETH", value: 28.3, color: "#34d399" },
  { id: "sol", label: "SOL", value: 12.1, color: "#a78bfa" },
  { id: "arb", label: "ARB", value: 6.4, color: "#fbbf24" },
  { id: "link", label: "LINK", value: 4.2, color: "#fb7185" },
  { id: "avax", label: "AVAX", value: 3.1, color: "#94a3b8" },
  { id: "doge", label: "DOGE", value: 1.8, color: "#f472b6" },
  { id: "other", label: "Other", value: 1.6, color: "#475569" },
];

const DEMO_MANY_SEGMENTS: EquityBreakdownSegment[] = [
  ...DEMO_PORTFOLIO_SEGMENTS,
  { id: "bucket-d", label: "Cross · i9j0k1…", value: 4_200, color: PORTFOLIO_COLORS[4]! },
  { id: "bucket-e", label: "Cross · l2m3n4…", value: 2_850, color: PORTFOLIO_COLORS[5]! },
  { id: "bucket-f", label: "Isolated · o5p6…", value: 1_120, color: PORTFOLIO_COLORS[6]! },
  { id: "dust-a", label: "Cross · q7r8s9…", value: 420, color: "#2dd4bf" },
  { id: "dust-b", label: "Cross · t0u1v2…", value: 180, color: "#818cf8" },
];

function formatCurrency(value: number): string {
  if (value >= 1_000_000) return `$${(value / 1_000_000).toFixed(2)}M`;
  if (value >= 1_000) return `$${(value / 1_000).toFixed(1)}k`;
  return `$${value.toFixed(2)}`;
}

function ChartPreview({
  segments,
  layout,
  title,
  defaultCenterValue,
  defaultCenterLabel,
  preserveSegments,
  legendValueFormat,
  legendColumns,
  hideCenterLabel,
  inlineDonutInset,
  height = 280,
}: {
  segments: EquityBreakdownSegment[];
  layout: PortfolioEquityBreakdownChartLayout;
  title?: string;
  defaultCenterValue?: string;
  defaultCenterLabel?: string;
  preserveSegments?: boolean;
  legendValueFormat?: "currency" | "percent";
  legendColumns?: number;
  hideCenterLabel?: boolean;
  inlineDonutInset?: number;
  height?: number;
}): JSX.Element {
  return (
    <div className="portfolio-slot portfolio-slot--flush" style={{ height }}>
      <PortfolioEquityBreakdownChart
        segments={segments}
        layout={layout}
        title={title}
        defaultCenterValue={defaultCenterValue}
        defaultCenterLabel={defaultCenterLabel}
        preserveSegments={preserveSegments}
        legendValueFormat={legendValueFormat}
        legendColumns={legendColumns}
        hideCenterLabel={hideCenterLabel}
        inlineDonutInset={inlineDonutInset}
      />
    </div>
  );
}

export function PortfolioEquityBreakdownChartPage(): JSX.Element {
  const [layout, setLayout] =
    useState<PortfolioEquityBreakdownChartLayout>("stacked");
  const [legendValueFormat, setLegendValueFormat] = useState<
    "currency" | "percent"
  >("currency");
  const [preserveSegments, setPreserveSegments] = useState(false);
  const [hideCenterLabel, setHideCenterLabel] = useState(false);
  const [legendColumns, setLegendColumns] = useState<number | "auto">("auto");

  const allocationTotal = useMemo(
    () => DEMO_PORTFOLIO_SEGMENTS.reduce((sum, seg) => sum + seg.value, 0),
    [],
  );

  const segments =
    legendValueFormat === "percent" ? DEMO_ASSET_SEGMENTS : DEMO_PORTFOLIO_SEGMENTS;

  const previewHeight =
    layout === "radial" ? 320 : layout === "inline" ? 220 : 360;

  return (
    <ComponentDocPage
      title="Portfolio equity breakdown chart"
      description="Interactive donut chart for portfolio equity and asset allocation — radial, stacked, and inline layouts with hover focus and legend bucketing."
    >
      <DocSection
        title="Default preview"
        description="Portfolio-style equity segments with hover focus and segment bucketing."
      >
        <PreviewCanvas minHeight={previewHeight}>
          <ChartPreview
            segments={segments}
            layout={layout}
            defaultCenterValue={formatCurrency(allocationTotal)}
            defaultCenterLabel="Total equity"
            preserveSegments={preserveSegments}
            legendValueFormat={legendValueFormat}
            legendColumns={
              legendColumns === "auto" ? undefined : Number(legendColumns)
            }
            hideCenterLabel={hideCenterLabel}
            inlineDonutInset={layout === "inline" ? 4 : undefined}
            height={previewHeight}
          />
        </PreviewCanvas>
      </DocSection>

      <DocSection
        title="Customization"
        description="Switch layout, legend format, and segment bucketing behavior."
      >
        <div className="uitest-controls">
          <label className="uitest-field">
            <span className="uitest-field__label">Layout</span>
            <select
              className="uitest-input"
              value={layout}
              onChange={(event) =>
                setLayout(event.target.value as PortfolioEquityBreakdownChartLayout)
              }
            >
              <option value="radial">Radial</option>
              <option value="stacked">Stacked</option>
              <option value="inline">Inline</option>
            </select>
          </label>
          <label className="uitest-field">
            <span className="uitest-field__label">Legend value format</span>
            <select
              className="uitest-input"
              value={legendValueFormat}
              onChange={(event) =>
                setLegendValueFormat(event.target.value as "currency" | "percent")
              }
            >
              <option value="currency">Currency</option>
              <option value="percent">Percent</option>
            </select>
          </label>
          <label className="uitest-field">
            <span className="uitest-field__label">Legend columns</span>
            <select
              className="uitest-input"
              value={legendColumns}
              onChange={(event) => {
                const value = event.target.value;
                setLegendColumns(value === "auto" ? "auto" : Number(value));
              }}
            >
              <option value="auto">Auto</option>
              <option value="2">2</option>
              <option value="3">3</option>
            </select>
          </label>
          <label className="uitest-field uitest-field--checkbox">
            <input
              type="checkbox"
              checked={preserveSegments}
              onChange={(event) => setPreserveSegments(event.target.checked)}
            />
            <span className="uitest-field__label">Preserve segments (no bucketing)</span>
          </label>
          <label className="uitest-field uitest-field--checkbox">
            <input
              type="checkbox"
              checked={hideCenterLabel}
              onChange={(event) => setHideCenterLabel(event.target.checked)}
            />
            <span className="uitest-field__label">Hide center label</span>
          </label>
        </div>
        <PreviewCanvas minHeight={previewHeight}>
          <ChartPreview
            segments={segments}
            layout={layout}
            defaultCenterValue={formatCurrency(allocationTotal)}
            defaultCenterLabel="Total equity"
            preserveSegments={preserveSegments}
            legendValueFormat={legendValueFormat}
            legendColumns={
              legendColumns === "auto" ? undefined : Number(legendColumns)
            }
            hideCenterLabel={hideCenterLabel}
            inlineDonutInset={layout === "inline" ? 4 : undefined}
            height={previewHeight}
          />
        </PreviewCanvas>
      </DocSection>

      <DocSection
        title="Layouts"
        description="Radial (full SVG), stacked (donut + legend), and inline (title + donut + legend)."
      >
        <VariantGrid columns={1}>
          <VariantTile label="Radial — portfolio grid slot">
            <ChartPreview
              segments={DEMO_PORTFOLIO_SEGMENTS}
              layout="radial"
              height={320}
            />
          </VariantTile>
          <VariantTile label="Stacked — compact portfolio summary">
            <ChartPreview
              segments={DEMO_PORTFOLIO_SEGMENTS}
              layout="stacked"
              height={360}
            />
          </VariantTile>
          <VariantTile label="Inline — focused agent allocation">
            <ChartPreview
              segments={DEMO_PORTFOLIO_SEGMENTS}
              layout="inline"
              title="Allocation"
              defaultCenterValue={formatCurrency(allocationTotal)}
              defaultCenterLabel="Allocation"
              height={220}
            />
          </VariantTile>
        </VariantGrid>
      </DocSection>

      <DocSection
        title="Product contexts"
        description="Patterns from portfolio summary and agent asset preferences."
      >
        <VariantGrid columns={2}>
          <VariantTile label="Portfolio — dual inline donuts">
            <div
              className="portfolio-equity-donuts-row portfolio-equity-donuts-row--svg"
              style={{ height: 360 }}
            >
              <ChartPreview
                segments={DEMO_PORTFOLIO_SEGMENTS}
                layout="inline"
                title="Allocation"
                defaultCenterValue={formatCurrency(allocationTotal)}
                defaultCenterLabel="Allocation"
                height={170}
              />
              <ChartPreview
                segments={[
                  {
                    id: "focus",
                    label: "Focus agent",
                    value: 28_320,
                    color: "#38bdf8",
                  },
                  {
                    id: "fleet",
                    label: "Rest of fleet",
                    value: 41_280,
                    color: "#64748b",
                  },
                ]}
                layout="inline"
                title="vs Fleet"
                defaultCenterValue="40.7%"
                defaultCenterLabel="vs Fleet"
                height={170}
              />
            </div>
          </VariantTile>
          <VariantTile label="Agent — asset preferences (percent)">
            <ChartPreview
              segments={DEMO_ASSET_SEGMENTS}
              layout="inline"
              preserveSegments
              legendValueFormat="percent"
              legendColumns={3}
              hideCenterLabel
              inlineDonutInset={4}
              height={220}
            />
          </VariantTile>
        </VariantGrid>
      </DocSection>

      <DocSection
        title="Segment bucketing"
        description="Small slices roll into Other unless preserveSegments is set."
      >
        <VariantGrid columns={2}>
          <VariantTile label="Default bucketing (many segments)">
            <ChartPreview
              segments={DEMO_MANY_SEGMENTS}
              layout="stacked"
              height={360}
            />
          </VariantTile>
          <VariantTile label="Preserve all segments">
            <ChartPreview
              segments={DEMO_MANY_SEGMENTS}
              layout="stacked"
              preserveSegments
              height={360}
            />
          </VariantTile>
        </VariantGrid>
      </DocSection>
    </ComponentDocPage>
  );
}
