const NAVIGABLE_MARKET_IDS = new Set(["1", "2"]);

function ActivityLogPreview({
  entryCount,
  symbolNavigation,
  onSymbolClick,
}: {
  entryCount: number;
  symbolNavigation: boolean;
  onSymbolClick?: (marketId: string) => void;
}): JSX.Element {
  const entries = useMemo(() => {
    const built = buildFleetActivityLogEntries(DEMO_TRADES);
    return built.slice(0, entryCount);
  }, [entryCount]);

  return (
    <div className="agent-activity-log-scroll">
      <AgentActivityLogTimeline
        entries={entries}
        onSymbolClick={symbolNavigation ? onSymbolClick : undefined}
        isSymbolNavigable={
          symbolNavigation
            ? (marketId) => NAVIGABLE_MARKET_IDS.has(marketId)
            : undefined
        }
      />
    </div>
  );
}

export function AgentActivityLogTimelinePage(): JSX.Element {
  const [entryCount, setEntryCount] = useState(4);
  const [symbolNavigation, setSymbolNavigation] = useState(true);
  const [lastClickedMarketId, setLastClickedMarketId] = useState<string | null>(
    null,
  );

  const allEntries = useMemo(
    () => buildFleetActivityLogEntries(DEMO_TRADES),
    [],
  );

  return (
    <ComponentDocPage
      title="Agent activity log timeline"
      description="Fleet trade activity timeline with long/short badges, narrative segments, symbol links, and realized PnL coloring."
    >
      <DocSection
        title="Default preview"
        description="Latest-first timeline built from mock fleet trade events."
      >
        <PreviewCanvas minHeight={360}>
          <ActivityLogPreview
            entryCount={entryCount}
            symbolNavigation={symbolNavigation}
            onSymbolClick={setLastClickedMarketId}
          />
        </PreviewCanvas>
      </DocSection>

      <DocSection
        title="Customization"
        description="Trim visible entries and toggle symbol navigation."
      >
        <div className="uitest-controls">
          <label className="uitest-field">
            <span className="uitest-field__label">
              Entries ({entryCount} of {allEntries.length})
            </span>
            <input
              className="uitest-input"
              type="range"
              min={1}
              max={allEntries.length}
              value={entryCount}
              onChange={(event) => setEntryCount(Number(event.target.value))}
            />
          </label>
          <label className="uitest-field uitest-field--checkbox">
            <input
              type="checkbox"
              checked={symbolNavigation}
              onChange={(event) => setSymbolNavigation(event.target.checked)}
            />
            <span className="uitest-field__label">Symbol navigation</span>
          </label>
          {lastClickedMarketId ? (
            <p className="uitest-field__label">
              Last symbol click: market {lastClickedMarketId}
            </p>
          ) : null}
        </div>
        <PreviewCanvas minHeight={360}>
          <ActivityLogPreview
            entryCount={entryCount}
            symbolNavigation={symbolNavigation}
            onSymbolClick={setLastClickedMarketId}
          />
        </PreviewCanvas>
      </DocSection>

      <DocSection
        title="Symbol links"
        description="Navigable symbols render as buttons; static symbols render as plain text."
      >
        <VariantGrid columns={2}>
          <VariantTile label="Navigable symbols">
            <div className="agent-activity-log-scroll">
              <AgentActivityLogTimeline
                entries={allEntries.slice(0, 2)}
                onSymbolClick={() => undefined}
                isSymbolNavigable={(marketId) =>
                  NAVIGABLE_MARKET_IDS.has(marketId)
                }
              />
            </div>
          </VariantTile>
          <VariantTile label="Static symbols">
            <div className="agent-activity-log-scroll">
              <AgentActivityLogTimeline entries={allEntries.slice(0, 2)} />
            </div>
          </VariantTile>
        </VariantGrid>
      </DocSection>

      <DocSection
        title="PnL tones"
        description="Closing fills highlight realized PnL in long (profit) or short (loss) tones."
      >
        <VariantGrid columns={2}>
          <VariantTile label="Profitable close">
            <div className="agent-activity-log-scroll">
              <AgentActivityLogTimeline
                entries={allEntries.filter((entry) => entry.id === "evt-close-profit")}
              />
            </div>
          </VariantTile>
          <VariantTile label="Loss close">
            <div className="agent-activity-log-scroll">
              <AgentActivityLogTimeline
                entries={allEntries.filter((entry) => entry.id === "evt-close-loss")}
              />
            </div>
          </VariantTile>
        </VariantGrid>
      </DocSection>
    </ComponentDocPage>
  );
}
