function buildAgentTickerSpec(profile: (typeof mockAgentProfiles)[number]): TickerSpec {
  return {
    price: profile.price,
    minSizeLimit: 0.01,
    maxSizeLimit: 500,
  };
}

function buildAgentPickerMeta(profile: (typeof mockAgentProfiles)[number]): TickerPickerMeta {
  return {
    category: "agent",
    displayName: profile.name,
    tickerLabel: profile.ticker,
    deployer: profile.deployer ?? "mxm",
    leverage: profile.leverage ?? 20,
    change24h: profile.change24h,
    annFunding: profile.annFunding ?? 0,
    volume24h: profile.volume24hNumeric ?? 0,
    openInterest: profile.openInterest ?? 0,
    isSelectable: true,
    agentRoute: `/agents/${profile.id}`,
    showInPicker: true,
  };
}

function buildIndexTickerSpec(entry: (typeof LIVE_MAEX_INDEX_PERPS)[number]): TickerSpec {
  return {
    price: entry.price,
    minSizeLimit: 0.01,
    maxSizeLimit: 500,
  };
}

function buildIndexPickerMeta(entry: (typeof LIVE_MAEX_INDEX_PERPS)[number]): TickerPickerMeta {
  return {
    category: "index",
    displayName: entry.displayName,
    tickerLabel: entry.tickerLabel,
    deployer: entry.deployer,
    leverage: entry.leverage,
    change24h: entry.change24h,
    annFunding: entry.annFunding,
    volume24h: entry.volume24h,
    openInterest: entry.openInterest,
    isSelectable: entry.isSelectable,
    navRoute: entry.navRoute,
    showInPicker: true,
  };
}

const TICKER_SPECS: Record<MockTradingTicker, TickerSpec> = {
  ...LEGACY_TICKER_SPECS,
  ...Object.fromEntries(
    mockAgentProfiles.map((profile) => [
      profile.perpBaseAsset,
      buildAgentTickerSpec(profile),
    ]),
  ),
  ...Object.fromEntries(
    LIVE_MAEX_INDEX_PERPS.map((entry) => [
      entry.baseAsset,
      buildIndexTickerSpec(entry),
    ]),
  ),
} as Record<MockTradingTicker, TickerSpec>;

function getLegacyPickerCategory(ticker: string): TickerPickerCategory {
  if ((LEGACY_TRADFI_TICKERS as readonly string[]).includes(ticker)) {
    return "tradfi";
  }
  return "legacy";
}

const TICKER_PICKER_META: Record<MockTradingTicker, TickerPickerMeta> = {
  ...Object.fromEntries(
    (
      [...LEGACY_CRYPTO_TICKERS, ...LEGACY_TRADFI_TICKERS, "JELLY"] as readonly string[]
    ).map((ticker) => {
      const legacyMeta = LEGACY_TICKER_META[
        ticker as keyof typeof LEGACY_TICKER_META
      ] ?? {
        leverage: 20,
        change24h: 0,
        annFunding: 0,
        volume24h: 0,
        openInterest: 0,
      };
      return [
        ticker,
        {
          ...legacyMeta,
          category: getLegacyPickerCategory(ticker),
          isSelectable: true,
          showInPicker:
            "showInPicker" in legacyMeta
              ? legacyMeta.showInPicker ?? true
              : true,
        } satisfies TickerPickerMeta,
      ];
    }),
  ),
  ...Object.fromEntries(
    CRYPTO_PICKER_MAJORS.map((ticker) => [
      ticker,
      {
        ...(LEGACY_TICKER_META[ticker] ?? {
          leverage: 50,
          change24h: 0,
          annFunding: 0,
          volume24h: 0,
          openInterest: 0,
        }),
        category: "crypto",
        isSelectable: true,
        showInPicker: true,
      } satisfies TickerPickerMeta,
    ]),
  ),
  ...Object.fromEntries(
    mockAgentProfiles.map((profile) => [
      profile.perpBaseAsset,
      buildAgentPickerMeta(profile),
    ]),
  ),
  ...Object.fromEntries(
    LIVE_MAEX_INDEX_PERPS.map((entry) => [
      entry.baseAsset,
      buildIndexPickerMeta(entry),
    ]),
  ),
} as Record<MockTradingTicker, TickerPickerMeta>;

export function getTickerPickerMeta(ticker: string): TickerPickerMeta {
  const normalized = ticker.toUpperCase().replace(/-USDT$/, "") as MockTradingTicker;
  return (
    TICKER_PICKER_META[normalized] ?? {
      category: "legacy",
      leverage: 20,
      isBeta: true,
      change24h: 0,
      annFunding: 0,
      volume24h: 0,
      openInterest: 0,
      isSelectable: true,
      showInPicker: true,
    }
  );
}

/** @deprecated Use getTickerPickerMeta */
export function getTickerDisplayMeta(ticker: string): TickerPickerMeta {
  return getTickerPickerMeta(ticker);
}

function buildMockMarket(ticker: MockTradingTicker, index: number): MockMarket {
  const spec = TICKER_SPECS[ticker];
  const pair = `${ticker}-USDT`;
  return {
    marketIndex: String(index + 1),
    symbol: pair,
    moniker: pair,
    baseAsset: ticker,
    quoteAsset: "USDT",
    status: "MARKET_STATUS_ACTIVE",
    maxSizeLimit: spec.maxSizeLimit,
    minSizeLimit: spec.minSizeLimit,
  };
}

export const mockMarkets: MockMarket[] = MOCK_TRADING_TICKERS.map(buildMockMarket);

/** Resolve catalog marketIndex (1-based) for a mock trading ticker. */
export function getMockMarketIndex(ticker: MockTradingTicker): string {
  const idx = MOCK_TRADING_TICKERS.indexOf(ticker);
  if (idx < 0) throw new Error(`Unknown ticker: ${ticker}`);
  return String(idx + 1);
}

