/** Spot-only assets (bank balances) that are not perp tickers. */
export const MOCK_SPOT_ASSET_PRICES_USD: Readonly<Record<string, number>> = {
  /** Native platform token — not listed in MOCK_TRADING_TICKERS. */
  MORM: 0.1,
};

/**
 * USD mark for portfolio idle-spot rows. Stablecoins = $1; spot-only assets use
 * MOCK_SPOT_ASSET_PRICES_USD; tradable tickers use TICKER_SPECS. Unknown assets
 * return 0 (never fall back to BTC — that inflated MORM balances).
 */
export function getMockPortfolioAssetPriceUsd(ticker: string): number {
  const normalized = ticker.toUpperCase().replace(/-USDT$/, "");
  if (normalized === "USDC" || normalized === "USDT") return 1;
  const spotPrice = MOCK_SPOT_ASSET_PRICES_USD[normalized];
  if (spotPrice != null) return spotPrice;
  const spec = TICKER_SPECS[normalized as MockTradingTicker];
  return spec?.price ?? 0;
}

export function getMockMarketPriceByTicker(ticker: string): number {
  const normalized = ticker.toUpperCase().replace(/-USDT$/, "");
  const spec = TICKER_SPECS[normalized as MockTradingTicker];
  return spec?.price ?? TICKER_SPECS.BTC.price;
}

export function getMockBalance(asset: string): number {
  return mockWalletState.balances[asset.toUpperCase()] ?? 0;
}

