import "./layout.css";
import React from "react";
export interface ErrorMessageProps {
  error: string;
}

export interface EmptyMessageProps {
  message: string;
}

export interface WarningMessageProps {
  message: string;
}

/**
 * Message fragment for error state
 */
export function ErrorMessage({ error }: ErrorMessageProps): JSX.Element {
  return <div className="message error">Error: {error}</div>;
}

/**
 * Message fragment for empty state
 */
export function EmptyMessage({ message }: EmptyMessageProps): JSX.Element {
  return <div className="message empty">{message}</div>;
}

/**
 * Message fragment for warning state
 */
export function WarningMessage({ message }: WarningMessageProps): JSX.Element {
  return <div className="message warning">{message}</div>;
}
