import type { TabSectionTabId } from "../tables/TabSection";

export const HIGH_AGENCY_PINNED_TABS: TabSectionTabId[] = ["agentTasks"];

export const HIGH_AGENCY_OPTIONAL_TABS: TabSectionTabId[] = [
  "buckets",
  "positions",
  "tradeHistory",
  "openOrders",
  "history",
  "fundingHistory",
  "memoryAudit",
];

export const DEFAULT_HIGH_AGENCY_OPTIONAL_TABS: TabSectionTabId[] = [
  "buckets",
  "positions",
];

const OPTIONAL_TAB_SET = new Set<string>(HIGH_AGENCY_OPTIONAL_TABS);

export interface HighAgencyTabsPrefs {
  visibleOptionalTabs: TabSectionTabId[];
}

export const DEFAULT_HIGH_AGENCY_TABS_PREFS: HighAgencyTabsPrefs = {
  visibleOptionalTabs: DEFAULT_HIGH_AGENCY_OPTIONAL_TABS,
};

/** Filter to valid optional tab IDs, dedupe, preserve order. Allows empty. */
export function sanitizeHighAgencyOptionalTabs(
  input: unknown,
): TabSectionTabId[] {
  if (!Array.isArray(input)) return [];

  const seen = new Set<string>();
  const sanitized: TabSectionTabId[] = [];

  for (const item of input) {
    if (typeof item !== "string" || !OPTIONAL_TAB_SET.has(item) || seen.has(item)) {
      continue;
    }
    seen.add(item);
    sanitized.push(item as TabSectionTabId);
  }

  return sanitized;
}

/** Load/migrate prefs: missing or non-array input falls back to default. */
export function normalizeHighAgencyOptionalTabs(
  input: unknown,
): TabSectionTabId[] {
  if (!Array.isArray(input)) {
    return [...DEFAULT_HIGH_AGENCY_OPTIONAL_TABS];
  }
  return sanitizeHighAgencyOptionalTabs(input);
}

export function buildHighAgencyTabOrder(
  visibleOptional: TabSectionTabId[],
): TabSectionTabId[] {
  const optional = sanitizeHighAgencyOptionalTabs(visibleOptional);
  return [...HIGH_AGENCY_PINNED_TABS, ...optional];
}

export function toggleHighAgencyOptionalTab(
  visibleOptional: TabSectionTabId[],
  tabId: TabSectionTabId,
  enabled: boolean,
): TabSectionTabId[] {
  if (!OPTIONAL_TAB_SET.has(tabId)) return visibleOptional;

  if (enabled) {
    if (visibleOptional.includes(tabId)) return visibleOptional;
    return [...visibleOptional, tabId];
  }

  return visibleOptional.filter((id) => id !== tabId);
}

export function moveHighAgencyOptionalTab(
  visibleOptional: TabSectionTabId[],
  tabId: TabSectionTabId,
  direction: "up" | "down",
): TabSectionTabId[] {
  const index = visibleOptional.indexOf(tabId);
  if (index === -1) return visibleOptional;

  const swapIndex = direction === "up" ? index - 1 : index + 1;
  if (swapIndex < 0 || swapIndex >= visibleOptional.length) {
    return visibleOptional;
  }

  const next = [...visibleOptional];
  [next[index], next[swapIndex]] = [next[swapIndex]!, next[index]!];
  return next;
}

export function getHighAgencyTabsDisplayOrder(
  visibleOptional: TabSectionTabId[],
): TabSectionTabId[] {
  const visible = sanitizeHighAgencyOptionalTabs(visibleOptional);
  const hidden = HIGH_AGENCY_OPTIONAL_TABS.filter((id) => !visible.includes(id));
  return [...visible, ...hidden];
}
