import { toNumberFromSatoshi } from "../sdk/utils/math";
import { normalizeTimestamp } from "../sdk/utils/time";

export interface UserWalletTradeNotify {
  marketId: string;
  tradeId: string;
  price: number;
  quantity: number;
  timestamp: number;
  side: "buy" | "sell";
}

export interface TradeWithAddresses {
  tradeId?: string;
  price: string;
  quantity: string;
  timestamp: string | number;
  buyAddress?: string;
  sellAddress?: string;
}

export function addressesMatch(a?: string, b?: string): boolean {
  if (!a || !b) return false;
  return a.toLowerCase() === b.toLowerCase();
}

export function buildUserWalletTradeNotify(
  marketId: string,
  trade: TradeWithAddresses,
  walletAddress?: string,
): UserWalletTradeNotify | null {
  if (!walletAddress?.trim()) return null;

  const wallet = walletAddress.trim();
  const isBuyer = addressesMatch(trade.buyAddress, wallet);
  const isSeller = addressesMatch(trade.sellAddress, wallet);
  if (!isBuyer && !isSeller) return null;

  return {
    marketId,
    tradeId: trade.tradeId ?? "",
    price: toNumberFromSatoshi(trade.price),
    quantity: toNumberFromSatoshi(trade.quantity),
    timestamp: normalizeTimestamp(trade.timestamp),
    side: isBuyer ? "buy" : "sell",
  };
}
