import React, {
  createContext,
  useCallback,
  useContext,
  useMemo,
  useRef,
  useState,
  type ReactNode,
} from "react";
import { useLocation, useNavigate } from "react-router-dom";
import { toast } from "sonner";

import { getAppRoute } from "../../routes";
import { hasSeenVaultTour } from "../../../offline/tutorials/vaultTourStorage";
import { isDesktopTourBreakpoint } from "../welcome-tour/constants";
import type { CreateVaultTourStepId } from "./constants";
import { CREATE_VAULT_TOUR_PREFILL } from "./constants";
import { inferTourBreakpointFromWidth } from "../vault-tour/vaultTourFlowSync";

export interface StartCreateVaultTourOptions {
  skipVaultTourPrerequisite?: boolean;
  skipWalletCheck?: boolean;
}

export interface CreateVaultTourModalState {
  isOpen: boolean;
  step: CreateVaultTourStepId;
  showSuccess?: boolean;
}

export interface CreateVaultTourContextValue {
  runTour: boolean;
  stepIndex: number;
  currentBreakpoint: string;
  pathname: string;
  modalState: CreateVaultTourModalState;
  tourPrefill: typeof CREATE_VAULT_TOUR_PREFILL;
  startCreateVaultTour: (options?: StartCreateVaultTourOptions) => void;
  stopTour: () => void;
  onTourComplete: () => void;
  setStepIndex: (index: number | ((prev: number) => number)) => void;
  notifyModalState: (state: CreateVaultTourModalState) => void;
  registerTourMutex: (fn: () => void) => () => void;
  registerBreakpoint: (getter: () => string) => () => void;
  registerWallet: (getter: () => string | null) => () => void;
  registerOpenCreateVault: (fn: (prefill: typeof CREATE_VAULT_TOUR_PREFILL) => void) => () => void;
  registerSetModalStep: (fn: (step: CreateVaultTourStepId) => void) => () => void;
  openCreateVaultForTour: () => void;
  setModalStepForTour: (step: CreateVaultTourStepId) => void;
}

const defaultModalState: CreateVaultTourModalState = {
  isOpen: false,
  step: "details",
};

const CreateVaultTourContext = createContext<CreateVaultTourContextValue | undefined>(
  undefined,
);

export interface CreateVaultTourProviderProps {
  children: ReactNode;
  onCreateVaultTourSeen?: () => void;
}

export function CreateVaultTourProvider({
  children,
  onCreateVaultTourSeen,
}: CreateVaultTourProviderProps): JSX.Element {
  const navigate = useNavigate();
  const location = useLocation();
  const [runTour, setRunTour] = useState(false);
  const [stepIndex, setStepIndex] = useState(0);
  const [currentBreakpoint, setCurrentBreakpointState] = useState("lg");
  const [modalState, setModalState] = useState<CreateVaultTourModalState>(
    defaultModalState,
  );

  const tourMutexRef = useRef<(() => void) | null>(null);
  const breakpointRef = useRef<(() => string) | null>(null);
  const walletGetterRef = useRef<(() => string | null) | null>(null);
  const openCreateVaultRef = useRef<
    ((prefill: typeof CREATE_VAULT_TOUR_PREFILL) => void) | null
  >(null);
  const setModalStepRef = useRef<((step: CreateVaultTourStepId) => void) | null>(
    null,
  );

  const stopTour = useCallback(() => {
    setRunTour(false);
    setStepIndex(0);
    setModalState(defaultModalState);
  }, []);

  const onTourComplete = useCallback(() => {
    setRunTour(false);
    setStepIndex(0);
    setModalState(defaultModalState);
    onCreateVaultTourSeen?.();
    toast.success("Create vault tour complete", {
      description: "Your demo vault is ready — explore buckets on a protocol vault anytime.",
    });
  }, [onCreateVaultTourSeen]);

  const startCreateVaultTour = useCallback(
    (options?: StartCreateVaultTourOptions) => {
      const wallet = walletGetterRef.current?.()?.trim();
      if (!options?.skipWalletCheck && !wallet) {
        toast.error("Connect wallet first", {
          description: "Connect your wallet before starting the create vault tour.",
        });
        return;
      }

      if (!options?.skipVaultTourPrerequisite && !hasSeenVaultTour()) {
        toast.info("Complete the vault layout tour first", {
          description: "Start Understand vaults from the demo guide (?).",
        });
        return;
      }

      const breakpoint =
        breakpointRef.current?.() ??
        (typeof window !== "undefined"
          ? inferTourBreakpointFromWidth(window.innerWidth)
          : currentBreakpoint);

      if (!isDesktopTourBreakpoint(breakpoint)) {
        toast.info(
          "Create vault tour is available on desktop and tablet view. Widen your window to explore step-by-step.",
        );
        return;
      }

      tourMutexRef.current?.();
      setStepIndex(0);
      setModalState(defaultModalState);
      setRunTour(true);
      navigate(getAppRoute("vault"));
    },
    [currentBreakpoint, navigate],
  );

  const notifyModalState = useCallback((state: CreateVaultTourModalState) => {
    setModalState((prev) => {
      if (
        prev.isOpen === state.isOpen &&
        prev.step === state.step &&
        Boolean(prev.showSuccess) === Boolean(state.showSuccess)
      ) {
        return prev;
      }
      return state;
    });
  }, []);

  const registerTourMutex = useCallback((fn: () => void) => {
    tourMutexRef.current = fn;
    return () => {
      if (tourMutexRef.current === fn) {
        tourMutexRef.current = null;
      }
    };
  }, []);

  const registerBreakpoint = useCallback((getter: () => string) => {
    breakpointRef.current = getter;
    setCurrentBreakpointState(getter());
    return () => {
      if (breakpointRef.current === getter) {
        breakpointRef.current = null;
      }
    };
  }, []);

  const registerWallet = useCallback((getter: () => string | null) => {
    walletGetterRef.current = getter;
    return () => {
      if (walletGetterRef.current === getter) {
        walletGetterRef.current = null;
      }
    };
  }, []);

  const registerOpenCreateVault = useCallback(
    (fn: (prefill: typeof CREATE_VAULT_TOUR_PREFILL) => void) => {
      openCreateVaultRef.current = fn;
      return () => {
        if (openCreateVaultRef.current === fn) {
          openCreateVaultRef.current = null;
        }
      };
    },
    [],
  );

  const registerSetModalStep = useCallback((fn: (step: CreateVaultTourStepId) => void) => {
    setModalStepRef.current = fn;
    return () => {
      if (setModalStepRef.current === fn) {
        setModalStepRef.current = null;
      }
    };
  }, []);

  const openCreateVaultForTour = useCallback(() => {
    openCreateVaultRef.current?.(CREATE_VAULT_TOUR_PREFILL);
  }, []);

  const setModalStepForTour = useCallback((step: CreateVaultTourStepId) => {
    setModalStepRef.current?.(step);
  }, []);

  const value = useMemo(
    (): CreateVaultTourContextValue => ({
      runTour,
      stepIndex,
      currentBreakpoint,
      pathname: location.pathname,
      modalState,
      tourPrefill: CREATE_VAULT_TOUR_PREFILL,
      startCreateVaultTour,
      stopTour,
      onTourComplete,
      setStepIndex,
      notifyModalState,
      registerTourMutex,
      registerBreakpoint,
      registerWallet,
      registerOpenCreateVault,
      registerSetModalStep,
      openCreateVaultForTour,
      setModalStepForTour,
    }),
    [
      runTour,
      stepIndex,
      currentBreakpoint,
      location.pathname,
      modalState,
      startCreateVaultTour,
      stopTour,
      onTourComplete,
      notifyModalState,
      registerTourMutex,
      registerBreakpoint,
      registerWallet,
      registerOpenCreateVault,
      registerSetModalStep,
      openCreateVaultForTour,
      setModalStepForTour,
    ],
  );

  return (
    <CreateVaultTourContext.Provider value={value}>
      {children}
    </CreateVaultTourContext.Provider>
  );
}

export function useCreateVaultTour(): CreateVaultTourContextValue {
  const ctx = useContext(CreateVaultTourContext);
  if (!ctx) {
    throw new Error("useCreateVaultTour must be used within CreateVaultTourProvider");
  }
  return ctx;
}

export function useOptionalCreateVaultTour(): CreateVaultTourContextValue | undefined {
  return useContext(CreateVaultTourContext);
}
