import { useState } from "react";

import {
  TabLayoutHeaderToolBar,
  type TabLayoutHeaderToolBarTab,
} from "@mormlayer/components/smartlayout/tab-layout-header-toolbar";
import "@mormlayer/components/smartlayout/layout.css";
import "@mormlayer/components/tables/TabSection.css";

import { ComponentDocPage } from "../layout/ComponentDocPage";
import { DocSection } from "../layout/DocSection";
import { PreviewCanvas } from "../layout/PreviewCanvas";
import { VariantGrid, VariantTile } from "../layout/VariantGrid";

const DEFAULT_TABS: TabLayoutHeaderToolBarTab[] = [
  { id: "positions", label: "Positions" },
  { id: "openOrders", label: "Open Orders", shortLabel: "Orders" },
  { id: "tradeHistory", label: "Trade History", shortLabel: "History" },
  { id: "balances", label: "Balances" },
];

const STAKING_TABS: TabLayoutHeaderToolBarTab[] = [
  { id: "rewards", label: "Rewards" },
  { id: "activity", label: "Activity" },
  {
    id: "pending",
    label: "Pending Unstakes",
    shortLabel: "Pending",
    badgeCount: 3,
  },
  { id: "delegate", label: "Delegate" },
];

const VAULT_TABS: TabLayoutHeaderToolBarTab[] = [
  { id: "about", label: "About" },
  { id: "yourPerf", label: "Your Perf." },
  { id: "analystVerdict", label: "Analyst Verdict", shortLabel: "Verdict" },
];

function MockLeadingToggle(): JSX.Element {
  return (
    <button
      type="button"
      className="raw-pro-data-toggle-segment is-active"
      aria-label="Chart view"
    >
      Chart
    </button>
  );
}

function MockHeaderActions(): JSX.Element {
  return (
    <div className="uitest-tab-toolbar-actions">
      <button type="button" className="uitest-tab-toolbar-actions__btn">
        Filters
      </button>
      <button
        type="button"
        className="uitest-tab-toolbar-actions__btn uitest-tab-toolbar-actions__btn--primary"
      >
        Export
      </button>
    </div>
  );
}

export function TabLayoutHeaderToolBarPage(): JSX.Element {
  const [activeTabId, setActiveTabId] = useState("positions");
  const [showBadge, setShowBadge] = useState(false);
  const [badgePulse, setBadgePulse] = useState(false);
  const [showLeading, setShowLeading] = useState(false);
  const [showActions, setShowActions] = useState(true);
  const [scrollActiveTabIntoView, setScrollActiveTabIntoView] = useState(false);
  const [narrowStrip, setNarrowStrip] = useState(false);

  const tabs = DEFAULT_TABS.map((tab) =>
    tab.id === "openOrders" && showBadge
      ? {
          ...tab,
          badgeCount: 5,
          ...(badgePulse ? { badgePulse: true } : {}),
        }
      : tab,
  );

  return (
    <ComponentDocPage
      title="Tab layout header toolbar"
      description="Shared tab section header — animated underline, compact labels, badges, leading control, and trailing actions."
    >
      <DocSection
        title="Default preview"
        description="Portfolio-style tab strip with four tabs and trailing actions."
      >
        <PreviewCanvas minHeight={52}>
          <div className="tab-section-root uitest-tab-toolbar-shell">
            <TabLayoutHeaderToolBar
              tabs={DEFAULT_TABS}
              activeTabId="positions"
              onTabChange={() => {}}
            >
              <MockHeaderActions />
            </TabLayoutHeaderToolBar>
          </div>
        </PreviewCanvas>
      </DocSection>

      <DocSection
        title="Customization"
        description="Toggle active tab, badges, leading slot, actions, scroll-into-view, and narrow strip width."
      >
        <div className="uitest-controls">
          <label className="uitest-field">
            <span className="uitest-field__label">Active tab</span>
            <select
              className="uitest-input"
              value={activeTabId}
              onChange={(e) => setActiveTabId(e.target.value)}
            >
              {tabs.map((tab) => (
                <option key={tab.id} value={tab.id}>
                  {tab.label}
                </option>
              ))}
            </select>
          </label>
          <label className="uitest-field uitest-field--checkbox">
            <input
              type="checkbox"
              checked={showBadge}
              onChange={(e) => setShowBadge(e.target.checked)}
            />
            <span className="uitest-field__label">Badge on Open Orders</span>
          </label>
          <label className="uitest-field uitest-field--checkbox">
            <input
              type="checkbox"
              checked={badgePulse}
              onChange={(e) => setBadgePulse(e.target.checked)}
              disabled={!showBadge}
            />
            <span className="uitest-field__label">Pulsing badge</span>
          </label>
          <label className="uitest-field uitest-field--checkbox">
            <input
              type="checkbox"
              checked={showLeading}
              onChange={(e) => setShowLeading(e.target.checked)}
            />
            <span className="uitest-field__label">Leading control</span>
          </label>
          <label className="uitest-field uitest-field--checkbox">
            <input
              type="checkbox"
              checked={showActions}
              onChange={(e) => setShowActions(e.target.checked)}
            />
            <span className="uitest-field__label">Trailing actions</span>
          </label>
          <label className="uitest-field uitest-field--checkbox">
            <input
              type="checkbox"
              checked={scrollActiveTabIntoView}
              onChange={(e) => setScrollActiveTabIntoView(e.target.checked)}
            />
            <span className="uitest-field__label">Scroll active tab into view</span>
          </label>
          <label className="uitest-field uitest-field--checkbox">
            <input
              type="checkbox"
              checked={narrowStrip}
              onChange={(e) => setNarrowStrip(e.target.checked)}
            />
            <span className="uitest-field__label">Narrow strip (compact labels)</span>
          </label>
        </div>
        <PreviewCanvas minHeight={52}>
          <div
            className={`tab-section-root uitest-tab-toolbar-shell${
              narrowStrip ? " uitest-tab-toolbar-shell--narrow" : ""
            }`}
          >
            <TabLayoutHeaderToolBar
              tabs={tabs}
              activeTabId={activeTabId}
              onTabChange={setActiveTabId}
              scrollActiveTabIntoView={scrollActiveTabIntoView}
              leading={showLeading ? <MockLeadingToggle /> : undefined}
            >
              {showActions ? <MockHeaderActions /> : null}
            </TabLayoutHeaderToolBar>
          </div>
        </PreviewCanvas>
      </DocSection>

      <DocSection
        title="Variants"
        description="Common tab toolbar configurations across terminal pages."
      >
        <VariantGrid columns={1}>
          <VariantTile label="Portfolio — positions strip">
            <div className="tab-section-root uitest-tab-toolbar-shell">
              <TabLayoutHeaderToolBar
                tabs={DEFAULT_TABS}
                activeTabId="positions"
                onTabChange={() => {}}
              >
                <MockHeaderActions />
              </TabLayoutHeaderToolBar>
            </div>
          </VariantTile>
          <VariantTile label="Staking — badge on pending tab">
            <div className="tab-section-root uitest-tab-toolbar-shell">
              <TabLayoutHeaderToolBar
                tabs={STAKING_TABS}
                activeTabId="activity"
                onTabChange={() => {}}
              />
            </div>
          </VariantTile>
          <VariantTile label="Vault detail — three mode tabs">
            <div className="tab-section-root uitest-tab-toolbar-shell">
              <TabLayoutHeaderToolBar
                tabs={VAULT_TABS}
                activeTabId="yourPerf"
                onTabChange={() => {}}
              />
            </div>
          </VariantTile>
          <VariantTile label="Trade mobile — leading chart toggle">
            <div className="tab-section-root uitest-tab-toolbar-shell uitest-tab-toolbar-shell--narrow">
              <TabLayoutHeaderToolBar
                tabs={[
                  { id: "manual", label: "Manual" },
                  { id: "intent", label: "Intent" },
                ]}
                activeTabId="manual"
                onTabChange={() => {}}
                leading={<MockLeadingToggle />}
              />
            </div>
          </VariantTile>
          <VariantTile label="Intents — pulsing attention badge">
            <div className="tab-section-root uitest-tab-toolbar-shell">
              <TabLayoutHeaderToolBar
                tabs={[
                  { id: "overview", label: "Overview" },
                  {
                    id: "intents",
                    label: "Intents",
                    badgeCount: 2,
                    badgePulse: true,
                  },
                  { id: "config", label: "Config" },
                ]}
                activeTabId="overview"
                onTabChange={() => {}}
              />
            </div>
          </VariantTile>
        </VariantGrid>
      </DocSection>
    </ComponentDocPage>
  );
}
