import React, {
  useCallback,
  useRef,
  useEffect,
  useLayoutEffect,
  useState,
  useMemo,
} from "react";
import { useOrderbook } from "../../hooks/useOrderbook";
import { useEnhancedOrderbook } from "../../hooks/useEnhancedOrderbook";
import type { EnhancementConfig } from "../../utils/orderbookEnhancement";
import { formatOrderbookPrice, formatSize } from "../../sdk/utils/display";
import {
  clampScrollTop,
  computeRestScrollTopFromLayout,
  computeScrollPadding,
  computeSideCanvasHeight,
  createCubicBezierEasing,
  measureRestScrollTop,
  measureSpreadDrift,
} from "./orderbooktool";
import {
  ErrorMessage,
  EmptyMessage,
  StatusIndicator,
  LayoutHeader,
} from "../smartlayout";
import MorpheumInlineLoading from "../ui/MorpheumInlineLoading";
import {
  DEFAULT_HEIGHT_ORDERBOOK,
  DEFAULT_MAX_DEPTH,
} from "../../constants";
import "../smartlayout/layout.css";
import "./orderbookTradesPanel.css";
import { AskLevelFragment, BidLevelFragment } from "./OrderbookLevelFragments";
import OrderbookDepthTooltip from "./OrderbookDepthTooltip";
import {
  computeOrderbookHoverMetrics,
} from "./orderbookHoverMetrics";
import { resolveOrderbookAssets } from "./orderbookAssets";
import type { OrderbookDepthTooltipPlacement } from "./orderbookDepthTooltipLayout";
import { SubscriptionClient } from "../../sdk";
import { useSubscription } from "../../context/SubscriptionContext";

interface Orderbook002Props {
  baseURL: string;
  /** Optional: when inside SubscriptionProvider, hook uses context. */
  subscriptionClient?: SubscriptionClient;
  marketId: string;
  maxDepth?: number;
  height?: string;
  onPriceClick?: (price: number) => void;
  /**
   * Optional enhancement config. When undefined or config.enabled is false, enhancements are off.
   * Single source of truth: no separate "enhancementsEnabled" prop.
   */
  enhancementConfig?: EnhancementConfig;
  /** When false, suppresses flash highlight on size changes. Defaults to true. */
  animationEnabled?: boolean;
  /** Tooltip opens toward chart; auto flips based on panel screen position. */
  tooltipPlacement?: OrderbookDepthTooltipPlacement;
}

type HoveredOrderbookLevel = {
  side: "ask" | "bid";
  index: number;
  anchorEl: HTMLElement;
};

const FOOTER_EMA_ALPHA = 0.15;
const SPREAD_DRIFT_TOLERANCE_PX = 0.5;

function Orderbook002({
  baseURL,
  subscriptionClient: subscriptionClientProp,
  marketId,
  maxDepth = DEFAULT_MAX_DEPTH,
  height = DEFAULT_HEIGHT_ORDERBOOK,
  onPriceClick,
  enhancementConfig,
  animationEnabled = true,
  tooltipPlacement = "auto",
}: Orderbook002Props): JSX.Element {
  const { client: contextClient } = useSubscription();
  const subscriptionClient = subscriptionClientProp ?? contextClient;

  const raw = useOrderbook({
    baseURL,
    ...(subscriptionClient != null && { subscriptionClient }),
    marketId,
    maxDepth,
  });

  const { asks, bids, spread, loading, error, isConnected, wsError } =
    useEnhancedOrderbook(
      {
        asks: raw.asks,
        bids: raw.bids,
        spread: raw.spread,
        loading: raw.loading,
        error: raw.error,
        isConnected: raw.isConnected,
        wsError: raw.wsError,
      },
      enhancementConfig ?? { enabled: false },
      maxDepth,
    );

  const midPrice = raw.midPrice;

  const orderbookSectionRef = useRef<HTMLDivElement>(null);
  const orderbookContentRef = useRef<HTMLDivElement>(null);
  const scrollBodyRef = useRef<HTMLDivElement>(null);
  const askSlotRef = useRef<HTMLDivElement>(null);
  const bidSlotRef = useRef<HTMLDivElement>(null);
  const spreadRef = useRef<HTMLDivElement>(null);
  const animationFrameRef = useRef<number | null>(null);
  const isAnimatingRef = useRef<boolean>(false);
  const isProgrammaticScrollRef = useRef<boolean>(false);
  const isPanningRef = useRef<boolean>(false);
  const panStartYRef = useRef<number>(0);
  const panStartScrollTopRef = useRef<number>(0);
  const restScrollTopRef = useRef<number | null>(null);
  const mousePanCleanupRef = useRef<(() => void) | null>(null);
  const layoutSignatureRef = useRef<string>("");
  const hasCenteredOnceRef = useRef<boolean>(false);
  const layoutRetryFrameRef = useRef<number | null>(null);
  const syncScrollLayoutRef = useRef<() => boolean>(() => false);

  const [isSpreadPanning, setIsSpreadPanning] = useState(false);
  const [hoveredLevel, setHoveredLevel] = useState<HoveredOrderbookLevel | null>(
    null,
  );

  const orderbookAssets = useMemo(
    () => resolveOrderbookAssets(marketId),
    [marketId],
  );

  const hoverMetrics = useMemo(() => {
    if (!hoveredLevel || midPrice <= 0) return null;
    return computeOrderbookHoverMetrics(
      hoveredLevel.side,
      hoveredLevel.index,
      asks,
      bids,
      midPrice,
    );
  }, [hoveredLevel, asks, bids, midPrice]);

  const handleAskRowHover = useCallback((index: number, el: HTMLElement) => {
    setHoveredLevel({ side: "ask", index, anchorEl: el });
  }, []);

  const handleBidRowHover = useCallback((index: number, el: HTMLElement) => {
    setHoveredLevel({ side: "bid", index, anchorEl: el });
  }, []);

  const handleRowLeave = useCallback(() => {
    setHoveredLevel(null);
  }, []);

  const lastAskCumulative =
    asks.length > 0
      ? (asks[asks.length - 1]?.cumulative ?? 0)
      : 0;
  const lastBidCumulative =
    bids.length > 0
      ? (bids[bids.length - 1]?.cumulative ?? 0)
      : 0;

  const formatPriceMemo = formatOrderbookPrice;
  const formatSizeMemo = formatSize;

  const getAskDepthPercentage = useCallback(
    (depthValue: number): number => {
      if (lastAskCumulative === 0) return 0;
      return (depthValue / lastAskCumulative) * 100;
    },
    [lastAskCumulative],
  );

  const getBidDepthPercentage = useCallback(
    (cumulative: number): number => {
      if (lastBidCumulative === 0) return 0;
      return (cumulative / lastBidCumulative) * 100;
    },
    [lastBidCumulative],
  );

  const canCenterSpread =
    spread > 0 && asks.length > 0 && bids.length > 0;

  const scheduleLayoutRetry = useCallback(() => {
    if (layoutRetryFrameRef.current !== null) return;
    layoutRetryFrameRef.current = requestAnimationFrame(() => {
      layoutRetryFrameRef.current = null;
      syncScrollLayoutRef.current();
    });
  }, []);

  const syncScrollLayout = useCallback((): boolean => {
    if (isPanningRef.current || isAnimatingRef.current) return false;

    const section = orderbookSectionRef.current;
    const scrollBody = scrollBodyRef.current;
    const askSlot = askSlotRef.current;
    const bidSlot = bidSlotRef.current;
    const spreadEl = spreadRef.current;
    if (!section || !scrollBody || !askSlot || !bidSlot || !spreadEl) {
      scheduleLayoutRetry();
      return false;
    }

    const viewportH = section.clientHeight;
    if (viewportH === 0) {
      scheduleLayoutRetry();
      return false;
    }

    const spreadH = spreadEl.getBoundingClientRect().height;
    if (spreadH === 0) {
      scheduleLayoutRetry();
      return false;
    }

    const canvasH = computeSideCanvasHeight(viewportH);

    askSlot.style.height = `${canvasH}px`;
    bidSlot.style.height = `${canvasH}px`;

    const { paddingTop, paddingBottom, panSlack } = computeScrollPadding(
      viewportH,
      canvasH,
      canvasH,
      spreadH,
    );

    scrollBody.style.paddingTop = `${paddingTop}px`;
    scrollBody.style.paddingBottom = `${paddingBottom}px`;
    void scrollBody.offsetHeight;

    const signature = `${canvasH}|${viewportH}|${spreadH}|${panSlack}`;
    const layoutChanged = signature !== layoutSignatureRef.current;

    if (!layoutChanged && hasCenteredOnceRef.current) {
      return true;
    }

    const rest = computeRestScrollTopFromLayout(
      viewportH,
      canvasH,
      spreadH,
      panSlack,
    );

    isProgrammaticScrollRef.current = true;
    section.scrollTop = clampScrollTop(section, rest);

    for (let attempt = 0; attempt < 5; attempt++) {
      const drift = measureSpreadDrift(section, spreadEl);
      if (Math.abs(drift) < SPREAD_DRIFT_TOLERANCE_PX) break;
      const next = clampScrollTop(section, section.scrollTop + drift);
      if (Math.abs(next - section.scrollTop) < 0.01) break;
      section.scrollTop = next;
    }

    const finalDrift = measureSpreadDrift(section, spreadEl);

    requestAnimationFrame(() => {
      isProgrammaticScrollRef.current = false;
    });

    if (Math.abs(finalDrift) < SPREAD_DRIFT_TOLERANCE_PX) {
      layoutSignatureRef.current = signature;
      restScrollTopRef.current = section.scrollTop;
      hasCenteredOnceRef.current = true;
      return true;
    }

    scheduleLayoutRetry();
    return false;
  }, [scheduleLayoutRetry]);

  syncScrollLayoutRef.current = syncScrollLayout;

  const cancelSnapAnimation = useCallback(() => {
    if (isAnimatingRef.current && animationFrameRef.current) {
      cancelAnimationFrame(animationFrameRef.current);
      animationFrameRef.current = null;
      isAnimatingRef.current = false;
      isProgrammaticScrollRef.current = false;
    }
  }, []);

  const smoothScrollTo = useCallback(
    (
      content: HTMLElement,
      targetScroll: number,
      currentScroll: number,
    ): void => {
      if (isAnimatingRef.current) return;

      const clampedTarget = clampScrollTop(content, targetScroll);

      isAnimatingRef.current = true;
      isProgrammaticScrollRef.current = true;
      const startScroll = currentScroll;
      const distance = clampedTarget - startScroll;
      const duration = 300;
      const startTime = performance.now();
      const endTime = startTime + duration;
      const easeCubicBezier = createCubicBezierEasing(0.57, 0.4, 0.55, 1.17);

      const finish = () => {
        isAnimatingRef.current = false;
        isProgrammaticScrollRef.current = false;
        if (animationFrameRef.current) {
          cancelAnimationFrame(animationFrameRef.current);
          animationFrameRef.current = null;
        }
      };

      const animate = (currentTime: number) => {
        if (currentTime >= endTime) {
          content.scrollTop = clampScrollTop(content, clampedTarget);
          restScrollTopRef.current = content.scrollTop;
          finish();
          return;
        }

        const elapsed = currentTime - startTime;
        const progress = Math.min(elapsed / duration, 1.0);
        const eased = easeCubicBezier(progress);
        content.scrollTop = clampScrollTop(
          content,
          startScroll + distance * eased,
        );
        animationFrameRef.current = requestAnimationFrame(animate);
      };

      animationFrameRef.current = requestAnimationFrame(animate);
    },
    [],
  );

  const snapScrollToRest = useCallback(() => {
    const section = orderbookSectionRef.current;
    const spreadEl = spreadRef.current;
    if (!section || !spreadEl || isAnimatingRef.current) return;

    const rest = measureRestScrollTop(section, spreadEl);
    if (rest === null) return;

    const target = clampScrollTop(section, rest);
    restScrollTopRef.current = target;
    const current = section.scrollTop;
    if (Math.abs(target - current) > 1) {
      smoothScrollTo(section, target, current);
    }
  }, [smoothScrollTo]);

  const endSpreadPan = useCallback(() => {
    if (!isPanningRef.current) return;
    isPanningRef.current = false;
    setIsSpreadPanning(false);
    mousePanCleanupRef.current?.();
    mousePanCleanupRef.current = null;
    snapScrollToRest();
  }, [snapScrollToRest]);

  const handleSpreadMouseDown = useCallback(
    (e: React.MouseEvent<HTMLDivElement>) => {
      e.preventDefault();
      const section = orderbookSectionRef.current;
      if (!section) return;

      cancelSnapAnimation();
      mousePanCleanupRef.current?.();

      isPanningRef.current = true;
      setIsSpreadPanning(true);
      panStartYRef.current = e.clientY;
      panStartScrollTopRef.current = section.scrollTop;

      const onMouseMove = (moveEvent: MouseEvent) => {
        if (!isPanningRef.current) return;
        const scrollable = orderbookSectionRef.current;
        if (!scrollable) return;

        const deltaY = moveEvent.clientY - panStartYRef.current;
        scrollable.scrollTop = clampScrollTop(
          scrollable,
          panStartScrollTopRef.current - deltaY,
        );
      };

      const onMouseUp = () => {
        window.removeEventListener("mousemove", onMouseMove);
        window.removeEventListener("mouseup", onMouseUp);
        mousePanCleanupRef.current = null;
        endSpreadPan();
      };

      mousePanCleanupRef.current = () => {
        window.removeEventListener("mousemove", onMouseMove);
        window.removeEventListener("mouseup", onMouseUp);
      };

      window.addEventListener("mousemove", onMouseMove);
      window.addEventListener("mouseup", onMouseUp);
    },
    [cancelSnapAnimation, endSpreadPan],
  );

  const handleSpreadTouchStart = useCallback(
    (e: React.TouchEvent<HTMLDivElement>) => {
      const section = orderbookSectionRef.current;
      if (!section) return;

      cancelSnapAnimation();
      isPanningRef.current = true;
      setIsSpreadPanning(true);
      panStartYRef.current = e.touches[0]?.clientY ?? 0;
      panStartScrollTopRef.current = section.scrollTop;
    },
    [cancelSnapAnimation],
  );

  const handleSpreadTouchMove = useCallback(
    (e: React.TouchEvent<HTMLDivElement>) => {
      if (!isPanningRef.current) return;
      e.preventDefault();

      const section = orderbookSectionRef.current;
      if (!section) return;

      const y = e.touches[0]?.clientY ?? panStartYRef.current;
      const deltaY = y - panStartYRef.current;
      section.scrollTop = clampScrollTop(
        section,
        panStartScrollTopRef.current - deltaY,
      );
    },
    [],
  );

  const handleSpreadTouchEnd = useCallback(() => {
    endSpreadPan();
  }, [endSpreadPan]);

  // Sync padding + scroll before paint when spread can center.
  useLayoutEffect(() => {
    if (!canCenterSpread) {
      hasCenteredOnceRef.current = false;
      layoutSignatureRef.current = "";
      restScrollTopRef.current = null;
      return;
    }
    syncScrollLayout();
  }, [asks.length, bids.length, canCenterSpread, syncScrollLayout]);

  // Re-sync on viewport resize before paint.
  useLayoutEffect(() => {
    if (!canCenterSpread) return;

    const section = orderbookSectionRef.current;
    if (!section || typeof ResizeObserver === "undefined") {
      return;
    }

    const observer = new ResizeObserver(() => {
      if (isPanningRef.current || isAnimatingRef.current) return;
      syncScrollLayout();
    });

    observer.observe(section);
    return () => observer.disconnect();
  }, [canCenterSpread, syncScrollLayout]);

  useEffect(() => {
    if (!isSpreadPanning) return;
    setHoveredLevel(null);
  }, [isSpreadPanning]);

  // Block native wheel scroll on levels — pan is spread-only.
  useEffect(() => {
    const section = orderbookSectionRef.current;
    if (!section) return;

    const onWheel = (e: WheelEvent) => {
      e.preventDefault();
    };

    section.addEventListener("wheel", onWheel, { passive: false });
    return () => section.removeEventListener("wheel", onWheel);
  }, [loading, error]);

  useEffect(() => {
    return () => {
      mousePanCleanupRef.current?.();
      mousePanCleanupRef.current = null;
      cancelSnapAnimation();
      if (layoutRetryFrameRef.current !== null) {
        cancelAnimationFrame(layoutRetryFrameRef.current);
        layoutRetryFrameRef.current = null;
      }
      if (animationFrameRef.current) {
        cancelAnimationFrame(animationFrameRef.current);
        animationFrameRef.current = null;
      }
    };
  }, [cancelSnapAnimation]);

  if (loading) {
    return <MorpheumInlineLoading message="Loading orderbook..." />;
  }

  if (error) {
    return <ErrorMessage error={error} />;
  }

  return (
    <div className="layout-container" style={{ height }}>
      {wsError && (asks.length > 0 || bids.length > 0) && (
        <div className="orderbook-ws-warning">
          <img
            src="/caution-icon.svg"
            alt="Caution"
            className="orderbook-ws-warning-icon"
          />
          <span className="orderbook-ws-warning-text">{wsError}</span>
        </div>
      )}

      <LayoutHeader title={<StatusIndicator isConnected={isConnected ?? false} />}>
        <span>Depth: {maxDepth}</span>
      </LayoutHeader>
      <div className="orderbook-content" ref={orderbookContentRef}>
        <div className="orderbook-column-header">
          <span className="orderbook-column-header-cell">Price</span>
          <span className="orderbook-column-header-cell right">Size</span>
          <span className="orderbook-column-header-cell right">Total</span>
        </div>
        <div className="orderbook-section" ref={orderbookSectionRef}>
          <div className="orderbook-scroll-body" ref={scrollBodyRef}>
            <div className="orderbook-ask-slot" ref={askSlotRef}>
              {asks.map((level, index) => {
                const askDepthValue =
                  lastAskCumulative - level.cumulative + level.size;
                const depthPercent = getAskDepthPercentage(askDepthValue);
                return (
                  <AskLevelFragment
                    key={`ask-${level.price}`}
                    level={level}
                    index={index}
                    isLast={
                      index === asks.length - 1 &&
                      bids.length === 0
                    }
                    depthPercent={depthPercent}
                    formatPrice={formatPriceMemo}
                    formatSize={formatSizeMemo}
                    onPriceClick={onPriceClick}
                    displayTotal={askDepthValue}
                    animationEnabled={animationEnabled}
                    onRowHover={handleAskRowHover}
                    onRowLeave={handleRowLeave}
                    isHovered={
                      hoveredLevel?.side === "ask" &&
                      hoveredLevel.index === index
                    }
                  />
                );
              })}
              {asks.length === 0 && bids.length === 0 && (
                <EmptyMessage message="No orders" />
              )}
              {asks.length === 0 && bids.length > 0 && (
                <EmptyMessage message="No ask orders" />
              )}
            </div>
            {canCenterSpread && (
              <div
                className={`orderbook-mid-price-spread${isSpreadPanning ? " is-panning" : ""}`}
                ref={spreadRef}
                onMouseDown={handleSpreadMouseDown}
                onTouchStart={handleSpreadTouchStart}
                onTouchMove={handleSpreadTouchMove}
                onTouchEnd={handleSpreadTouchEnd}
                onTouchCancel={handleSpreadTouchEnd}
              >
                Spread: {formatPriceMemo(spread)}
              </div>
            )}
            <div className="orderbook-bid-slot" ref={bidSlotRef}>
              {bids.map((level, index) => {
                const depthPercent = getBidDepthPercentage(level.cumulative);
                return (
                  <BidLevelFragment
                    key={`bid-${level.price}`}
                    level={level}
                    index={index}
                    isLast={index === bids.length - 1}
                    depthPercent={depthPercent}
                    formatPrice={formatPriceMemo}
                    formatSize={formatSizeMemo}
                    onPriceClick={onPriceClick}
                    displayTotal={level.cumulative}
                    animationEnabled={animationEnabled}
                    onRowHover={handleBidRowHover}
                    onRowLeave={handleRowLeave}
                    isHovered={
                      hoveredLevel?.side === "bid" &&
                      hoveredLevel.index === index
                    }
                  />
                );
              })}
              {bids.length === 0 && asks.length > 0 && (
                <EmptyMessage message="No bid orders" />
              )}
            </div>
          </div>
        </div>
      </div>

      <FooterSummary
        totalBids={lastBidCumulative}
        totalAsks={lastAskCumulative}
      />

      {hoverMetrics &&
        hoveredLevel &&
        orderbookContentRef.current &&
        orderbookSectionRef.current && (
          <OrderbookDepthTooltip
            metrics={hoverMetrics}
            anchorEl={hoveredLevel.anchorEl}
            panelEl={orderbookContentRef.current}
            scrollContainerEl={orderbookSectionRef.current}
            baseAsset={orderbookAssets.base}
            quoteAsset={orderbookAssets.quote}
            placement={tooltipPlacement}
          />
        )}
    </div>
  );
}

const FooterSummary = React.memo(
  ({ totalBids, totalAsks }: { totalBids: number; totalAsks: number }) => {
    const emaRef = useRef<{ bid: number; ask: number } | null>(null);
    const total = totalBids + totalAsks;
    const bidTarget = total > 0 ? totalBids / total : 0.5;
    const askTarget = total > 0 ? totalAsks / total : 0.5;

    if (emaRef.current === null) {
      emaRef.current = { bid: bidTarget, ask: askTarget };
    } else {
      emaRef.current = {
        bid:
          emaRef.current.bid * (1 - FOOTER_EMA_ALPHA) +
          bidTarget * FOOTER_EMA_ALPHA,
        ask:
          emaRef.current.ask * (1 - FOOTER_EMA_ALPHA) +
          askTarget * FOOTER_EMA_ALPHA,
      };
    }

    const bidsPercent = `${Math.round(emaRef.current.bid * 100)}%`;
    const asksPercent = `${Math.round(emaRef.current.ask * 100)}%`;

    return (
      <div className="orderbook-footer orderbook-footer-v2">
        <div className="orderbook-footer-v2-labels">
          <span className="orderbook-footer-v2-percent terminal-long">
            {bidsPercent}
          </span>
          <span className="orderbook-footer-v2-percent terminal-short">
            {asksPercent}
          </span>
        </div>
        <div
          className="orderbook-footer-v2-bar"
          style={
            { "--bid-fraction": emaRef.current.bid } as React.CSSProperties
          }
        >
          <div className="orderbook-footer-v2-track">
            <div className="orderbook-footer-v2-segment bid" />
            <div className="orderbook-footer-v2-segment ask" />
          </div>
          <div className="orderbook-footer-v2-marker" aria-hidden="true" />
        </div>
      </div>
    );
  },
);

FooterSummary.displayName = "FooterSummary";

export default React.memo(Orderbook002);
