export const ORDERBOOK_DEPTH_TOOLTIP_GAP_PX = 12;

const VIEWPORT_MARGIN_PX = 8;

export type OrderbookDepthTooltipSide = "left" | "right";

export type OrderbookDepthTooltipPlacement = "auto" | "left" | "right";

export interface OrderbookDepthTooltipLayoutInput {
  rowRect: DOMRectReadOnly;
  panelRect: DOMRectReadOnly;
  tooltipWidth: number;
  tooltipHeight: number;
  viewportWidth?: number;
  viewportHeight?: number;
  gapPx?: number;
  placement?: OrderbookDepthTooltipPlacement;
}

export interface OrderbookDepthTooltipLayoutResult {
  left: number;
  top: number;
  side: OrderbookDepthTooltipSide;
}

function clamp(value: number, min: number, max: number): number {
  return Math.max(min, Math.min(value, max));
}

function resolveSide(
  panelRect: DOMRectReadOnly,
  viewportWidth: number,
  placement: OrderbookDepthTooltipPlacement,
): OrderbookDepthTooltipSide {
  if (placement === "left" || placement === "right") {
    return placement;
  }
  const panelCenter = panelRect.left + panelRect.width / 2;
  return panelCenter > viewportWidth / 2 ? "left" : "right";
}

export function computeOrderbookDepthTooltipPosition(
  input: OrderbookDepthTooltipLayoutInput,
): OrderbookDepthTooltipLayoutResult {
  const {
    rowRect,
    panelRect,
    tooltipWidth,
    tooltipHeight,
    viewportWidth = window.innerWidth,
    viewportHeight = window.innerHeight,
    gapPx = ORDERBOOK_DEPTH_TOOLTIP_GAP_PX,
    placement = "auto",
  } = input;

  const side = resolveSide(panelRect, viewportWidth, placement);

  const rowCenterY = rowRect.top + rowRect.height / 2;
  const maxTop = Math.max(
    VIEWPORT_MARGIN_PX,
    viewportHeight - tooltipHeight - VIEWPORT_MARGIN_PX,
  );
  const top = clamp(
    rowCenterY - tooltipHeight / 2,
    VIEWPORT_MARGIN_PX,
    maxTop,
  );

  const left =
    side === "left"
      ? rowRect.left - tooltipWidth - gapPx
      : rowRect.right + gapPx;

  const maxLeft = Math.max(
    VIEWPORT_MARGIN_PX,
    viewportWidth - tooltipWidth - VIEWPORT_MARGIN_PX,
  );
  const clampedLeft = clamp(left, VIEWPORT_MARGIN_PX, maxLeft);

  return { left: clampedLeft, top, side };
}
