  /**
   * Get all markets. Uses /market/v1/all (market_api.md). Response may have count or total; SDK normalizes to total.
   */
  async getMarkets(): Promise<GetMarketsResponse> {
    const response = await this.httpClient.get(
      "/market/v1/all",
      this.getHeaders(),
    );
    const body = response.body as GetMarketsResponse;
    if (body && typeof body === "object" && "markets" in body) {
      const total = body.count ?? body.total ?? (body.markets?.length ?? 0);
      return { markets: body.markets ?? [], total, count: body.count };
    }
    return { markets: [], total: 0 };
  }

  /**
   * Get markets with filters.
   * Uses HTTP endpoint /market/v1/all with query params.
   */
  async getMarketsWithFilters(
    filter?: string,
    activeOnly?: boolean,
  ): Promise<GetMarketsResponse> {
    let path = "/market/v1/all";
    const params: string[] = [];
    if (filter) {
      params.push(`filter=${filter}`);
    }
    if (activeOnly) {
      params.push("active_only=true");
    }
    if (params.length > 0) {
      path += "?" + params.join("&");
    }
    const response = await this.httpClient.get(path, this.getHeaders());
    const body = response.body as GetMarketsResponse;
    if (body && typeof body === "object" && "markets" in body) {
      const total = body.count ?? body.total ?? (body.markets?.length ?? 0);
      return { markets: body.markets ?? [], total, count: body.count };
    }
    return { markets: [], total: 0 };
  }

