  /**
   * Query orderbook snapshot for a market.
   * Proto: QueryOrderBookSnapshot — GET /clob/v1/orderbook/{marketIndex}
   * Response PriceLevels ({price, quantity, orderCount}) are normalized to OrderbookEntry tuples.
   * See: proto-lib/proto/clob/v1/query.proto, orchestrator E2E TestOrderbookSnapshot.
   */
  async getOrderbook(
    marketIndex: string,
    convertToDecimal: boolean = true,
    depth: number = 20,
  ): Promise<RawOrderbook> {
    const depthValue = depth > 0 && depth < 100 ? depth : 20;
    const path = `/clob/v1/orderbook/${marketIndex}?depth=${depthValue}`;

    const response = await this.httpClient.get(path, this.getHeaders());
    const raw = response.body as Record<string, unknown>;

    return {
      marketIndex: raw.marketIndex as string | undefined,
      symbol: raw.symbol as string | undefined,
      bids: this.normalizePriceLevels(raw.bids, convertToDecimal),
      asks: this.normalizePriceLevels(raw.asks, convertToDecimal),
      sequenceId: raw.sequenceId != null ? Number(raw.sequenceId) : undefined,
      checksum: raw.checksum as string | undefined,
      blockHeight: raw.blockHeight as string | undefined,
      updatedAt: raw.updatedAt as string | undefined,
    };
  }

  /**
   * Normalize PriceLevel objects from proto JSON into OrderbookEntry tuples.
   * Proto format: {price: string, quantity: string, orderCount: number}
   * Output format: [price, quantity] as OrderbookEntry
   */
  private normalizePriceLevels(
    levels: unknown,
    convertToDecimal: boolean,
  ): OrderbookEntry[] {
    if (!Array.isArray(levels)) return [];
    return levels.map((level): OrderbookEntry => {
      let price: string;
      let quantity: string;
      if (typeof level === "object" && level !== null && "price" in level) {
        // PriceLevel object from proto JSON: {price, quantity, orderCount}
        const pl = level as { price: string; quantity: string };
        price = pl.price;
        quantity = pl.quantity;
      } else if (Array.isArray(level) && level.length >= 2) {
        // Already in tuple format (e.g., from WebSocket or other sources)
        price = String(level[0]);
        quantity = String(level[1]);
      } else {
        return [0, 0];
      }
      if (convertToDecimal) {
        return [fromSatoshi(price), fromSatoshi(quantity)];
      }
      return [price, quantity];
    });
  }

  /**
   * Get market trades by market ID
   * Uses HTTP endpoint /clob/v1/market/{marketIndex}/trades (proto-aligned, E2E-verified in place_order_e2e_test.go)
   * Response format: { trades: RawTrade[], totalCount: number, marketIndex: string, symbol: string, timestamp }
   */
  async getMarketTrades(marketId: string, limit?: number): Promise<RawTrade[]> {
    let path = `/clob/v1/market/${marketId}/trades`;
    if (limit && limit > 0) {
      path += `?limit=${limit}`;
    }
    const response = await this.httpClient.get(path, this.getHeaders());
    console.debug(
      "[InfoClient] getMarketTrades response for marketId:",
      marketId,
      "response:",
      response.body,
    );

    const body = response.body as TradesResponse;

    // Handle the actual API response structure
    if (
      body &&
      typeof body === "object" &&
      "trades" in body &&
      Array.isArray(body.trades)
    ) {
      return body.trades;
    }

    // Fallback for legacy formats (direct array or { data: [...] })
    if (Array.isArray(body)) {
      return body;
    }
    // Check for legacy format with 'data' property (not part of TradesResponse type)
    const bodyAny = body as any;
    if (bodyAny?.data && Array.isArray(bodyAny.data)) {
      return bodyAny.data;
    }

    console.warn(
      "[InfoClient] getMarketTrades: Unexpected response structure:",
      response.body,
    );
    // Return empty array if response structure is unexpected
    return [];
  }

