  /**
   * Get transaction history for an address. GET /bank/v1/transactions/history per bank_api.md.
   * Query params: address, txType (transfer|cross_chain|mint|burn), limit, offset.
   */
  async getTransactionHistory(params: {
    address: string;
    txType?: string;
    limit?: number;
    offset?: number;
  }): Promise<{
    address: string;
    transactions: Array<{
      txhash: string;
      type: string;
      from: string;
      to: string;
      amount: string;
      collateralAssetIndex: { ticker: string };
      timestamp: { seconds: number; nanos: number };
      status: string;
    }>;
    pagination: {
      limit: number;
      offset: number;
      total: number;
    };
  }> {
    const queryParams = new URLSearchParams({
      address: params.address,
    });
    if (params.txType) queryParams.set("txType", params.txType);
    if (params.limit) queryParams.set("limit", params.limit.toString());
    if (params.offset) queryParams.set("offset", params.offset.toString());

    const response = await this.httpClient.get(
      `/bank/v1/transactions/history?${queryParams.toString()}`,
      this.getHeaders(),
    );
    return response.body as any;
  }

