  /**
   * Get balance for an address. Uses /bank/v1/balance/{address}?asset= per bank_api.md (query param: asset).
   * Single-balance response may return asset as object (BalanceAsset); SDK normalizes to asset: symbol.
   * @param address - Account address
   * @param asset - Asset symbol (e.g. MORM, USDC). Default on server: MORM.
   */
  async getBalance(address: string, asset: string): Promise<RawBalance> {
    const path = `/bank/v1/balance/${encodeURIComponent(address)}?asset=${encodeURIComponent(asset)}`;
    const response = await this.httpClient.get(path, this.getHeaders());
    const b = response.body as RawBalance & { asset?: string | { symbol?: string } };
    const rawAsset = b.asset as string | { symbol?: string } | undefined;
    if (typeof rawAsset === "object" && rawAsset?.symbol) {
      return { ...b, asset: rawAsset.symbol };
    }
    if (!rawAsset && (b as any).collateralAssetIndex) {
      const t = (b as any).collateralAssetIndex?.ticker ?? (b as any).collateralAssetIndex;
      if (typeof t === "string") return { ...b, asset: t };
    }
    return b;
  }

  /**
   * Get balances for an address
   * Uses HTTP endpoint /bank/v1/balances/{address} (matches Go client GetBalances)
   *
   * Actual API response structure (proto camelCase):
   * {
   *   "address": "0x...",
   *   "balances": [
   *     {
   *       "asset": { "assetIndex": "0", "symbol": "MORM", "type": "ASSET_TYPE_NATIVE_MORM", ... },
   *       "availableBalance": "100000000000000000000000",
   *       "balance": "100000000000000000000000",
   *       "lockedBalance": "0",
   *       "shardId": ""
   *     },
   *     ...
   *   ],
   *   "shardId": ""
   * }
   */
  async getBalances(address: string): Promise<RawBalance[]> {
    const response = await this.httpClient.get(
      `/bank/v1/balances/${address}`,
      this.getHeaders(),
    );
    const body = response.body as GetBalancesResponse;

    // Handle the actual API response structure (GetBalancesResponse)
    if (
      body &&
      typeof body === "object" &&
      "balances" in body &&
      Array.isArray(body.balances)
    ) {
      // Normalize: API returns asset as object (BalanceAsset); set asset to symbol for backward compat
      return body.balances.map((b: RawBalance & { asset?: string | { symbol?: string } }) => {
        const rawAsset = b.asset as string | { symbol?: string } | undefined;
        if (typeof rawAsset === "string") return b;
        if (rawAsset && typeof rawAsset === "object" && typeof rawAsset.symbol === "string") {
          return { ...b, asset: rawAsset.symbol };
        }
        const ticker = (b as any).collateralAssetIndex?.ticker ?? (b as any).collateralAssetIndex;
        if (ticker && typeof ticker === "string") {
          return { ...b, asset: ticker };
        }
        return b;
      });
    }

    return [];
  }

  /**
   * Get balance with decimal conversion. Passes assetID as collateralAssetIndex to getBalance.
   * @param assetID - Collateral asset ticker (e.g. MORM, USDC).
   */
  async getBalanceDecimal(
    address: string,
    assetID: string,
  ): Promise<RawBalance> {
    const balance = await this.getBalance(address, assetID);

    if (balance && typeof balance === "object") {
      const converted: RawBalance & Record<string, any> = { ...balance };
      if (converted.balance) {
        converted.balance = fromSatoshi(converted.balance) as any;
      }
      if (converted.availableBalance) {
        converted.available = fromSatoshi(converted.availableBalance);
      }
      if (converted.available && typeof converted.available === "string") {
        converted.available = fromSatoshi(converted.available);
      }
      if (converted.lockedBalance) {
        converted.locked = fromSatoshi(converted.lockedBalance);
      }
      if (converted.locked && typeof converted.locked === "string") {
        converted.locked = fromSatoshi(converted.locked);
      }
      // Type assertion: converted has all RawBalance properties (spread from balance)
      // even though some values are converted from string to number
      return converted as RawBalance;
    }

    return balance;
  }

