  /**
   * Get market data. /clob/v1/market/data is deprecated (501); per clob_api use orderbook snapshot
   * and derive lastPrice from best bid/ask. Uses GET /clob/v1/orderbook/{marketIndex}/snapshot.
   */
  async getMarketData(marketIndexOrSymbol: string): Promise<MarketDataResponse> {
    const path = `/clob/v1/orderbook/${encodeURIComponent(marketIndexOrSymbol)}/snapshot?depth=1`;
    const response = await this.httpClient.get(path, this.getHeaders());
    const ob = response.body as { bids?: Array<{ price: string }>; asks?: Array<{ price: string }>; symbol?: string };
    const bids = ob?.bids ?? [];
    const asks = ob?.asks ?? [];
    const bestBid = bids[0]?.price;
    const bestAsk = asks[0]?.price;
    let lastPrice: number | undefined;
    if (bestBid != null && bestAsk != null) {
      lastPrice = (parseFloat(bestBid) + parseFloat(bestAsk)) / 2;
    } else if (bestBid != null) lastPrice = parseFloat(bestBid);
    else if (bestAsk != null) lastPrice = parseFloat(bestAsk);
    return {
      ...(ob ?? {}),
      symbol: ob?.symbol,
      assetPair: ob?.symbol,
      lastPrice: lastPrice != null ? String(lastPrice) : undefined,
      last_price: lastPrice,
      markPrice: lastPrice != null ? String(lastPrice) : undefined,
      mark_price: lastPrice,
    } as MarketDataResponse;
  }

