  /**
   * Readiness probe. GET /health/ready. Query: verbose, strict.
   */
  async getHealthReady(verbose?: boolean, strict?: boolean): Promise<{ status?: string; [key: string]: any }> {
    const params = new URLSearchParams();
    if (verbose) params.set("verbose", "true");
    if (strict) params.set("strict", "true");
    const q = params.toString();
    const path = q ? `/health/ready?${q}` : "/health/ready";
    const response = await this.httpClient.get(path, this.getHeaders());
    return response.body as any;
  }

