import { BubbleTip, BUBBLE_TIP_IDS } from "../../tutorials/bubble-tip";
import "./layout.css";
import React from "react";
export interface StatusIndicatorProps {
  isConnected: boolean;
  connectedText?: string;
  disconnectedText?: string;
}

/**
 * Status indicator showing connection status
 */
export function StatusIndicator({
  isConnected,
  connectedText = "● LIVE",
  disconnectedText = "○ OFFLINE",
}: StatusIndicatorProps): JSX.Element {
  const statusLabel = isConnected ? connectedText : disconnectedText;

  return (
    <div className="status-indicator">
      {isConnected ? (
        <BubbleTip id={BUBBLE_TIP_IDS.liveIndicator}>
          <span
            className={`status-dot ${isConnected ? "connected" : "disconnected"}`}
          >
            {statusLabel}
          </span>
        </BubbleTip>
      ) : (
        <span
          className={`status-dot ${isConnected ? "connected" : "disconnected"}`}
        >
          {statusLabel}
        </span>
      )}
    </div>
  );
}
