import type { ReactNode } from "react";

export interface DocSectionProps {
  title: string;
  description?: string;
  children: ReactNode;
}

export function DocSection({
  title,
  description,
  children,
}: DocSectionProps): JSX.Element {
  return (
    <section className="uitest-doc-section">
      <header className="uitest-doc-section__header">
        <h2 className="uitest-doc-section__title">{title}</h2>
        {description ? (
          <p className="uitest-doc-section__description">{description}</p>
        ) : null}
      </header>
      <div className="uitest-doc-section__body">{children}</div>
    </section>
  );
}
