import {
  getMockMarketBaseAsset,
  mockMarkets,
} from "../../../offline/mock_data";

export interface OrderbookAssets {
  base: string;
  quote: string;
}

function parseBaseFromMarketId(marketId: string): string {
  const trimmed = marketId.trim();
  if (!trimmed) return "";
  const split = trimmed.split(/[-/]/)[0]?.trim();
  return split ?? "";
}

export function resolveOrderbookAssets(marketId: string): OrderbookAssets {
  const mockMarket = mockMarkets.find((market) => market.marketIndex === marketId);
  if (mockMarket) {
    return {
      base: mockMarket.baseAsset,
      quote: mockMarket.quoteAsset,
    };
  }

  const mockBase = getMockMarketBaseAsset(marketId);
  const base = mockBase ?? parseBaseFromMarketId(marketId);
  return {
    base: base || "—",
    quote: "USDC",
  };
}
